import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export type ZoneType = 'North' | 'South' | 'East' | 'West' | 'Center';

export interface Neighborhood {
  id: string;
  name: string;
  zone: ZoneType;
  description?: string;
}

export interface Landmark {
  id: string;
  name: string;
  type: 'monument' | 'park' | 'street' | 'river';
  coordinates: { x: number; y: number };
  description: string;
}

export interface MapData {
  zones: Record<ZoneType, { color: string; hoverColor: string; label: string }>;
  landmarks: Landmark[];
  neighborhoods: Neighborhood[];
}

import { GoogleGenAI } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export async function getNeighborhoodInsights(neighborhoodName: string) {
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `Forneça um breve parágrafo (máximo 40 palavras) com uma curiosidade cultural ou histórica sobre o bairro "${neighborhoodName}" em São Paulo, Brasil. Use um tom convidativo de guia turístico.`,
      config: {
        temperature: 0.7,
      },
    });
    return response.text || "Informação não disponível no momento.";
  } catch (error) {
    console.error("Gemini Error:", error);
    return "Não foi possível carregar as curiosidades agora.";
  }
}

import React from 'react';

interface LandmarkIconProps {
  type: 'monument' | 'park' | 'street' | 'river';
  x: number;
  y: number;
  name: string;
  onClick: () => void;
}

const LandmarkIcon: React.FC<LandmarkIconProps> = ({ type, x, y, name, onClick }) => {
  const getIcon = () => {
    switch (type) {
      case 'monument':
        return (
          <path 
            d="M-5,10 L5,10 L3,-8 L-3,-8 Z" 
            fill="#e11d48" 
            stroke="#fff" 
            strokeWidth="1.5"
          />
        );
      case 'park':
        return (
          <circle r="8" fill="#16a34a" stroke="#fff" strokeWidth="2" />
        );
      case 'street':
        return (
          <rect x="-15" y="-3" width="30" height="6" rx="2" fill="#475569" stroke="#fff" strokeWidth="1" />
        );
      default:
        return <circle r="5" fill="#000" />;
    }
  };

  return (
    <g transform={`translate(${x}, ${y})`} onClick={onClick} className="cursor-pointer group">
      {/* Glow Effect */}
      <circle r="15" fill="rgba(255,255,255,0.4)" className="opacity-0 group-hover:opacity-100 transition-opacity" />
      {getIcon()}
      <text
        y="25"
        textAnchor="middle"
        className="text-[12px] font-bold fill-slate-800 drop-shadow-sm select-none pointer-events-none"
        style={{ fontSize: '12px' }}
      >
        {name}
      </text>
    </g>
  );
};

export default LandmarkIcon;

