export type ZoneType = 'North' | 'South' | 'East' | 'West' | 'Center';

export interface Neighborhood {
  id: string;
  name: string;
  zone: ZoneType;
  description?: string;
}

export interface Landmark {
  id: string;
  name: string;
  type: 'monument' | 'park' | 'street' | 'river';
  coordinates: { lat: number; lng: number };
  description: string;
}

export interface MapData {
  zones: Record<ZoneType, { color: string; hoverColor: string; label: string; center: [number, number] }>;
  landmarks: Landmark[];
  neighborhoods: Neighborhood[];
}

import { GoogleGenAI } from "@google/genai";

export async function getGroundedLocationInfo(query: string) {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  try {
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash",
      contents: `Forneça informações detalhadas e links oficiais do Google Maps sobre o seguinte local ou região em São Paulo: "${query}". Fale sobre sua importância histórica e o que o visitante pode esperar encontrar lá.`,
      config: {
        tools: [{ googleMaps: {} }],
        toolConfig: {
          retrievalConfig: {
            latLng: {
              latitude: -23.5505,
              longitude: -46.6333
            }
          }
        }
      },
    });

    const text = response.text || "Informação não disponível no momento.";
    const chunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks || [];

    return {
      text,
      links: chunks
        .filter((chunk: any) => chunk.maps)
        .map((chunk: any) => ({
          uri: chunk.maps.uri,
          title: chunk.maps.title || "Ver no Google Maps"
        }))
    };
  } catch (error) {
    console.error("Gemini Grounding Error:", error);
    return { text: "Erro ao carregar dados geográficos reais.", links: [] };
  }
}

import React, { useEffect, useRef } from 'react';
import { SP_MAP_DATA } from '../constants';
import { ZoneType } from '../types';

interface RealMapProps {
  selectedZone: ZoneType | null;
  onZoneClick: (zone: ZoneType) => void;
  onLandmarkClick: (id: string) => void;
}

const RealMap: React.FC<RealMapProps> = ({ selectedZone, onZoneClick, onLandmarkClick }) => {
  const mapRef = useRef<L.Map | null>(null);
  const containerRef = useRef<HTMLDivElement>(null);
  const zonesLayerRef = useRef<L.LayerGroup | null>(null);

  useEffect(() => {
    if (!containerRef.current || mapRef.current) return;

    // Inicializa o mapa focado em SP
    const map = L.map(containerRef.current, {
      zoomControl: false
    }).setView([-23.5505, -46.6333], 12);

    mapRef.current = map;

    // Adiciona controle de zoom no canto inferior direito
    L.control.zoom({ position: 'bottomright' }).addTo(map);

    // Camada de Tiles Realista e Limpa (CartoDB Voyager)
    L.tileLayer('https://{s}.basemaps.cartocdn.com/rastertiles/voyager/{z}/{x}/{y}{r}.png', {
      attribution: '&copy; OpenStreetMap &copy; CARTO',
      subdomains: 'abcd',
      maxZoom: 20
    }).addTo(map);

    zonesLayerRef.current = L.layerGroup().addTo(map);

    // Adiciona Marcadores para os Marcos Principais
    SP_MAP_DATA.landmarks.forEach(landmark => {
      const icon = L.divIcon({
        className: 'custom-marker',
        html: `<div class="group relative flex flex-col items-center">
                <div class="bg-emerald-600 w-8 h-8 rounded-full border-2 border-white shadow-xl flex items-center justify-center text-white transform transition-all hover:scale-125 hover:bg-emerald-500">
                  <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="3" stroke-linecap="round" stroke-linejoin="round"><path d="M21 10c0 7-9 13-9 13s-9-6-9-13a9 9 0 0 1 18 0z"></path></svg>
                </div>
                <div class="absolute top-10 bg-white/90 px-2 py-0.5 rounded text-[10px] font-bold shadow-sm whitespace-nowrap opacity-0 group-hover:opacity-100 transition-opacity">
                  ${landmark.name}
                </div>
              </div>`,
        iconSize: [32, 32],
        iconAnchor: [16, 32],
      });

      L.marker([landmark.coordinates.lat, landmark.coordinates.lng], { icon })
        .addTo(map)
        .on('click', (e) => {
          L.DomEvent.stopPropagation(e);
          onLandmarkClick(landmark.id);
        });
    });

    return () => {
      map.remove();
      mapRef.current = null;
    };
  }, []);

  // Atualiza as zonas coloridas e o foco da câmera
  useEffect(() => {
    if (!mapRef.current || !zonesLayerRef.current) return;

    zonesLayerRef.current.clearLayers();

    Object.entries(SP_MAP_DATA.zones).forEach(([key, zone]) => {
      const isSelected = selectedZone === key;

      const circle = L.circle(zone.center, {
        color: zone.color,
        fillColor: zone.color,
        fillOpacity: isSelected ? 0.35 : 0.1,
        radius: 4500,
        weight: isSelected ? 4 : 1,
      })
      .addTo(zonesLayerRef.current!)
      .on('click', (e) => {
        L.DomEvent.stopPropagation(e);
        onZoneClick(key as ZoneType);
      });

      if (isSelected) {
        mapRef.current?.flyTo(zone.center, 13, { duration: 1.5 });
      }
    });
  }, [selectedZone]);

  return (
    <div className="relative w-full aspect-[297/420] bg-slate-200 rounded-2xl overflow-hidden shadow-[0_20px_50px_rgba(0,0,0,0.1)] border-8 border-white print:border-0 print:shadow-none print:rounded-none">
      <div ref={containerRef} id="map" className="w-full h-full" />

      {/* Overlay de Título Estilizado */}
      <div className="absolute top-8 left-8 z-[1000] pointer-events-none">
        <div className="bg-white/80 backdrop-blur-md p-5 rounded-xl border border-white/50 shadow-2xl">
          <h1 className="font-display text-4xl text-slate-800 leading-none mb-1">São Paulo</h1>
          <p className="text-[10px] font-black uppercase tracking-[0.2em] text-emerald-600">Explorador Grounded por IA</p>
        </div>
      </div>

      {/* Rosa dos Ventos Decorativa */}
      <div className="absolute bottom-8 left-8 z-[1000] opacity-30 pointer-events-none">
         <div className="w-16 h-16 border border-slate-400 rounded-full flex items-center justify-center">
            <div className="w-px h-full bg-slate-400 absolute"></div>
            <div className="h-px w-full bg-slate-400 absolute"></div>
            <span className="absolute -top-6 text-[10px] font-bold">N</span>
         </div>
      </div>
    </div>
  );
};

export default RealMap;

