export type MapStyle = 'standard' | 'satellite';

const App: React.FC = () => {
  const [selectedZone, setSelectedZone] = useState<ZoneType | null>(null);
  const [selectedLandmark, setSelectedLandmark] = useState<Landmark | null>(null);
  const [groundedInfo, setGroundedInfo] = useState<{ text: string, links: {uri: string, title: string}[] }>({ text: '', links: [] });
  const [loading, setLoading] = useState<boolean>(false);
  const [isSidebarOpen, setIsSidebarOpen] = useState<boolean>(true);
  const [mapStyle, setMapStyle] = useState<MapStyle>('standard');

  const handleZoneClick = async (zone: ZoneType) => {
    setSelectedZone(zone);
    setSelectedLandmark(null);
    setLoading(true);
    const info = await getGroundedLocationInfo(SP_MAP_DATA.zones[zone].label);
    setGroundedInfo(info);
    setLoading(false);
    if (window.innerWidth < 768) {
      setIsSidebarOpen(false);
    }
  };

  const handleLandmarkClick = async (id: string) => {
    const landmark = SP_MAP_DATA.landmarks.find(l => l.id === id);
    if (landmark) {
      setSelectedLandmark(landmark);
      setSelectedZone(null);
      setLoading(true);
      const info = await getGroundedLocationInfo(landmark.name);
      setGroundedInfo(info);
      setLoading(false);
      setIsSidebarOpen(true);
    }
  };

  const toggleMapStyle = () => {
    setMapStyle(prev => prev === 'standard' ? 'satellite' : 'standard');
  };

  const handlePrint = () => {
    window.print();
  };

  const activeTitle = selectedLandmark ? selectedLandmark.name : (selectedZone ? SP_MAP_DATA.zones[selectedZone].label : null);

  return (
    <div className="h-full flex flex-col md:flex-row bg-[#f8fafc] text-slate-900 overflow-hidden relative">

      {!isSidebarOpen && (
        <button 
          onClick={() => setIsSidebarOpen(true)}
          className="md:hidden fixed top-4 right-4 z-[2000] bg-white p-3 rounded-full shadow-2xl border border-slate-100 text-slate-700 animate-in zoom-in duration-300 no-print"
        >
          <Menu size={24} />
        </button>
      )}

      <aside 
        className={`
          fixed inset-0 z-[1001] md:relative md:inset-auto
          flex flex-col bg-white shadow-2xl no-print border-slate-100 transition-all duration-300 ease-in-out overflow-hidden
          ${isSidebarOpen 
            ? 'w-full md:w-80 lg:w-96 opacity-100 translate-x-0' 
            : 'w-0 opacity-0 -translate-x-full md:translate-x-0 md:pointer-events-none'
          }
        `}
      >
        <div className="flex items-center justify-between p-4 md:p-6 md:pb-8 border-b border-slate-50 md:border-none shrink-0 min-w-[320px]">
          <div className="flex items-center gap-3">
            <div className="bg-emerald-600 p-2 rounded-xl text-white shadow-lg shadow-emerald-100">
              <MapIcon size={20} />
            </div>
            <div>
              <h1 className="text-xl md:text-2xl font-bold font-display leading-none">SP Real</h1>
              <p className="hidden md:block text-[9px] font-bold text-slate-400 uppercase tracking-widest mt-1">Grounded IA Guide</p>
            </div>
          </div>

          <button 
            onClick={() => setIsSidebarOpen(false)}
            className="p-2 hover:bg-slate-50 rounded-lg text-slate-400 hover:text-slate-600 transition-colors"
          >
            <X size={20} className="md:hidden" />
            <ChevronLeft size={20} className="hidden md:block" />
          </button>
        </div>

        <div className="flex-1 overflow-y-auto custom-scrollbar p-4 md:p-6 pt-2 space-y-6 md:space-y-8 min-w-[320px]">
          <section className="hidden md:block">
            <h2 className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] mb-3 flex items-center gap-2">
              <Compass size={14} className="text-emerald-500" /> Explorar
            </h2>
            <p className="text-slate-500 text-xs leading-relaxed italic">
              Selecione uma zona para ver detalhes demográficos ou clique nos pins para marcos históricos.
            </p>
          </section>

          <section>
            <h2 className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] mb-4">Zonas Urbanas</h2>
            <div className="flex md:flex-col gap-2 overflow-x-auto md:overflow-visible pb-2 md:pb-0 custom-scrollbar">
              {(Object.keys(SP_MAP_DATA.zones) as ZoneType[]).map((zone) => (
                <button
                  key={zone}
                  onClick={() => handleZoneClick(zone)}
                  className={`flex items-center justify-between p-3 md:p-3.5 rounded-xl transition-all border-2 shrink-0 md:shrink ${
                    selectedZone === zone 
                      ? 'bg-slate-900 border-slate-900 text-white shadow-lg' 
                      : 'bg-slate-50 border-transparent hover:border-slate-200 text-slate-600'
                  }`}
                >
                  <div className="flex items-center gap-2 md:gap-3">
                    <div 
                      className="w-2 h-2 rounded-full" 
                      style={{ backgroundColor: SP_MAP_DATA.zones[zone].color }}
                    />
                    <span className="font-bold text-xs md:text-sm tracking-tight whitespace-nowrap">{SP_MAP_DATA.zones[zone].label}</span>
                  </div>
                  <ChevronRight size={14} className={`hidden md:block ${selectedZone === zone ? 'text-emerald-400' : 'text-slate-300'}`} />
                </button>
              ))}
            </div>
          </section>

          {activeTitle && (
            <section className="bg-emerald-50/50 p-4 md:p-6 rounded-2xl md:rounded-3xl border border-emerald-100 animate-in fade-in slide-in-from-bottom-6 duration-500">
              <div className="flex items-start gap-3 mb-4 text-emerald-800">
                <div className="bg-white p-2 rounded-lg shadow-sm shrink-0">
                   <MapPin size={16} className="text-emerald-600" />
                </div>
                <div>
                  <h2 className="font-bold text-md md:text-lg leading-tight">{activeTitle}</h2>
                  <p className="text-[9px] uppercase font-bold text-emerald-600/60 mt-0.5">Localização Verificada</p>
                </div>
              </div>

              <div className="space-y-4">
                <div className="bg-white p-4 md:p-5 rounded-xl md:rounded-2xl shadow-sm border border-emerald-100/50">
                  <div className="flex items-center gap-2 mb-3 text-emerald-600 font-black text-[9px] uppercase tracking-widest">
                    <Sparkles size={11} /> Insight via Google Maps
                  </div>

                  {loading ? (
                    <div className="flex gap-1.5 py-4 justify-center">
                      <div className="w-1.5 h-1.5 bg-emerald-400 rounded-full animate-bounce"></div>
                      <div className="w-1.5 h-1.5 bg-emerald-400 rounded-full animate-bounce delay-100"></div>
                      <div className="w-1.5 h-1.5 bg-emerald-400 rounded-full animate-bounce delay-200"></div>
                    </div>
                  ) : (
                    <>
                      <div className="text-slate-600 text-[11px] md:text-xs leading-relaxed font-medium">
                        {groundedInfo.text}
                      </div>

                      {groundedInfo.links.length > 0 && (
                        <div className="mt-4 pt-3 border-t border-slate-50 flex flex-col gap-1.5">
                          {groundedInfo.links.map((link, i) => (
                            <a 
                              key={i}
                              href={link.uri}
                              target="_blank"
                              rel="noopener noreferrer"
                              className="group flex items-center justify-between gap-2 text-[10px] font-bold text-emerald-700 hover:text-emerald-800 transition-colors"
                            >
                              <span className="truncate">{link.title}</span>
                              <ExternalLink size={10} className="shrink-0 opacity-50 group-hover:opacity-100" />
                            </a>
                          ))}
                        </div>
                      )}
                    </>
                  )}
                </div>
              </div>
            </section>
          )}
        </div>

        <div className="p-4 md:p-6 border-t border-slate-100 shrink-0 bg-white min-w-[320px]">
          <button 
            onClick={handlePrint}
            className="w-full flex items-center justify-center gap-2 md:gap-3 py-3 md:py-4 px-4 bg-emerald-600 text-white rounded-xl md:rounded-2xl hover:bg-emerald-700 transition-all font-bold shadow-lg shadow-emerald-50 text-sm md:text-base"
          >
            <Printer size={16} /> Exportar A3
          </button>
        </div>
      </aside>

      <main className="flex-1 relative flex flex-col bg-slate-100 print:bg-white print:p-0 overflow-hidden transition-all duration-300">
        {!isSidebarOpen && (
          <button 
            onClick={() => setIsSidebarOpen(true)}
            className="hidden md:flex absolute top-1/2 left-0 -translate-y-1/2 z-[1002] bg-white p-2 py-8 rounded-r-xl shadow-xl border border-l-0 border-slate-200 text-slate-400 hover:text-emerald-600 hover:bg-slate-50 transition-all animate-in slide-in-from-left-full duration-300"
          >
            <ChevronRight size={24} />
          </button>
        )}

        {/* Botão de Troca de Camada */}
        <button 
          onClick={toggleMapStyle}
          className="absolute top-4 right-4 md:top-8 md:right-8 z-[1002] bg-white/90 backdrop-blur-sm p-3 md:p-4 rounded-2xl shadow-2xl border border-white/50 text-slate-700 hover:text-emerald-600 transition-all hover:scale-105 active:scale-95 group no-print"
          title={mapStyle === 'standard' ? "Ver Satélite" : "Ver Mapa"}
        >
          <div className="flex items-center gap-2 md:gap-3">
             <Layers size={20} className={mapStyle === 'satellite' ? 'text-emerald-600' : ''} />
             <span className="text-xs md:text-sm font-bold uppercase tracking-wider hidden sm:block">
               {mapStyle === 'standard' ? 'Satélite' : 'Mapa'}
             </span>
          </div>
        </button>

        <div className="flex-1 w-full h-full print-area">
          <RealMap 
            selectedZone={selectedZone} 
            onZoneClick={handleZoneClick}
            onLandmarkClick={handleLandmarkClick}
            mapStyle={mapStyle}
          />
        </div>
      </main>
    </div>
  );
};

export default App;

import React, { useEffect, useRef } from 'react';
import { SP_MAP_DATA } from '../constants';
import { ZoneType } from '../types';
import L from 'leaflet';
import { MapStyle } from '../App';

interface RealMapProps {
  selectedZone: ZoneType | null;
  onZoneClick: (zone: ZoneType) => void;
  onLandmarkClick: (id: string) => void;
  mapStyle: MapStyle;
}

const TILE_LAYERS = {
  standard: 'https://{s}.basemaps.cartocdn.com/rastertiles/voyager/{z}/{x}/{y}{r}.png',
  satellite: 'https://server.arcgisonline.com/ArcGIS/rest/services/World_Imagery/MapServer/tile/{z}/{y}/{x}'
};

const RealMap: React.FC<RealMapProps> = ({ selectedZone, onZoneClick, onLandmarkClick, mapStyle }) => {
  const mapRef = useRef<L.Map | null>(null);
  const containerRef = useRef<HTMLDivElement>(null);
  const zonesLayerRef = useRef<L.LayerGroup | null>(null);
  const tileLayerRef = useRef<L.TileLayer | null>(null);

  useEffect(() => {
    if (!containerRef.current || mapRef.current) return;

    const map = L.map(containerRef.current, {
      zoomControl: false,
      attributionControl: true
    }).setView([-23.5505, -46.6333], 12);

    mapRef.current = map;

    L.control.zoom({ position: 'bottomright' }).addTo(map);

    // Inicializa com o estilo atual
    tileLayerRef.current = L.tileLayer(TILE_LAYERS[mapStyle], {
      attribution: mapStyle === 'standard' 
        ? '&copy; OpenStreetMap &copy; CARTO' 
        : 'Tiles &copy; Esri &mdash; Source: Esri, i-cubed, USDA, USGS, AEX, GeoEye, Getmapping, Aerogrid, IGN, IGP, UPR-EGP, and the GIS User Community',
      maxZoom: 19
    }).addTo(map);

    zonesLayerRef.current = L.layerGroup().addTo(map);

    // Marcadores
    SP_MAP_DATA.landmarks.forEach(landmark => {
      const icon = L.divIcon({
        className: 'custom-marker',
        html: `<div class="group relative flex flex-col items-center">
                <div class="bg-emerald-600 w-7 h-7 md:w-8 md:h-8 rounded-full border-2 border-white shadow-xl flex items-center justify-center text-white transform transition-all hover:scale-125 hover:bg-emerald-500">
                  <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="3" stroke-linecap="round" stroke-linejoin="round"><path d="M21 10c0 7-9 13-9 13s-9-6-9-13a9 9 0 0 1 18 0z"></path></svg>
                </div>
              </div>`,
        iconSize: [32, 32],
        iconAnchor: [16, 32],
      });

      L.marker([landmark.coordinates.lat, landmark.coordinates.lng], { icon })
        .addTo(map)
        .on('click', (e) => {
          L.DomEvent.stopPropagation(e);
          onLandmarkClick(landmark.id);
        });
    });

    const resizeObserver = new ResizeObserver(() => {
      map.invalidateSize();
    });
    resizeObserver.observe(containerRef.current);

    return () => {
      resizeObserver.disconnect();
      map.remove();
      mapRef.current = null;
    };
  }, []);

  // Troca a camada de Tiles quando o estilo muda
  useEffect(() => {
    if (!mapRef.current || !tileLayerRef.current) return;

    tileLayerRef.current.setUrl(TILE_LAYERS[mapStyle]);

    // Atualiza atribuição manualmente se necessário
    const attribution = mapStyle === 'standard' 
      ? '&copy; OpenStreetMap &copy; CARTO' 
      : 'Tiles &copy; Esri';

    // No Leaflet puro, trocar a URL é o mais eficiente.
  }, [mapStyle]);

  useEffect(() => {
    if (!mapRef.current || !zonesLayerRef.current) return;
    zonesLayerRef.current.clearLayers();

    Object.entries(SP_MAP_DATA.zones).forEach(([key, zone]) => {
      const isSelected = selectedZone === key;
      L.circle(zone.center, {
        color: zone.color,
        fillColor: zone.color,
        fillOpacity: isSelected ? 0.35 : 0.15,
        radius: isSelected ? 5000 : 4000,
        weight: isSelected ? 4 : 1,
      })
      .addTo(zonesLayerRef.current!)
      .on('click', (e) => {
        L.DomEvent.stopPropagation(e);
        onZoneClick(key as ZoneType);
      });

      if (isSelected) {
        mapRef.current?.flyTo(zone.center, 13, { duration: 1.5 });
      }
    });
  }, [selectedZone]);

  return (
    <div className="relative w-full h-full flex flex-col bg-slate-200 shadow-inner print:shadow-none print:bg-white map-container-print">
      <div ref={containerRef} className="w-full h-full" />

      {/* Overlay de Título Adaptável - Ajusta cor se for satélite */}
      <div className="absolute top-4 left-4 md:top-8 md:left-8 z-[1000] pointer-events-none transition-all duration-500">
        <div className={`
          p-4 md:p-6 rounded-2xl border shadow-2xl max-w-[200px] md:max-w-none backdrop-blur-md
          ${mapStyle === 'satellite' 
            ? 'bg-slate-900/80 border-slate-700 text-white' 
            : 'bg-white/90 border-white/50 text-slate-800'
          }
        `}>
          <h1 className="font-display text-2xl md:text-4xl leading-none mb-1">São Paulo</h1>
          <p className={`text-[8px] md:text-[10px] font-black uppercase tracking-[0.2em] ${mapStyle === 'satellite' ? 'text-emerald-400' : 'text-emerald-600'}`}>
            Explorador Real por IA
          </p>
        </div>
      </div>

      {/* Rosa dos Ventos - Ajusta cor se for satélite */}
      <div className={`absolute bottom-20 md:bottom-8 left-8 z-[1000] pointer-events-none hidden sm:block transition-all duration-500 ${mapStyle === 'satellite' ? 'opacity-60 grayscale invert' : 'opacity-30'}`}>
         <div className="w-12 h-12 md:w-16 md:h-16 border border-slate-400 rounded-full flex items-center justify-center">
            <div className="w-px h-full bg-slate-400 absolute"></div>
            <div className="h-px w-full bg-slate-400 absolute"></div>
            <span className="absolute -top-6 text-[10px] font-bold text-slate-600">N</span>
         </div>
      </div>
    </div>
  );
};

export default RealMap;

