import React, { useEffect, useRef } from 'react';
import { SP_MAP_DATA } from '../constants';
import { ZoneType } from '../types';
import L from 'leaflet';
import { MapStyle } from '../App';

interface RealMapProps {
  selectedZone: ZoneType | null;
  onZoneClick: (zone: ZoneType) => void;
  onLandmarkClick: (id: string) => void;
  mapStyle: MapStyle;
}

const TILE_LAYERS = {
  standard: 'https://{s}.basemaps.cartocdn.com/rastertiles/voyager/{z}/{x}/{y}{r}.png',
  satellite: 'https://server.arcgisonline.com/ArcGIS/rest/services/World_Imagery/MapServer/tile/{z}/{y}/{x}'
};

const RealMap: React.FC<RealMapProps> = ({ selectedZone, onZoneClick, onLandmarkClick, mapStyle }) => {
  const mapRef = useRef<L.Map | null>(null);
  const containerRef = useRef<HTMLDivElement>(null);
  const zonesLayerRef = useRef<L.LayerGroup | null>(null);
  const tileLayerRef = useRef<L.TileLayer | null>(null);

  useEffect(() => {
    if (!containerRef.current || mapRef.current) return;

    // Configurações do mapa mais flexíveis
    const map = L.map(containerRef.current, {
      zoomControl: false,
      attributionControl: false,
      tap: true, // Importante para touch devices
      bounceAtZoomLimits: true
    }).setView([-23.5505, -46.6333], 12);

    mapRef.current = map;

    // Reposiciona o zoom para não atrapalhar outros botões em telas pequenas
    L.control.zoom({ position: 'bottomright' }).addTo(map);

    tileLayerRef.current = L.tileLayer(TILE_LAYERS[mapStyle], {
      maxZoom: 19,
      crossOrigin: true
    }).addTo(map);

    zonesLayerRef.current = L.layerGroup().addTo(map);

    // Marcadores responsivos
    SP_MAP_DATA.landmarks.forEach(landmark => {
      const icon = L.divIcon({
        className: 'custom-marker',
        html: `<div class="marker-pin-wrapper transition-transform duration-300 hover:scale-125">
                <div class="bg-emerald-600 w-8 h-8 sm:w-9 sm:h-9 rounded-2xl border-[3px] border-white shadow-2xl flex items-center justify-center text-white rotate-45 transform-gpu">
                  <div class="-rotate-45">
                    <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="3" stroke-linecap="round" stroke-linejoin="round"><path d="M21 10c0 7-9 13-9 13s-9-6-9-13a9 9 0 0 1 18 0z"></path></svg>
                  </div>
                </div>
              </div>`,
        iconSize: [40, 40],
        iconAnchor: [20, 40],
      });

      L.marker([landmark.coordinates.lat, landmark.coordinates.lng], { icon })
        .addTo(map)
        .on('click', (e) => {
          L.DomEvent.stopPropagation(e);
          onLandmarkClick(landmark.id);
        });
    });

    const resizeObserver = new ResizeObserver(() => {
      if (mapRef.current) {
        mapRef.current.invalidateSize();
      }
    });
    resizeObserver.observe(containerRef.current);

    return () => {
      resizeObserver.disconnect();
      if (mapRef.current) {
        mapRef.current.remove();
        mapRef.current = null;
      }
    };
  }, []);

  useEffect(() => {
    if (!mapRef.current || !tileLayerRef.current) return;
    tileLayerRef.current.setUrl(TILE_LAYERS[mapStyle]);
  }, [mapStyle]);

  useEffect(() => {
    if (!mapRef.current || !zonesLayerRef.current) return;
    zonesLayerRef.current.clearLayers();

    Object.entries(SP_MAP_DATA.zones).forEach(([key, zone]) => {
      const isSelected = selectedZone === key;
      const radius = isSelected ? 5000 : 4200;

      L.circle(zone.center, {
        color: zone.color,
        fillColor: zone.color,
        fillOpacity: isSelected ? 0.35 : 0.1,
        radius: radius,
        weight: isSelected ? 4 : 2,
        dashArray: isSelected ? '' : '10, 10'
      })
      .addTo(zonesLayerRef.current!)
      .on('click', (e) => {
        L.DomEvent.stopPropagation(e);
        onZoneClick(key as ZoneType);
      });

      if (isSelected) {
        // Ajusta o zoom flyTo baseado na largura da tela
        const zoomLevel = window.innerWidth < 768 ? 12 : 13;
        mapRef.current?.flyTo(zone.center, zoomLevel, { 
          duration: 2, 
          easeLinearity: 0.1 
        });
      }
    });
  }, [selectedZone]);

  return (
    <div className="relative w-full h-full flex flex-col bg-slate-200 shadow-inner overflow-hidden transition-all duration-500">
      <div ref={containerRef} className="w-full h-full grayscale-[0.2] hover:grayscale-0 transition-all duration-1000" />

      {/* Rosa dos Ventos - Mais minimalista e melhor posicionada */}
      <div className={`
        absolute z-[1000] pointer-events-none transition-all duration-700
        bottom-20 left-6 sm:bottom-10 sm:left-10
        ${mapStyle === 'satellite' ? 'opacity-80 invert hue-rotate-180 brightness-200' : 'opacity-20'}
      `}>
         <div className="relative w-14 h-14 sm:w-20 sm:h-20 flex items-center justify-center">
            {/* Círculo base */}
            <div className="absolute inset-0 border border-slate-900 rounded-full"></div>
            {/* Linhas cruzadas */}
            <div className="absolute w-full h-px bg-slate-900/40"></div>
            <div className="absolute h-full w-px bg-slate-900/40"></div>
            {/* Agulha Norte */}
            <div className="absolute w-0 h-0 border-l-[4px] border-l-transparent border-r-[4px] border-r-transparent border-bottom-[20px] sm:border-bottom-[30px] border-bottom-emerald-600 top-0 -translate-y-1/2"></div>
            <span className="absolute -top-6 text-[11px] font-black text-slate-800 tracking-tighter">N</span>
         </div>
      </div>

      {/* Legenda de Distância Minimalista (Opcional, mas dá um toque pro) */}
      <div className="absolute bottom-6 left-1/2 -translate-x-1/2 z-[1000] hidden sm:block">
        <div className="bg-white/80 backdrop-blur px-3 py-1 rounded-full text-[9px] font-bold text-slate-500 border border-slate-200 uppercase tracking-widest shadow-sm">
          Escala Dinâmica 1:50.000
        </div>
      </div>
    </div>
  );
};

export default RealMap;

