import React, { useEffect, useRef } from 'react';
import { SP_MAP_DATA } from '../constants';
import { ZoneType } from '../types';
import L from 'leaflet';
import { MapStyle } from '../App';

interface RealMapProps {
  selectedZone: ZoneType | null;
  onZoneClick: (zone: ZoneType) => void;
  onLandmarkClick: (id: string) => void;
  mapStyle: MapStyle;
}

const TILE_LAYERS = {
  standard: 'https://{s}.basemaps.cartocdn.com/rastertiles/voyager/{z}/{x}/{y}{r}.png',
  satellite: 'https://server.arcgisonline.com/ArcGIS/rest/services/World_Imagery/MapServer/tile/{z}/{y}/{x}'
};

const RealMap: React.FC<RealMapProps> = ({ selectedZone, onZoneClick, onLandmarkClick, mapStyle }) => {
  const mapRef = useRef<L.Map | null>(null);
  const containerRef = useRef<HTMLDivElement>(null);
  const zonesLayerRef = useRef<L.LayerGroup | null>(null);
  const tileLayerRef = useRef<L.TileLayer | null>(null);

  useEffect(() => {
    if (!containerRef.current || mapRef.current) return;

    // Inicialização do Mapa
    const map = L.map(containerRef.current, {
      zoomControl: false,
      attributionControl: false,
      tap: true,
      bounceAtZoomLimits: true,
      wheelDebounceTime: 150
    }).setView([-23.5505, -46.6333], 12);

    mapRef.current = map;

    // Zoom no canto inferior direito para acesso ergonômico no mobile
    L.control.zoom({ position: 'bottomright' }).addTo(map);

    tileLayerRef.current = L.tileLayer(TILE_LAYERS[mapStyle], {
      maxZoom: 19,
      crossOrigin: true
    }).addTo(map);

    zonesLayerRef.current = L.layerGroup().addTo(map);

    // Adiciona Marcos com áreas de clique maiores
    SP_MAP_DATA.landmarks.forEach(landmark => {
      const icon = L.divIcon({
        className: 'custom-marker',
        html: `<div class="marker-container">
                <div class="bg-emerald-600 w-10 h-10 sm:w-8 sm:h-8 rounded-full border-2 border-white shadow-2xl flex items-center justify-center text-white active:scale-125 transition-transform">
                  <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="3" stroke-linecap="round" stroke-linejoin="round"><path d="M21 10c0 7-9 13-9 13s-9-6-9-13a9 9 0 0 1 18 0z"></path></svg>
                </div>
              </div>`,
        iconSize: [40, 40],
        iconAnchor: [20, 40],
      });

      L.marker([landmark.coordinates.lat, landmark.coordinates.lng], { icon })
        .addTo(map)
        .on('click', (e) => {
          L.DomEvent.stopPropagation(e);
          onLandmarkClick(landmark.id);
        });
    });

    // Força atualização do tamanho quando o container muda
    const resizeObserver = new ResizeObserver(() => {
      if (mapRef.current) mapRef.current.invalidateSize();
    });
    resizeObserver.observe(containerRef.current);

    return () => {
      resizeObserver.disconnect();
      if (mapRef.current) mapRef.current.remove();
      mapRef.current = null;
    };
  }, []);

  // Atualiza Estilo do Mapa
  useEffect(() => {
    if (!mapRef.current || !tileLayerRef.current) return;
    tileLayerRef.current.setUrl(TILE_LAYERS[mapStyle]);
  }, [mapStyle]);

  // Atualiza Zonas e Foco
  useEffect(() => {
    if (!mapRef.current || !zonesLayerRef.current) return;
    zonesLayerRef.current.clearLayers();

    Object.entries(SP_MAP_DATA.zones).forEach(([key, zone]) => {
      const isSelected = selectedZone === key;
      L.circle(zone.center, {
        color: zone.color,
        fillColor: zone.color,
        fillOpacity: isSelected ? 0.3 : 0.1,
        radius: isSelected ? 4000 : 3000,
        weight: isSelected ? 4 : 2,
      })
      .addTo(zonesLayerRef.current!)
      .on('click', (e) => {
        L.DomEvent.stopPropagation(e);
        onZoneClick(key as ZoneType);
      });

      if (isSelected) {
        const zoom = window.innerWidth < 768 ? 11 : 12;
        mapRef.current?.flyTo(zone.center, zoom, { duration: 1.2 });
      }
    });
  }, [selectedZone]);

  return (
    <div className="relative w-full h-full flex flex-col bg-slate-200">
      <div ref={containerRef} className="w-full h-full" />

      {/* Rosa dos Ventos Fluida */}
      <div className={`
        absolute z-[1000] pointer-events-none transition-all duration-500
        bottom-24 left-6 sm:bottom-12 sm:left-8
        ${mapStyle === 'satellite' ? 'opacity-90 invert grayscale brightness-200' : 'opacity-20'}
      `}>
         <div className="relative w-12 h-12 flex items-center justify-center border-2 border-slate-900 rounded-full">
            <div className="absolute w-px h-[70%] bg-slate-900/40"></div>
            <div className="absolute h-px w-[70%] bg-slate-900/40"></div>
            <div className="absolute w-0 h-0 border-l-[4px] border-l-transparent border-r-[4px] border-r-transparent border-b-[18px] border-b-emerald-600 top-0 -translate-y-1/2"></div>
            <span className="absolute -top-6 text-[10px] font-black text-slate-800">N</span>
         </div>
      </div>
    </div>
  );
};

