};

const RealMap: React.FC<RealMapProps> = ({ onLandmarkClick, mapStyle }) => {
  const mapRef = useRef<L.Map | null>(null);
  const containerRef = useRef<HTMLDivElement>(null);
  const tileLayerRef = useRef<L.TileLayer | null>(null);

  useEffect(() => {
    if (!containerRef.current || mapRef.current) return;

    const map = L.map(containerRef.current, {
      zoomControl: false,
      attributionControl: false,
      tap: true,
      bounceAtZoomLimits: true,
      wheelDebounceTime: 150
    }).setView([-23.5505, -46.6333], 12);

    mapRef.current = map;

    L.control.zoom({ position: 'topright' }).addTo(map);

    tileLayerRef.current = L.tileLayer(TILE_LAYERS[mapStyle], {
      maxZoom: 19,
      crossOrigin: true
    }).addTo(map);

    // Adiciona Marcos
    SP_MAP_DATA.landmarks.forEach(landmark => {
      const icon = L.divIcon({
        className: 'custom-marker',
        html: `<div class="marker-container">
                <div class="bg-emerald-600 w-11 h-11 sm:w-9 sm:h-9 rounded-2xl border-2 border-white shadow-2xl flex items-center justify-center text-white active:scale-125 transition-transform">
                  <svg width="22" height="22" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="3" stroke-linecap="round" stroke-linejoin="round"><path d="M21 10c0 7-9 13-9 13s-9-6-9-13a9 9 0 0 1 18 0z"></path></svg>
                </div>
              </div>`,
        iconSize: [44, 44],
        iconAnchor: [22, 44],
      });

      L.marker([landmark.coordinates.lat, landmark.coordinates.lng], { icon })
        .addTo(map)
        .on('click', (e) => {
          L.DomEvent.stopPropagation(e);
          onLandmarkClick(landmark.id);
          map.flyTo([landmark.coordinates.lat, landmark.coordinates.lng], 15, { duration: 1.5 });
        });
    });

    const resizeObserver = new ResizeObserver(() => {
      if (mapRef.current) mapRef.current.invalidateSize();
    });
    resizeObserver.observe(containerRef.current);

    return () => {
      resizeObserver.disconnect();
      if (mapRef.current) mapRef.current.remove();
      mapRef.current = null;
    };
  }, []);

  useEffect(() => {
    if (!mapRef.current || !tileLayerRef.current) return;
    tileLayerRef.current.setUrl(TILE_LAYERS[mapStyle]);
  }, [mapStyle]);

  return (
    <div className="relative w-full h-full flex flex-col bg-slate-200">
      <div ref={containerRef} className="w-full h-full" />

      {/* Rosa dos Ventos */}
      <div className={`
        absolute z-[1000] pointer-events-none transition-all duration-500
        bottom-28 left-6 lg:bottom-12 lg:left-8
        ${mapStyle === 'satellite' ? 'opacity-80 invert grayscale brightness-200' : 'opacity-10'}
      `}>
         <div className="relative w-10 h-10 lg:w-14 lg:h-14 flex items-center justify-center border-2 border-slate-900 rounded-full">
            <div className="absolute w-px h-[60%] bg-slate-900/30"></div>
            <div className="absolute h-px w-[60%] bg-slate-900/30"></div>
            <div className="absolute w-0 h-0 border-l-[4px] border-l-transparent border-r-[4px] border-r-transparent border-b-[16px] border-b-emerald-600 top-0 -translate-y-1/2"></div>
            <span className="absolute -top-5 text-[9px] font-black text-slate-800 tracking-tighter">N</span>
         </div>
      </div>
    </div>
  );
};

