];

const RealMap: React.FC<RealMapProps> = ({ onLandmarkClick, mapStyle }) => {
  const mapRef = useRef<L.Map | null>(null);
  const containerRef = useRef<HTMLDivElement>(null);
  const tileLayerRef = useRef<L.TileLayer | null>(null);
  const userMarkerRef = useRef<L.Marker | null>(null);
  const [isLocating, setIsLocating] = useState(false);

  useEffect(() => {
    if (!containerRef.current || mapRef.current) return;

    const map = L.map(containerRef.current, {
      zoomControl: false,
      attributionControl: false,
      tap: true,
      bounceAtZoomLimits: true,
      wheelDebounceTime: 150,
      // Restrições geográficas estritas
      maxBounds: STATE_BOUNDS,
      maxBoundsViscosity: 1.0, 
      minZoom: 8, // Aumentado ligeiramente para focar mais no estado
      worldCopyJump: false,
    }).setView([-23.5505, -46.6333], 11);

    mapRef.current = map;

    L.control.zoom({ position: 'topright' }).addTo(map);

    tileLayerRef.current = L.tileLayer(TILE_LAYERS[mapStyle], {
      maxZoom: 19,
      bounds: STATE_BOUNDS, // Impede o carregamento de tiles fora do estado
      noWrap: true,
      crossOrigin: true
    }).addTo(map);

    // Adiciona o limite da cidade (Linha Vermelha)
    L.polyline(SP_BOUNDARY_COORDS, {
      color: '#ef4444',
      weight: 3,
      opacity: 0.7,
      dashArray: '8, 12',
      lineJoin: 'round',
      interactive: false
    }).addTo(map);

    // Adiciona Marcos
    SP_MAP_DATA.landmarks.forEach(landmark => {
      const icon = L.divIcon({
        className: 'custom-marker',
        html: `<div class="marker-container">
                <div class="bg-emerald-600 w-11 h-11 sm:w-9 sm:h-9 rounded-2xl border-2 border-white shadow-2xl flex items-center justify-center text-white active:scale-125 transition-transform">
                  <svg width="22" height="22" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="3" stroke-linecap="round" stroke-linejoin="round"><path d="M21 10c0 7-9 13-9 13s-9-6-9-13a9 9 0 0 1 18 0z"></path></svg>
                </div>
              </div>`,
        iconSize: [44, 44],
        iconAnchor: [22, 44],
      });

      L.marker([landmark.coordinates.lat, landmark.coordinates.lng], { icon })
        .addTo(map)
        .on('click', (e) => {
          L.DomEvent.stopPropagation(e);
          onLandmarkClick(landmark.id);
          map.flyTo([landmark.coordinates.lat, landmark.coordinates.lng], 15, { duration: 1.5 });
        });
    });

    const resizeObserver = new ResizeObserver(() => {
      if (mapRef.current) mapRef.current.invalidateSize();
    });
    resizeObserver.observe(containerRef.current);

    return () => {
      resizeObserver.disconnect();
      if (mapRef.current) mapRef.current.remove();
      mapRef.current = null;
    };
  }, []);

  useEffect(() => {
    if (!mapRef.current || !tileLayerRef.current) return;
    tileLayerRef.current.setUrl(TILE_LAYERS[mapStyle]);
  }, [mapStyle]);

  const handleLocateMe = () => {
    if (!navigator.geolocation) {
      alert("Geolocalização não é suportada pelo seu navegador.");
      return;
    }

    setIsLocating(true);
    navigator.geolocation.getCurrentPosition(
      (position) => {
        const { latitude, longitude } = position.coords;
        const latLng = L.latLng(latitude, longitude);

        setIsLocating(false);

        // Verifica se o usuário está dentro do Estado de SP
        if (!STATE_BOUNDS.contains(latLng)) {
          alert("Você parece estar fora do Estado de São Paulo. O mapa está restrito a esta região.");
          return;
        }

        if (mapRef.current) {
          // Criar ou atualizar marcador do usuário
          if (userMarkerRef.current) {
            userMarkerRef.current.setLatLng(latLng);
          } else {
            const userIcon = L.divIcon({
              className: 'user-location-marker',
              html: `
                <div class="relative flex items-center justify-center">
                  <div class="absolute w-8 h-8 bg-blue-500/30 rounded-full animate-ping"></div>
                  <div class="relative w-5 h-5 bg-blue-600 rounded-full border-2 border-white shadow-lg"></div>
                </div>
              `,
              iconSize: [32, 32],
              iconAnchor: [16, 16],
            });
            userMarkerRef.current = L.marker(latLng, { icon: userIcon, zIndexOffset: 1000 }).addTo(mapRef.current);
          }
          mapRef.current.flyTo(latLng, 14, { duration: 2 });
        }
      },
      (error) => {
        setIsLocating(false);
        console.error("Erro ao obter localização:", error);
        alert("Não foi possível obter sua localização. Verifique as permissões do navegador.");
      },
      { enableHighAccuracy: true, timeout: 5000, maximumAge: 0 }
    );
  };

  return (
    <div className="relative w-full h-full flex flex-col bg-slate-900 overflow-hidden">
      {/* Container do mapa com fundo escuro para destacar o "fim do mundo" fora dos bounds */}
      <div ref={containerRef} className="w-full h-full" />

      {/* Botão Localizar-me */}
      <button
        onClick={handleLocateMe}
        disabled={isLocating}
        className={`
          absolute z-[1000] top-28 right-3 sm:right-4
          bg-white p-3 rounded-2xl shadow-xl border border-slate-200
          text-slate-700 hover:text-blue-600 active:scale-90 transition-all
          ${isLocating ? 'opacity-50 cursor-not-allowed' : 'opacity-100'}
        `}
        title="Onde estou agora?"
      >
        <Navigation size={22} className={isLocating ? 'animate-pulse' : ''} fill={userMarkerRef.current ? '#2563eb' : 'none'} />
      </button>

      {/* Rosa dos Ventos */}
      <div className={`
        absolute z-[1000] pointer-events-none transition-all duration-500
        bottom-28 left-6 lg:bottom-12 lg:left-8
        ${mapStyle === 'satellite' ? 'opacity-80 invert grayscale brightness-200' : 'opacity-10'}
      `}>
         <div className="relative w-10 h-10 lg:w-14 lg:h-14 flex items-center justify-center border-2 border-slate-900 rounded-full">
            <div className="absolute w-px h-[60%] bg-slate-900/30"></div>
            <div className="absolute h-px w-[60%] bg-slate-900/30"></div>
            <div className="absolute w-0 h-0 border-l-[4px] border-l-transparent border-r-[4px] border-r-transparent border-b-[16px] border-b-emerald-600 top-0 -translate-y-1/2"></div>
            <span className="absolute -top-5 text-[9px] font-black text-slate-800 tracking-tighter">N</span>
         </div>
      </div>

      {/* Legenda do Perímetro */}
      <div className="absolute bottom-6 right-6 z-[1000] bg-white/90 backdrop-blur-sm p-2 px-3 rounded-xl border border-slate-200 shadow-sm pointer-events-none flex items-center gap-2">
        <div className="w-6 h-0.5 bg-red-500 border-t border-dashed border-red-500"></div>
        <span className="text-[10px] font-bold text-slate-500 uppercase tracking-wider">Limite Municipal</span>
      </div>
    </div>
  );
};

