import React, { useState, useEffect } from 'react';
import RealMap from './components/RealMap';
import { SP_MAP_DATA } from './constants';
import { Landmark, CustomMarker } from './types';
import { getGroundedLocationInfo } from './services/geminiService';
import { Printer, Compass, Sparkles, ChevronRight, ChevronLeft, ExternalLink, MapPin, X, Layers, Loader2, Plus, Save, Trash2 } from 'lucide-react';

export type MapStyle = 'standard' | 'satellite';

const COLORS = [
  { name: 'Esmeralda', hex: '#10b981' },
  { name: 'Rubi', hex: '#ef4444' },
  { name: 'Safira', hex: '#3b82f6' },
  { name: 'Ouro', hex: '#f59e0b' },
  { name: 'Ametista', hex: '#8b5cf6' },
  { name: 'Ônix', hex: '#1f2937' }
];

const App: React.FC = () => {
  const [selectedLandmark, setSelectedLandmark] = useState<Landmark | CustomMarker | null>(null);
  const [groundedInfo, setGroundedInfo] = useState<{ text: string, links: {uri: string, title: string}[] }>({ text: '', links: [] });
  const [loading, setLoading] = useState<boolean>(false);
  const [isSidebarOpen, setIsSidebarOpen] = useState<boolean>(window.innerWidth >= 1024);
  const [mapStyle, setMapStyle] = useState<MapStyle>('standard');

  // Custom Markers State
  const [customMarkers, setCustomMarkers] = useState<CustomMarker[]>(() => {
    const saved = localStorage.getItem('sp_custom_markers');
    return saved ? JSON.parse(saved) : [];
  });
  const [isAddingMode, setIsAddingMode] = useState(false);
  const [pendingCoords, setPendingCoords] = useState<{lat: number, lng: number} | null>(null);
  const [newMarkerForm, setNewMarkerForm] = useState({ title: '', description: '', color: COLORS[0].hex });

  useEffect(() => {
    localStorage.setItem('sp_custom_markers', JSON.stringify(customMarkers));
  }, [customMarkers]);

  useEffect(() => {
    const handleResize = () => {
      if (window.innerWidth >= 1024) setIsSidebarOpen(true);
    };
    window.addEventListener('resize', handleResize);
    return () => window.removeEventListener('resize', handleResize);
  }, []);

  const handleLandmarkClick = async (id: string) => {
    const landmark = SP_MAP_DATA.landmarks.find(l => l.id === id);
    if (landmark) {
      setSelectedLandmark(landmark);
      setLoading(true);
      const info = await getGroundedLocationInfo(landmark.name);
      setGroundedInfo(info);
      setLoading(false);
      if (window.innerWidth < 1024) setIsSidebarOpen(false); // Close sidebar on mobile if it was open
    }
  };

  const handleCustomLandmarkClick = (marker: CustomMarker) => {
    setSelectedLandmark(marker);
    setGroundedInfo({ text: marker.description, links: [] });
    setLoading(false);
  };

  const handleMapClick = (latlng: any) => {
    if (isAddingMode) {
      setPendingCoords({ lat: latlng.lat, lng: latlng.lng });
    }
  };

  const saveCustomMarker = () => {
    if (!pendingCoords || !newMarkerForm.title) return;

    const newMarker: CustomMarker = {
      id: `custom-${Date.now()}`,
      name: newMarkerForm.title,
      type: 'custom',
      coordinates: pendingCoords,
      description: newMarkerForm.description,
      color: newMarkerForm.color
    };

    setCustomMarkers([...customMarkers, newMarker]);
    setPendingCoords(null);
    setIsAddingMode(false);
    setNewMarkerForm({ title: '', description: '', color: COLORS[0].hex });
  };

  const deleteCustomMarker = (id: string) => {
    setCustomMarkers(customMarkers.filter(m => m.id !== id));
    if (selectedLandmark?.id === id) setSelectedLandmark(null);
  };

  const toggleMapStyle = () => setMapStyle(prev => prev === 'standard' ? 'satellite' : 'standard');
  const activeTitle = selectedLandmark ? selectedLandmark.name : null;

  return (
    <div className="h-[100dvh] w-screen bg-slate-100 text-slate-900 overflow-hidden relative flex flex-col lg:flex-row">

      {/* SIDEBAR */}
      <aside className={`fixed inset-y-0 left-0 lg:relative flex flex-col bg-white border-r border-slate-200 z-[2000] transition-all duration-300 ${isSidebarOpen ? 'w-[400px]' : 'w-0 overflow-hidden border-none'}`}>
        <div className="p-8 border-b border-slate-50 flex justify-between items-center">
          <h1 className="font-display text-2xl font-bold text-slate-800">Sampa Map</h1>
          <button onClick={() => setIsSidebarOpen(false)} className="p-2 hover:bg-slate-100 rounded-lg"><ChevronLeft /></button>
        </div>

        <div className="flex-1 overflow-y-auto p-8 space-y-8 custom-scrollbar">
          {/* Adicionar Marcador Section */}
          <section className="bg-slate-50 p-6 rounded-[32px] border-2 border-dashed border-slate-200">
            {!isAddingMode ? (
              <button 
                onClick={() => setIsAddingMode(true)}
                className="w-full flex items-center justify-center gap-3 py-4 bg-emerald-600 text-white rounded-2xl font-bold hover:bg-emerald-700 transition-all shadow-lg"
              >
                <Plus size={20} /> Novo Marcador
              </button>
            ) : (
              <div className="space-y-4 animate-in fade-in slide-in-from-top-4">
                <div className="flex justify-between items-center mb-2">
                  <h3 className="text-xs font-black text-slate-400 uppercase tracking-widest">Adicionar Local</h3>
                  <button onClick={() => {setIsAddingMode(false); setPendingCoords(null);}} className="text-slate-400 hover:text-slate-600"><X size={16} /></button>
                </div>

                {!pendingCoords ? (
                  <div className="text-center py-4 px-2">
                    <p className="text-sm text-slate-500 font-medium">Ative o modo e clique em qualquer lugar do mapa para escolher a localização.</p>
                  </div>
                ) : (
