import React, { useEffect, useRef, useState } from 'react';
import { SP_MAP_DATA } from '../constants';
import L from 'leaflet';
import { MapStyle } from '../App';
import { Navigation } from 'lucide-react';
import { CustomMarker } from '../types';

interface RealMapProps {
  onLandmarkClick: (id: string) => void;
  onCustomLandmarkClick: (marker: CustomMarker) => void;
  mapStyle: MapStyle;
  customMarkers: CustomMarker[];
  isAddingMode: boolean;
  onMapClick: (latlng: L.LatLng) => void;
  pendingCoords: { lat: number; lng: number } | null;
}

const TILE_LAYERS = {
  standard: 'https://{s}.basemaps.cartocdn.com/rastertiles/voyager/{z}/{x}/{y}{r}.png',
  satellite: 'https://server.arcgisonline.com/ArcGIS/rest/services/World_Imagery/MapServer/tile/{z}/{y}/{x}'
};

const STATE_BOUNDS = L.latLngBounds(
  [-25.5, -53.2],
  [-19.5, -44.0]
);

const SP_BOUNDARY_COORDS: [number, number][] = [
  [-23.3563, -46.6806], [-23.3644, -46.5492], [-23.3934, -46.4957],
  [-23.4111, -46.4255], [-23.4449, -46.3986], [-23.4862, -46.3655],
  [-23.5173, -46.3695], [-23.5684, -46.3888], [-23.6195, -46.4178],
  [-23.6666, -46.4382], [-23.7058, -46.4576], [-23.7554, -46.4908],
  [-23.8407, -46.5652], [-23.9103, -46.6217], [-23.9667, -46.6437],
  [-23.9761, -46.6905], [-23.9103, -46.7291], [-23.8407, -46.7388],
  [-23.7386, -46.7842], [-23.6811, -46.8311], [-23.6262, -46.8242],
  [-23.5857, -46.8214], [-23.5411, -46.8352], [-23.4977, -46.8256],
  [-23.4474, -46.7911], [-23.4042, -46.7608], [-23.3563, -46.6806]
];

const RealMap: React.FC<RealMapProps> = ({ 
  onLandmarkClick, 
  onCustomLandmarkClick,
  mapStyle, 
  customMarkers, 
  isAddingMode, 
  onMapClick,
  pendingCoords
}) => {
  const mapRef = useRef<L.Map | null>(null);
  const containerRef = useRef<HTMLDivElement>(null);
  const tileLayerRef = useRef<L.TileLayer | null>(null);
  const userMarkerRef = useRef<L.Marker | null>(null);
  const pendingMarkerRef = useRef<L.Marker | null>(null);
  const customMarkersLayerRef = useRef<L.LayerGroup | null>(null);
  const [isLocating, setIsLocating] = useState(false);

  // IMPORTANTE: Ref para evitar stale closure no evento de clique do mapa
  const onMapClickRef = useRef(onMapClick);
  useEffect(() => {
    onMapClickRef.current = onMapClick;
  }, [onMapClick]);

  useEffect(() => {
    if (!containerRef.current || mapRef.current) return;

    const map = L.map(containerRef.current, {
      zoomControl: false,
      attributionControl: false,
      tap: true,
      bounceAtZoomLimits: true,
      wheelDebounceTime: 150,
      maxBounds: STATE_BOUNDS,
      maxBoundsViscosity: 1.0, 
      minZoom: 8,
      worldCopyJump: false,
    }).setView([-23.5505, -46.6333], 11);

    mapRef.current = map;
    customMarkersLayerRef.current = L.layerGroup().addTo(map);

    L.control.zoom({ position: 'topright' }).addTo(map);

    tileLayerRef.current = L.tileLayer(TILE_LAYERS[mapStyle], {
      maxZoom: 19,
      bounds: STATE_BOUNDS,
      noWrap: true,
      crossOrigin: true
    }).addTo(map);

    L.polyline(SP_BOUNDARY_COORDS, {
      color: '#ef4444',
      weight: 3,
      opacity: 0.7,
      dashArray: '8, 12',
      lineJoin: 'round',
      interactive: false
    }).addTo(map);

    // Marcos Oficiais
    SP_MAP_DATA.landmarks.forEach(landmark => {
      const icon = L.divIcon({
        className: 'custom-marker',
        html: `<div class="marker-container">
                <div class="bg-emerald-600 w-11 h-11 sm:w-9 sm:h-9 rounded-2xl border-2 border-white shadow-2xl flex items-center justify-center text-white active:scale-125 transition-transform">
                  <svg width="22" height="22" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="3" stroke-linecap="round" stroke-linejoin="round"><path d="M21 10c0 7-9 13-9 13s-9-6-9-13a9 9 0 0 1 18 0z"></path></svg>
                </div>
              </div>`,
        iconSize: [44, 44],
        iconAnchor: [22, 44],
      });

      L.marker([landmark.coordinates.lat, landmark.coordinates.lng], { icon })
        .addTo(map)
        .on('click', (e) => {
          L.DomEvent.stopPropagation(e);
          onLandmarkClick(landmark.id);
          map.flyTo([landmark.coordinates.lat, landmark.coordinates.lng], 15, { duration: 1.5 });
        });
    });

    // Evento de clique no mapa usando a Ref para garantir acesso ao estado atual de isAddingMode em App.tsx
    map.on('click', (e) => {
      onMapClickRef.current(e.latlng);
    });

    const resizeObserver = new ResizeObserver(() => {
      if (mapRef.current) mapRef.current.invalidateSize();
    });
    resizeObserver.observe(containerRef.current);

    return () => {
      resizeObserver.disconnect();
      if (mapRef.current) mapRef.current.remove();
      mapRef.current = null;
    };
  }, []);

  // Atualiza Marcadores Personalizados
  useEffect(() => {
    if (!mapRef.current || !customMarkersLayerRef.current) return;

    customMarkersLayerRef.current.clearLayers();

    customMarkers.forEach(marker => {
      const icon = L.divIcon({
        className: 'user-custom-marker',
        html: `<div class="marker-container">
                <div style="background-color: ${marker.color}" class="w-11 h-11 sm:w-9 sm:h-9 rounded-2xl border-2 border-white shadow-2xl flex items-center justify-center text-white active:scale-125 transition-transform">
                  <svg width="22" height="22" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="3" stroke-linecap="round" stroke-linejoin="round"><path d="M21 10c0 7-9 13-9 13s-9-6-9-13a9 9 0 0 1 18 0z"></path></svg>
                </div>
              </div>`,
        iconSize: [44, 44],
        iconAnchor: [22, 44],
      });

      L.marker([marker.coordinates.lat, marker.coordinates.lng], { icon })
        .addTo(customMarkersLayerRef.current!)
        .on('click', (e) => {
          L.DomEvent.stopPropagation(e);
          onCustomLandmarkClick(marker);
          mapRef.current?.flyTo([marker.coordinates.lat, marker.coordinates.lng], 15, { duration: 1.5 });
        });
    });
  }, [customMarkers]);

  // Gerencia o marcador "fantasma" de quando o usuário clica mas ainda não salvou
  useEffect(() => {
    if (!mapRef.current) return;

    if (pendingCoords) {
      if (pendingMarkerRef.current) {
        pendingMarkerRef.current.setLatLng([pendingCoords.lat, pendingCoords.lng]);
      } else {
        const ghostIcon = L.divIcon({
          className: 'pending-marker',
          html: `<div class="animate-bounce opacity-70">
                  <div class="bg-slate-400 w-9 h-9 rounded-2xl border-2 border-white shadow-lg flex items-center justify-center text-white">
                    <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="3"><path d="M21 10c0 7-9 13-9 13s-9-6-9-13a9 9 0 0 1 18 0z"></path></svg>
                  </div>
                </div>`,
          iconSize: [36, 36],
          iconAnchor: [18, 36],
        });
        pendingMarkerRef.current = L.marker([pendingCoords.lat, pendingCoords.lng], { icon: ghostIcon }).addTo(mapRef.current);
      }
    } else {
      if (pendingMarkerRef.current) {
        pendingMarkerRef.current.remove();
        pendingMarkerRef.current = null;
      }
    }
  }, [pendingCoords]);

  useEffect(() => {
    if (!mapRef.current || !tileLayerRef.current) return;
    tileLayerRef.current.setUrl(TILE_LAYERS[mapStyle]);
  }, [mapStyle]);

  const handleLocateMe = () => {
    if (!navigator.geolocation) {
      alert("Geolocalização não é suportada.");
      return;
    }

    setIsLocating(true);
    navigator.geolocation.getCurrentPosition(
      (position) => {
        const { latitude, longitude } = position.coords;
        const latLng = L.latLng(latitude, longitude);
        setIsLocating(false);

        if (!STATE_BOUNDS.contains(latLng)) {
          alert("Você está fora de São Paulo.");
          return;
        }

        if (mapRef.current) {
          if (userMarkerRef.current) {
            userMarkerRef.current.setLatLng(latLng);
          } else {
            const userIcon = L.divIcon({
              className: 'user-location-marker',
              html: `<div class="relative flex items-center justify-center"><div class="absolute w-8 h-8 bg-blue-500/30 rounded-full animate-ping"></div><div class="relative w-5 h-5 bg-blue-600 rounded-full border-2 border-white shadow-lg"></div></div>`,
              iconSize: [32, 32],
              iconAnchor: [16, 16],
            });
            userMarkerRef.current = L.marker(latLng, { icon: userIcon, zIndexOffset: 1000 }).addTo(mapRef.current);
          }
          mapRef.current.flyTo(latLng, 14, { duration: 2 });
        }
      },
      () => {
        setIsLocating(false);
        alert("Erro ao obter localização.");
      }
    );
  };

  return (
    <div className={`relative w-full h-full flex flex-col bg-slate-900 overflow-hidden ${isAddingMode ? 'cursor-crosshair' : ''}`}>
      <div ref={containerRef} className="w-full h-full" />

      {isAddingMode && (
        <div className="absolute top-4 left-1/2 -translate-x-1/2 z-[1001] bg-emerald-600 text-white px-6 py-2 rounded-full font-bold shadow-2xl border-2 border-white animate-bounce pointer-events-none">
          {pendingCoords ? "Local definido! Preencha os dados na lateral" : "Clique no mapa para escolher o local"}
        </div>
      )}

      <button
        onClick={handleLocateMe}
        disabled={isLocating}
        className={`absolute z-[1000] top-28 right-3 sm:right-4 bg-white p-3 rounded-2xl shadow-xl border border-slate-200 text-slate-700 hover:text-blue-600 active:scale-90 transition-all ${isLocating ? 'opacity-50' : 'opacity-100'}`}
      >
        <Navigation size={22} className={isLocating ? 'animate-pulse' : ''} fill={userMarkerRef.current ? '#2563eb' : 'none'} />
      </button>

      <div className={`absolute z-[1000] pointer-events-none transition-all duration-500 bottom-28 left-6 lg:bottom-12 lg:left-8 ${mapStyle === 'satellite' ? 'opacity-80 invert grayscale brightness-200' : 'opacity-10'}`}>
         <div className="relative w-10 h-10 lg:w-14 lg:h-14 flex items-center justify-center border-2 border-slate-900 rounded-full">
            <div className="absolute w-px h-[60%] bg-slate-900/30"></div>
            <div className="absolute h-px w-[60%] bg-slate-900/30"></div>
            <div className="absolute w-0 h-0 border-l-[4px] border-l-transparent border-r-[4px] border-r-transparent border-b-[16px] border-b-emerald-600 top-0 -translate-y-1/2"></div>
            <span className="absolute -top-5 text-[9px] font-black text-slate-800 tracking-tighter">N</span>
         </div>
      </div>

      <div className="absolute bottom-6 right-6 z-[1000] bg-white/90 backdrop-blur-sm p-2 px-3 rounded-xl border border-slate-200 shadow-sm pointer-events-none flex items-center gap-2">
        <div className="w-6 h-0.5 bg-red-500 border-t border-dashed border-red-500"></div>
        <span className="text-[10px] font-bold text-slate-500 uppercase tracking-wider">Limite Municipal</span>
      </div>
    </div>
  );
};

export default RealMap;

