                      <button 
                        onClick={saveCustomMarker}
                        disabled={!newMarkerForm.title}
                        className="flex-[2] flex items-center justify-center gap-2 py-4 bg-slate-900 text-white rounded-2xl font-bold disabled:opacity-50 active:scale-95 transition-all"
                      >
                        Salvar Local
