                    </button>
                    <button 
                      onClick={() => deleteCustomMarker(marker.id)}
                      className={`p-2 rounded-lg hover:bg-red-500/10 ${selectedLandmark?.id === marker.id ? 'text-red-400' : 'text-slate-400'}`}
                    >
                      <Trash2 size={16} />
