                    <h2 className="text-xl font-bold leading-none">{selectedLandmark.name}</h2>
                    <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mt-1.5">Marcador Personalizado</p>
                  </div>
                </div>
                <button onClick={() => setSelectedLandmark(null)} className="bg-slate-50 p-2.5 rounded-full text-slate-400"><X size={20} /></button>
              </div>
              <div className="bg-slate-50 p-6 rounded-3xl">
                <p className="text-slate-600 leading-relaxed">{selectedLandmark.description || "Sem descrição."}</p>
                <button 
                  onClick={() => deleteCustomMarker(selectedLandmark.id)}
                  className="mt-6 flex items-center justify-center gap-2 w-full py-4 text-red-500 font-bold border-2 border-red-500/20 rounded-2xl hover:bg-red-50"
                >
                  <Trash2 size={18} /> Remover Marcador
                </button>
              </div>
           </div>
        </div>
      )}

      <div className="lg:hidden absolute inset-0 z-[1000] pointer-events-none">
        <div className="absolute top-4 left-4 right-4 flex justify-end items-center pointer-events-auto">
          <button 
            onClick={toggleMapStyle}
            className="bg-white/90 backdrop-blur-xl p-3.5 rounded-full shadow-2xl border border-white/50 text-slate-700 active:scale-90 transition-transform"
          >
            <Layers size={22} className={mapStyle === 'satellite' ? 'text-emerald-600' : ''} />
          </button>
        </div>

        {activeTitle && selectedLandmark?.type !== 'custom' && (
          <div className="absolute inset-x-0 bottom-0 pointer-events-auto animate-in slide-in-from-bottom-full duration-500 ease-out">
            <div className="bg-white rounded-t-[40px] shadow-[0_-20px_50px_-12px_rgba(0,0,0,0.15)] p-6 pb-12 max-h-[85vh] overflow-y-auto custom-scrollbar relative">
              <div className="w-12 h-1.5 bg-slate-100 rounded-full mx-auto mb-6" />
              <div className="flex justify-between items-start mb-6">
                <div className="flex items-center gap-4">
                  <div className="bg-emerald-600/10 p-3.5 rounded-2xl text-emerald-600">
                    <MapPin size={24} />
                  </div>
                  <div>
                    <h2 className="text-xl font-bold leading-none">{activeTitle}</h2>
                    <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mt-1.5">Localização Oficial</p>
                  </div>
                </div>
                <button onClick={() => setSelectedLandmark(null)} className="bg-slate-50 p-2.5 rounded-full text-slate-400"><X size={20} /></button>
              </div>
              <div className="space-y-6">
                <div className="bg-slate-50/80 p-5 rounded-3xl border border-slate-100">
                  <div className="flex items-center gap-2 mb-4 text-emerald-600 font-black text-[9px] uppercase tracking-[0.2em]">
