                      {groundedInfo.links.length > 0 && (
                        <div className="mt-6 pt-5 border-t border-slate-200/50 space-y-2">
                          {groundedInfo.links.map((link, i) => (
                            <a key={i} href={link.uri} target="_blank" rel="noopener noreferrer" className="flex items-center justify-between p-4 bg-white rounded-2xl border border-slate-100 shadow-sm">
                              <span className="text-xs font-bold text-slate-700 truncate pr-4">{link.title}</span>
                              <ExternalLink size={14} className="text-emerald-500" />
                            </a>
                          ))}
                        </div>
                      )}
                    </>
                  )}
                </div>
              </div>
            </div>
          </div>
        )}
      </div>

      <main className="flex-1 relative bg-slate-200 no-print">
        <div className="absolute inset-0">
          <RealMap 
            onLandmarkClick={handleLandmarkClick}
            onCustomLandmarkClick={handleCustomLandmarkClick}
            mapStyle={mapStyle}
            customMarkers={customMarkers}
            isAddingMode={isAddingMode}
            onMapClick={handleMapClick}
            pendingCoords={pendingCoords}
          />
        </div>
      </main>

      <div className="hidden print:block fixed inset-0 bg-white z-[9999] p-12">
        <div className="flex justify-between items-end mb-8 border-b-4 border-slate-900 pb-6">
          <div>
            <h1 className="text-6xl font-display text-slate-900">São Paulo</h1>
            <p className="text-xl font-bold text-slate-500 uppercase tracking-[0.3em] mt-2">Mapa Turístico e Pessoal</p>
          </div>
          <div className="text-right">
            <p className="text-sm font-black text-slate-400">GUIA DE MARCOS REAIS E LOCAIS SALVOS</p>
          </div>
        </div>
        <div className="h-[800px] border-4 border-slate-100 rounded-[40px] overflow-hidden">
          <RealMap 
            onLandmarkClick={handleLandmarkClick}
            onCustomLandmarkClick={handleCustomLandmarkClick}
            mapStyle={mapStyle}
            customMarkers={customMarkers}
            isAddingMode={false}
            onMapClick={()=>{}}
            pendingCoords={null}
          />
        </div>
      </div>
    </div>
  );
};

