                  ) : (
                    <div className="space-y-4 animate-in fade-in slide-in-from-top-2">
                      <input 
                        type="text" 
                        placeholder="Nome do lugar (ex: Meu Café Favorito)" 
                        className="w-full p-4 rounded-2xl border-none ring-1 ring-slate-200 text-sm font-medium focus:ring-2 focus:ring-emerald-500 outline-none transition-shadow"
                        value={newMarkerForm.title}
                        onChange={e => setNewMarkerForm({...newMarkerForm, title: e.target.value})}
                      />
                      <textarea 
                        placeholder="Adicione uma breve descrição ou nota..." 
                        rows={3}
                        className="w-full p-4 rounded-2xl border-none ring-1 ring-slate-200 text-sm font-medium focus:ring-2 focus:ring-emerald-500 outline-none resize-none transition-shadow"
                        value={newMarkerForm.description}
                        onChange={e => setNewMarkerForm({...newMarkerForm, description: e.target.value})}
                      />
                      <div className="space-y-2">
                        <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest px-1">Cor do Ícone</p>
                        <div className="flex flex-wrap gap-2.5">
                          {COLORS.map(c => (
                            <button 
                              key={c.hex}
                              onClick={() => setNewMarkerForm({...newMarkerForm, color: c.hex})}
                              className={`w-9 h-9 rounded-full border-4 transition-all ${newMarkerForm.color === c.hex ? 'border-emerald-500 scale-110 shadow-lg' : 'border-white hover:scale-105'}`}
                              style={{ backgroundColor: c.hex }}
                            />
                          ))}
                        </div>
                      </div>
                      <div className="flex flex-col gap-2 pt-2">
                        <button 
                          onClick={saveCustomMarker}
                          disabled={!newMarkerForm.title}
                          className="w-full py-4.5 bg-emerald-600 text-white rounded-[24px] font-bold disabled:opacity-50 active:scale-95 transition-all shadow-lg shadow-emerald-600/20"
                        >
                          Salvar Localização
                        </button>
                        <button 
                          onClick={() => setPendingCoords(null)}
                          className="w-full py-3 text-xs font-bold text-slate-400 hover:text-slate-600"
                        >
                          Alterar ponto no mapa
