                      </div>
                    </div>
                  )}
                </div>
              )}
            </section>

            {/* LISTA DE LUGARES */}
            <div className="space-y-8">
              {/* Meus Lugares */}
              {customMarkers.length > 0 && (
                <section>
                  <h2 className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] mb-4 flex items-center gap-2">
                    <Sparkles size={14} className="text-blue-500" /> Lugares Salvos ({customMarkers.length})
                  </h2>
                  <div className="space-y-2">
                    {customMarkers.map((marker) => (
                      <div 
                        key={marker.id}
                        className={`group flex items-center justify-between p-4 rounded-2xl transition-all border-2 ${selectedLandmark?.id === marker.id ? 'bg-slate-900 border-slate-900 text-white shadow-xl' : 'bg-white border-slate-100 hover:border-slate-200 text-slate-600'}`}
                      >
                        <button
                          onClick={() => handleCustomLandmarkClick(marker)}
                          className="flex-1 flex items-center gap-4 text-left overflow-hidden"
                        >
                          <div className="w-3.5 h-3.5 rounded-full flex-shrink-0 shadow-inner" style={{ backgroundColor: marker.color }} />
                          <span className="font-bold text-sm truncate">{marker.name}</span>
                        </button>
                        <button 
                          onClick={() => deleteCustomMarker(marker.id)}
                          className={`p-2 rounded-xl transition-colors ${selectedLandmark?.id === marker.id ? 'text-slate-400 hover:text-red-400' : 'text-slate-300 hover:text-red-500 hover:bg-red-50'}`}
                        >
                          <Trash2 size={16} />
                        </button>
                      </div>
                    ))}
                  </div>
                </section>
              )}

              {/* Oficiais */}
              <section>
                <h2 className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] mb-4 flex items-center gap-2">
                  <Compass size={14} className="text-emerald-500" /> Marcos de São Paulo
                </h2>
                <div className="grid grid-cols-1 gap-2">
                  {SP_MAP_DATA.landmarks.map((landmark) => (
                    <button
                      key={landmark.id}
                      onClick={() => handleLandmarkClick(landmark.id)}
                      className={`flex items-center justify-between p-4 rounded-2xl transition-all border-2 ${selectedLandmark?.id === landmark.id ? 'bg-slate-900 border-slate-900 text-white shadow-xl' : 'bg-white border-slate-100 hover:border-slate-200 text-slate-600 shadow-sm'}`}
                    >
                      <div className="flex items-center gap-4">
                        <MapPin size={18} className={selectedLandmark?.id === landmark.id ? 'text-emerald-400' : 'text-slate-300'} />
                        <span className="font-bold text-sm truncate">{landmark.name}</span>
                      </div>
                      <ChevronRight size={16} opacity={0.5} />
                    </button>
                  ))}
                </div>
              </section>
            </div>
          </div>

          <div className="p-8 bg-slate-50/50">
            <button onClick={() => window.print()} className="w-full py-4.5 bg-white text-slate-800 border border-slate-200 rounded-[24px] font-bold hover:bg-slate-900 hover:text-white transition-all shadow-sm active:scale-95">Imprimir Mapa</button>
          </div>
        </div>
      </aside>

      {/* OVERLAY PARA MOBILE SIDEBAR */}
      {isSidebarOpen && window.innerWidth < 1024 && (
        <div 
          className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm z-[2500] transition-opacity"
          onClick={() => setIsSidebarOpen(false)}
        />
      )}

      {/* MAPA PRINCIPAL */}
      <main className="flex-1 relative bg-slate-100 no-print">
        <RealMap 
          onLandmarkClick={handleLandmarkClick}
          onCustomLandmarkClick={handleCustomLandmarkClick}
          mapStyle={mapStyle}
          customMarkers={customMarkers}
          isAddingMode={isAddingMode}
          onMapClick={handleMapClick}
          pendingCoords={pendingCoords}
        />

        {/* CONTROLES FLUTUANTES (Top Right) */}
        <div className="absolute top-4 right-4 z-[1000] flex flex-col gap-3">
          <button 
            onClick={() => setIsSidebarOpen(true)}
            className="lg:hidden bg-white/95 backdrop-blur-md p-3.5 rounded-2xl shadow-xl border border-white text-slate-800 active:scale-90 transition-all flex items-center justify-center"
          >
