        {/* MODO DE ADIÇÃO (Floating UI) */}
        {isAddingMode && (
          <div className="absolute top-6 left-1/2 -translate-x-1/2 z-[2000] w-[90%] sm:w-auto">
            <div className="bg-emerald-600 text-white px-6 py-3.5 rounded-full font-bold shadow-2xl border-2 border-white/20 flex items-center gap-3 animate-sheet">
              <div className="w-2 h-2 bg-white rounded-full animate-ping" />
              <span className="text-sm whitespace-nowrap">
                {pendingCoords ? "Local selecionado!" : "Toque para fixar o ponto"}
              </span>
              <button 
                onClick={() => {setIsAddingMode(false); setPendingCoords(null);}}
                className="ml-2 p-1 hover:bg-white/20 rounded-full"
              >
                <X size={18} />
              </button>
            </div>
          </div>
        )}

        {/* BOTTOM SHEET - DETALHES DO LOCAL (MOBILE) */}
        {selectedLandmark && (
          <div className="lg:hidden fixed inset-x-0 bottom-0 z-[4000] px-4 pb-8 pointer-events-none">
            <div className="bg-white rounded-[40px] shadow-[0_-20px_60px_-15px_rgba(0,0,0,0.2)] pointer-events-auto animate-sheet overflow-hidden max-h-[80vh] flex flex-col">
              {/* Handle */}
              <div className="w-full py-4 flex flex-col items-center">
                <div className="w-10 h-1.5 bg-slate-100 rounded-full mb-2" />
              </div>

              <div className="px-8 pb-10 overflow-y-auto custom-scrollbar">
                <div className="flex justify-between items-start mb-6">
                  <div className="flex items-center gap-4">
                    <div className={`p-4 rounded-[22px] text-white shadow-lg ${selectedLandmark.type === 'custom' ? '' : 'bg-emerald-600'}`} style={{ backgroundColor: selectedLandmark.type === 'custom' ? (selectedLandmark as CustomMarker).color : undefined }}>
                      {selectedLandmark.type === 'custom' ? <Sparkles size={24} /> : <MapPin size={24} />}
                    </div>
                    <div>
                      <h2 className="text-2xl font-black text-slate-900 tracking-tight leading-tight">{selectedLandmark.name}</h2>
                      <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mt-1.5">
                        {selectedLandmark.type === 'custom' ? 'Marcador Pessoal' : 'Marco da Cidade'}
                      </p>
                    </div>
                  </div>
                  <button onClick={() => setSelectedLandmark(null)} className="bg-slate-50 p-2.5 rounded-full text-slate-400 active:scale-90"><X size={20} /></button>
                </div>

                <div className="space-y-6">
                  {loading ? (
                    <div className="flex flex-col items-center py-12 bg-slate-50 rounded-[32px] gap-4">
                      <div className="relative">
                        <div className="absolute inset-0 bg-emerald-500/20 blur-xl rounded-full animate-pulse" />
                        <Loader2 className="animate-spin text-emerald-600 relative" size={40} />
                      </div>
                      <span className="text-xs font-bold text-slate-400 uppercase tracking-widest">IA Consultando...</span>
                    </div>
                  ) : (
                    <div className="bg-slate-50 p-6 rounded-[32px] border border-slate-100">
                      <div className="flex items-center gap-2 mb-4 text-emerald-600 font-black text-[9px] uppercase tracking-[0.2em]">
                        <Info size={12} /> Sobre este local
                      </div>
                      <p className="text-slate-700 text-base leading-relaxed font-medium">
                        {selectedLandmark.type === 'custom' ? selectedLandmark.description : groundedInfo.text}
                      </p>

                      {selectedLandmark.type !== 'custom' && groundedInfo.links.length > 0 && (
                        <div className="mt-8 space-y-3">
                          <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest px-1">Links Úteis</p>
                          {groundedInfo.links.map((link, i) => (
                            <a 
                              key={i} 
                              href={link.uri} 
                              target="_blank" 
                              rel="noopener noreferrer" 
                              className="flex items-center justify-between p-5 bg-white rounded-2xl border border-slate-100 shadow-sm active:scale-[0.98] transition-all"
                            >
                              <div className="flex items-center gap-3 overflow-hidden">
                                <div className="w-8 h-8 bg-blue-50 text-blue-500 rounded-lg flex items-center justify-center flex-shrink-0">
                                  <MapIcon size={16} />
                                </div>
                                <span className="text-sm font-bold text-slate-800 truncate">{link.title}</span>
                              </div>
                              <ExternalLink size={16} className="text-slate-300" />
                            </a>
                          ))}
                        </div>
                      )}
                    </div>
                  )}

                  {selectedLandmark.type === 'custom' && (
                    <button 
                      onClick={() => deleteCustomMarker(selectedLandmark.id)}
                      className="flex items-center justify-center gap-3 w-full py-5 text-red-500 font-bold border-2 border-red-500/10 rounded-[24px] hover:bg-red-50 transition-colors active:scale-95"
                    >
                      <Trash2 size={20} /> Remover este lugar
                    </button>
                  )}
                </div>
              </div>
            </div>
          </div>
        )}
      </main>

      {/* PRINT LAYER */}
      <div className="hidden print:block fixed inset-0 bg-white z-[9999] p-12">
        <div className="flex justify-between items-end mb-8 border-b-4 border-slate-900 pb-6">
          <div>
            <h1 className="text-6xl font-display text-slate-900 font-black">São Paulo</h1>
            <p className="text-xl font-bold text-slate-500 uppercase tracking-[0.3em] mt-2">Guia Turístico & Pessoal</p>
          </div>
          <div className="text-right">
            <p className="text-sm font-black text-slate-400">PONTOS DE INTERESSE SALVOS</p>
          </div>
        </div>
        <div className="h-[800px] border-4 border-slate-100 rounded-[40px] overflow-hidden">
          <RealMap 
            onLandmarkClick={()=>{}}
            onCustomLandmarkClick={()=>{}}
            mapStyle={mapStyle}
            customMarkers={customMarkers}
            isAddingMode={false}
            onMapClick={()=>{}}
            pendingCoords={null}
          />
        </div>
      </div>
    </div>
  );
};

export default App;

import React, { useEffect, useRef, useState } from 'react';
import { SP_MAP_DATA } from '../constants';
import L from 'leaflet';
import { MapStyle } from '../App';
import { Navigation } from 'lucide-react';
import { CustomMarker } from '../types';

interface RealMapProps {
  onLandmarkClick: (id: string) => void;
  onCustomLandmarkClick: (marker: CustomMarker) => void;
  mapStyle: MapStyle;
  customMarkers: CustomMarker[];
  isAddingMode: boolean;
  onMapClick: (latlng: L.LatLng) => void;
  pendingCoords: { lat: number; lng: number } | null;
}

const TILE_LAYERS = {
  standard: 'https://{s}.basemaps.cartocdn.com/rastertiles/voyager/{z}/{x}/{y}{r}.png',
  satellite: 'https://server.arcgisonline.com/ArcGIS/rest/services/World_Imagery/MapServer/tile/{z}/{y}/{x}'
};

const STATE_BOUNDS = L.latLngBounds(
  [-25.5, -53.2],
  [-19.5, -44.0]
);

const SP_BOUNDARY_COORDS: [number, number][] = [
  [-23.3563, -46.6806], [-23.3644, -46.5492], [-23.3934, -46.4957],
  [-23.4111, -46.4255], [-23.4449, -46.3986], [-23.4862, -46.3655],
  [-23.5173, -46.3695], [-23.5684, -46.3888], [-23.6195, -46.4178],
  [-23.6666, -46.4382], [-23.7058, -46.4576], [-23.7554, -46.4908],
  [-23.8407, -46.5652], [-23.9103, -46.6217], [-23.9667, -46.6437],
  [-23.9761, -46.6905], [-23.9103, -46.7291], [-23.8407, -46.7388],
  [-23.7386, -46.7842], [-23.6811, -46.8311], [-23.6262, -46.8242],
  [-23.5857, -46.8214], [-23.5411, -46.8352], [-23.4977, -46.8256],
  [-23.4474, -46.7911], [-23.4042, -46.7608], [-23.3563, -46.6806]
];

const RealMap: React.FC<RealMapProps> = ({ 
  onLandmarkClick, 
  onCustomLandmarkClick,
  mapStyle, 
  customMarkers, 
  isAddingMode, 
  onMapClick,
  pendingCoords
}) => {
  const mapRef = useRef<L.Map | null>(null);
  const containerRef = useRef<HTMLDivElement>(null);
  const tileLayerRef = useRef<L.TileLayer | null>(null);
  const userMarkerRef = useRef<L.Marker | null>(null);
  const pendingMarkerRef = useRef<L.Marker | null>(null);
  const customMarkersLayerRef = useRef<L.LayerGroup | null>(null);
  const [isLocating, setIsLocating] = useState(false);

  const onMapClickRef = useRef(onMapClick);
  useEffect(() => {
    onMapClickRef.current = onMapClick;
  }, [onMapClick]);

  useEffect(() => {
    if (!containerRef.current || mapRef.current) return;

    const map = L.map(containerRef.current, {
      zoomControl: false,
      attributionControl: false,
      tap: true,
      bounceAtZoomLimits: true,
      wheelDebounceTime: 150,
      maxBounds: STATE_BOUNDS,
      maxBoundsViscosity: 1.0, 
      minZoom: 8,
      worldCopyJump: false,
    }).setView([-23.5505, -46.6333], 11);

    mapRef.current = map;
    customMarkersLayerRef.current = L.layerGroup().addTo(map);

    // Ajustar posição do zoom para o centro-direita para não bater nos botões flutuantes do App.tsx
    L.control.zoom({ position: 'topright' }).addTo(map);

    tileLayerRef.current = L.tileLayer(TILE_LAYERS[mapStyle], {
      maxZoom: 19,
      bounds: STATE_BOUNDS,
      noWrap: true,
      crossOrigin: true
    }).addTo(map);

    // Limite da cidade
    L.polyline(SP_BOUNDARY_COORDS, {
      color: '#ef4444',
      weight: 3,
      opacity: 0.6,
      dashArray: '10, 15',
      lineJoin: 'round',
      interactive: false
    }).addTo(map);

    // Marcos Oficiais
    SP_MAP_DATA.landmarks.forEach(landmark => {
      const icon = L.divIcon({
        className: 'custom-marker',
        html: `<div class="marker-container">
                <div class="bg-emerald-600 w-10 h-10 rounded-[14px] border-2 border-white shadow-lg flex items-center justify-center text-white">
                  <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="3"><path d="M21 10c0 7-9 13-9 13s-9-6-9-13a9 9 0 0 1 18 0z"></path></svg>
                </div>
              </div>`,
        iconSize: [40, 40],
        iconAnchor: [20, 40],
      });

      L.marker([landmark.coordinates.lat, landmark.coordinates.lng], { icon })
        .addTo(map)
        .on('click', (e) => {
          L.DomEvent.stopPropagation(e);
          onLandmarkClick(landmark.id);
          map.flyTo([landmark.coordinates.lat, landmark.coordinates.lng], 15, { duration: 1.5 });
        });
    });

    map.on('click', (e) => {
      onMapClickRef.current(e.latlng);
    });

    const resizeObserver = new ResizeObserver(() => {
      if (mapRef.current) mapRef.current.invalidateSize();
    });
    resizeObserver.observe(containerRef.current);

    return () => {
      resizeObserver.disconnect();
      if (mapRef.current) mapRef.current.remove();
      mapRef.current = null;
    };
  }, []);

  // Marcadores Customizados
  useEffect(() => {
    if (!mapRef.current || !customMarkersLayerRef.current) return;
    customMarkersLayerRef.current.clearLayers();

    customMarkers.forEach(marker => {
      const icon = L.divIcon({
        className: 'user-custom-marker',
        html: `<div class="marker-container">
                <div style="background-color: ${marker.color}" class="w-10 h-10 rounded-[14px] border-2 border-white shadow-lg flex items-center justify-center text-white">
                  <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="3"><path d="M21 10c0 7-9 13-9 13s-9-6-9-13a9 9 0 0 1 18 0z"></path></svg>
                </div>
              </div>`,
        iconSize: [40, 40],
        iconAnchor: [20, 40],
      });

      L.marker([marker.coordinates.lat, marker.coordinates.lng], { icon })
        .addTo(customMarkersLayerRef.current!)
        .on('click', (e) => {
          L.DomEvent.stopPropagation(e);
          onCustomLandmarkClick(marker);
          mapRef.current?.flyTo([marker.coordinates.lat, marker.coordinates.lng], 15, { duration: 1.5 });
        });
    });
  }, [customMarkers]);

  // Marcador Temporário (Pending)
  useEffect(() => {
    if (!mapRef.current) return;
    if (pendingCoords) {
      if (pendingMarkerRef.current) {
        pendingMarkerRef.current.setLatLng([pendingCoords.lat, pendingCoords.lng]);
      } else {
        const ghostIcon = L.divIcon({
          className: 'pending-marker',
          html: `<div class="animate-bounce">
                  <div class="bg-slate-900 w-12 h-12 rounded-[18px] border-4 border-white shadow-2xl flex items-center justify-center text-emerald-400">
                    <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="4"><path d="M12 5v14M5 12h14"></path></svg>
                  </div>
                </div>`,
          iconSize: [48, 48],
          iconAnchor: [24, 48],
        });
        pendingMarkerRef.current = L.marker([pendingCoords.lat, pendingCoords.lng], { icon: ghostIcon }).addTo(mapRef.current);
      }
    } else if (pendingMarkerRef.current) {
      pendingMarkerRef.current.remove();
      pendingMarkerRef.current = null;
    }
  }, [pendingCoords]);

  useEffect(() => {
    if (!mapRef.current || !tileLayerRef.current) return;
    tileLayerRef.current.setUrl(TILE_LAYERS[mapStyle]);
  }, [mapStyle]);

  const handleLocateMe = () => {
    if (!navigator.geolocation) return;
    setIsLocating(true);
    navigator.geolocation.getCurrentPosition(
      (position) => {
        const { latitude, longitude } = position.coords;
        const latLng = L.latLng(latitude, longitude);
        setIsLocating(false);
        if (!STATE_BOUNDS.contains(latLng)) {
          alert("Fora de SP");
          return;
        }
        if (mapRef.current) {
          if (!userMarkerRef.current) {
            const userIcon = L.divIcon({
              className: 'user-pos',
              html: `<div class="relative"><div class="absolute inset-0 w-8 h-8 bg-blue-500/20 rounded-full animate-ping -translate-x-1/2 -translate-y-1/2"></div><div class="w-4 h-4 bg-blue-600 rounded-full border-2 border-white shadow-md -translate-x-1/2 -translate-y-1/2"></div></div>`,
              iconSize: [0, 0],
            });
            userMarkerRef.current = L.marker(latLng, { icon: userIcon }).addTo(mapRef.current);
          } else {
            userMarkerRef.current.setLatLng(latLng);
          }
          mapRef.current.flyTo(latLng, 14, { duration: 2 });
        }
      },
      () => setIsLocating(false)
    );
  };

  return (
    <div className={`relative w-full h-full flex flex-col bg-slate-100 overflow-hidden ${isAddingMode ? 'cursor-crosshair' : ''}`}>
      <div ref={containerRef} className="w-full h-full" />

      {/* BOTÃO LOCALIZAÇÃO (Otimizado para mobile) */}
      <button
        onClick={handleLocateMe}
        disabled={isLocating}
        className={`
          absolute z-[1000] bottom-10 right-4 sm:bottom-auto sm:top-[124px] sm:right-4
          bg-white/95 backdrop-blur-md p-4 rounded-2xl shadow-2xl border border-white
          text-slate-700 hover:text-blue-600 active:scale-90 transition-all
          ${isLocating ? 'opacity-50' : 'opacity-100'}
        `}
      >
        <Navigation size={24} className={isLocating ? 'animate-pulse' : ''} fill={userMarkerRef.current ? '#2563eb' : 'none'} />
      </button>

      {/* Rosa dos ventos (Desktop) */}
      <div className={`hidden sm:block absolute z-[1000] pointer-events-none transition-all duration-500 bottom-12 left-8 ${mapStyle === 'satellite' ? 'opacity-80 invert grayscale brightness-200' : 'opacity-10'}`}>
         <div className="relative w-14 h-14 flex items-center justify-center border-2 border-slate-900 rounded-full">
            <div className="absolute w-px h-[60%] bg-slate-900/30"></div>
            <div className="absolute h-px w-[60%] bg-slate-900/30"></div>
            <div className="absolute w-0 h-0 border-l-[4px] border-l-transparent border-r-[4px] border-r-transparent border-b-[16px] border-b-emerald-600 top-0 -translate-y-1/2"></div>
            <span className="absolute -top-5 text-[9px] font-black text-slate-800">N</span>
         </div>
      </div>
    </div>
  );
};

export default RealMap;

