import React, { useState, useEffect, useRef } from 'react';
import RealMap from './components/RealMap';
import { SP_MAP_DATA } from './constants';
import { Landmark, CustomMarker } from './types';
import { getGroundedLocationInfo } from './services/geminiService';
import { 
  Compass, 
  Sparkles, 
  ChevronRight, 
  ChevronLeft, 
  ExternalLink, 
  MapPin, 
  X, 
  Layers, 
  Loader2, 
  Plus, 
  Save, 
  Trash2,
  Map as MapIcon,
  Info
} from 'lucide-react';

export type MapStyle = 'standard' | 'satellite';

const COLORS = [
  { name: 'Esmeralda', hex: '#10b981' },
  { name: 'Rubi', hex: '#ef4444' },
  { name: 'Safira', hex: '#3b82f6' },
  { name: 'Ouro', hex: '#f59e0b' },
  { name: 'Ametista', hex: '#8b5cf6' },
  { name: 'Ônix', hex: '#1f2937' },
  { name: 'Céu', hex: '#06b6d4' }
];

const App: React.FC = () => {
  const [selectedLandmark, setSelectedLandmark] = useState<Landmark | CustomMarker | null>(null);
  const [groundedInfo, setGroundedInfo] = useState<{ text: string, links: {uri: string, title: string}[] }>({ text: '', links: [] });
  const [loading, setLoading] = useState<boolean>(false);
  const [isSidebarOpen, setIsSidebarOpen] = useState<boolean>(window.innerWidth >= 1024);
  const [mapStyle, setMapStyle] = useState<MapStyle>('standard');

  const [customMarkers, setCustomMarkers] = useState<CustomMarker[]>(() => {
    const saved = localStorage.getItem('sp_custom_markers');
    return saved ? JSON.parse(saved) : [];
  });

  const [isAddingMode, setIsAddingMode] = useState(false);
  const [pendingCoords, setPendingCoords] = useState<{lat: number, lng: number} | null>(null);
  const [newMarkerForm, setNewMarkerForm] = useState({ title: '', description: '', color: COLORS[0].hex });

  useEffect(() => {
    localStorage.setItem('sp_custom_markers', JSON.stringify(customMarkers));
  }, [customMarkers]);

  useEffect(() => {
    const handleResize = () => {
      if (window.innerWidth >= 1024) setIsSidebarOpen(true);
    };
    window.addEventListener('resize', handleResize);
    return () => window.removeEventListener('resize', handleResize);
  }, []);

  const handleLandmarkClick = async (id: string) => {
    const landmark = SP_MAP_DATA.landmarks.find(l => l.id === id);
    if (landmark) {
      setSelectedLandmark(landmark);
      setLoading(true);
      const info = await getGroundedLocationInfo(landmark.name);
      setGroundedInfo(info);
      setLoading(false);
      if (window.innerWidth < 1024) setIsSidebarOpen(false);
    }
  };

  const handleCustomLandmarkClick = (marker: CustomMarker) => {
    setSelectedLandmark(marker);
    setGroundedInfo({ text: marker.description, links: [] });
    setLoading(false);
    if (window.innerWidth < 1024) setIsSidebarOpen(false);
  };

  const handleMapClick = (latlng: any) => {
    if (isAddingMode) {
      setPendingCoords({ lat: latlng.lat, lng: latlng.lng });
      if (window.innerWidth < 1024) setIsSidebarOpen(true);
    } else {
      if (selectedLandmark) setSelectedLandmark(null);
    }
  };

  const saveCustomMarker = () => {
    if (!pendingCoords || !newMarkerForm.title) return;

    const newMarker: CustomMarker = {
      id: `custom-${Date.now()}`,
      name: newMarkerForm.title,
      type: 'custom',
      coordinates: pendingCoords,
      description: newMarkerForm.description,
      color: newMarkerForm.color
    };

    setCustomMarkers([...customMarkers, newMarker]);
    setPendingCoords(null);
    setIsAddingMode(false);
    setNewMarkerForm({ title: '', description: '', color: COLORS[0].hex });
    setSelectedLandmark(newMarker);
    setGroundedInfo({ text: newMarker.description, links: [] });
  };

  const deleteCustomMarker = (id: string) => {
    setCustomMarkers(customMarkers.filter(m => m.id !== id));
    if (selectedLandmark?.id === id) setSelectedLandmark(null);
  };

  const toggleMapStyle = () => setMapStyle(prev => prev === 'standard' ? 'satellite' : 'standard');

  return (
    <div className="h-[100dvh] w-screen bg-slate-50 text-slate-900 overflow-hidden relative flex flex-col lg:flex-row font-sans">

      <aside className={`
        fixed inset-y-0 left-0 lg:relative z-[3000] lg:z-[2000]
        bg-white lg:bg-white/80 lg:backdrop-blur-xl border-r border-slate-200
        transition-all duration-500 ease-in-out
        ${isSidebarOpen ? 'w-full sm:w-[420px] translate-x-0' : 'w-0 -translate-x-full lg:translate-x-0 overflow-hidden'}
      `}>
        <div className="flex flex-col h-full">
          <div className="p-6 sm:p-8 flex justify-between items-center border-b border-slate-100">
            <div className="flex items-center gap-3">
              <div className="w-10 h-10 bg-emerald-600 rounded-xl flex items-center justify-center text-white shadow-lg shadow-emerald-600/20">
                <MapIcon size={20} />
              </div>
              <h1 className="font-display text-2xl font-black text-slate-800 tracking-tight">Sampa Map</h1>
            </div>
            <button 
              onClick={() => setIsSidebarOpen(false)} 
              className="p-2.5 hover:bg-slate-100 rounded-2xl text-slate-400 transition-colors"
            >
              <ChevronLeft size={24} />
            </button>
          </div>

          <div className="flex-1 overflow-y-auto p-6 sm:p-8 space-y-10 custom-scrollbar">

            <section className={`
              rounded-[32px] transition-all duration-300
              ${isAddingMode ? 'bg-emerald-50 border-2 border-emerald-200 p-6' : 'bg-slate-50 p-2'}
            `}>
              {!isAddingMode ? (
                <button 
                  onClick={() => setIsAddingMode(true)}
                  className="w-full flex items-center justify-center gap-3 py-4.5 bg-slate-900 text-white rounded-[24px] font-bold hover:bg-emerald-600 transition-all shadow-xl shadow-slate-900/10 active:scale-95"
                >
                  <Plus size={20} /> Novo Marcador
                </button>
              ) : (
                <div className="space-y-5">
                  <div className="flex justify-between items-center">
                    <span className="text-[10px] font-black text-emerald-600 uppercase tracking-widest">Adicionar Local</span>
                    <button onClick={() => {setIsAddingMode(false); setPendingCoords(null);}} className="text-slate-400 hover:text-slate-600 p-1"><X size={20} /></button>
                  </div>

                  {!pendingCoords ? (
                    <div className="text-center py-8 px-4 bg-white/60 rounded-2xl border border-emerald-100">
                      <div className="w-12 h-12 bg-emerald-100 text-emerald-600 rounded-full flex items-center justify-center mx-auto mb-4 animate-bounce">
                        <MapPin size={24} />
                      </div>
                      <p className="text-sm text-emerald-900 font-bold mb-1">Toque no Mapa</p>
                      <p className="text-xs text-emerald-600 font-medium leading-relaxed">Escolha o local exato para fixar seu novo marcador.</p>
                    </div>
                  ) : (
                    <div className="space-y-4 animate-in fade-in slide-in-from-top-2">
                      <input 
                        type="text" 
                        placeholder="Nome do lugar..." 
                        className="w-full p-4 rounded-2xl border-none ring-1 ring-slate-200 text-sm font-medium focus:ring-2 focus:ring-emerald-500 outline-none transition-shadow"
                        value={newMarkerForm.title}
                        onChange={e => setNewMarkerForm({...newMarkerForm, title: e.target.value})}
                      />
                      <textarea 
                        placeholder="Adicione uma breve descrição..." 
                        rows={3}
                        className="w-full p-4 rounded-2xl border-none ring-1 ring-slate-200 text-sm font-medium focus:ring-2 focus:ring-emerald-500 outline-none resize-none transition-shadow"
                        value={newMarkerForm.description}
                        onChange={e => setNewMarkerForm({...newMarkerForm, description: e.target.value})}
                      />
                      <div className="space-y-2">
                        <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest px-1">Cor do Ícone</p>
                        <div className="flex flex-wrap gap-2.5">
                          {COLORS.map(c => (
                            <button 
                              key={c.hex}
                              onClick={() => setNewMarkerForm({...newMarkerForm, color: c.hex})}
                              className={`w-9 h-9 rounded-full border-4 transition-all ${newMarkerForm.color === c.hex ? 'border-emerald-500 scale-110 shadow-lg' : 'border-white hover:scale-105'}`}
                              style={{ backgroundColor: c.hex }}
                            />
                          ))}
                        </div>
                      </div>
                      <div className="flex flex-col gap-2 pt-2">
                        <button 
                          onClick={saveCustomMarker}
                          disabled={!newMarkerForm.title}
                          className="w-full py-4.5 bg-emerald-600 text-white rounded-[24px] font-bold disabled:opacity-50 active:scale-95 transition-all shadow-lg shadow-emerald-600/20"
                        >
                          Salvar Localização
                        </button>
                        <button 
                          onClick={() => setPendingCoords(null)}
                          className="w-full py-3 text-xs font-bold text-slate-400 hover:text-slate-600"
                        >
                          Alterar ponto no mapa
                        </button>
                      </div>
                    </div>
                  )}
                </div>
              )}
            </section>

            <div className="space-y-8">
              {customMarkers.length > 0 && (
                <section>
                  <h2 className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] mb-4 flex items-center gap-2">
                    <Sparkles size={14} className="text-blue-500" /> Lugares Salvos ({customMarkers.length})
                  </h2>
                  <div className="space-y-2">
                    {customMarkers.map((marker) => (
                      <div 
                        key={marker.id}
                        className={`group flex items-center justify-between p-4 rounded-2xl transition-all border-2 ${selectedLandmark?.id === marker.id ? 'bg-slate-900 border-slate-900 text-white shadow-xl' : 'bg-white border-slate-100 hover:border-slate-200 text-slate-600'}`}
                      >
                        <button
                          onClick={() => handleCustomLandmarkClick(marker)}
                          className="flex-1 flex items-center gap-4 text-left overflow-hidden"
                        >
                          <div className="w-3.5 h-3.5 rounded-full flex-shrink-0 shadow-inner" style={{ backgroundColor: marker.color }} />
                          <span className="font-bold text-sm truncate">{marker.name}</span>
                        </button>
                        <button 
                          onClick={() => deleteCustomMarker(marker.id)}
                          className={`p-2 rounded-xl transition-colors ${selectedLandmark?.id === marker.id ? 'text-slate-400 hover:text-red-400' : 'text-slate-300 hover:text-red-500 hover:bg-red-50'}`}
                        >
                          <Trash2 size={16} />
                        </button>
                      </div>
                    ))}
                  </div>
                </section>
              )}

              <section>
                <h2 className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] mb-4 flex items-center gap-2">
                  <Compass size={14} className="text-emerald-500" /> Marcos de São Paulo
                </h2>
                <div className="grid grid-cols-1 gap-2">
                  {SP_MAP_DATA.landmarks.map((landmark) => (
                    <button
                      key={landmark.id}
                      onClick={() => handleLandmarkClick(landmark.id)}
                      className={`flex items-center justify-between p-4 rounded-2xl transition-all border-2 ${selectedLandmark?.id === landmark.id ? 'bg-slate-900 border-slate-900 text-white shadow-xl' : 'bg-white border-slate-100 hover:border-slate-200 text-slate-600 shadow-sm'}`}
                    >
                      <div className="flex items-center gap-4">
                        <MapPin size={18} className={selectedLandmark?.id === landmark.id ? 'text-emerald-400' : 'text-slate-300'} />
                        <span className="font-bold text-sm truncate">{landmark.name}</span>
                      </div>
                      <ChevronRight size={16} opacity={0.5} />
                    </button>
                  ))}
                </div>
              </section>
            </div>
          </div>

          <div className="p-8 bg-slate-50/50">
            <button onClick={() => window.print()} className="w-full py-4.5 bg-white text-slate-800 border border-slate-200 rounded-[24px] font-bold hover:bg-slate-900 hover:text-white transition-all shadow-sm active:scale-95">Imprimir Mapa</button>
          </div>
        </div>
      </aside>

      {isSidebarOpen && window.innerWidth < 1024 && (
        <div 
          className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm z-[2500] transition-opacity"
          onClick={() => setIsSidebarOpen(false)}
        />
      )}

      <main className="flex-1 relative bg-slate-100 no-print">
        <RealMap 
          onLandmarkClick={handleLandmarkClick}
          onCustomLandmarkClick={handleCustomLandmarkClick}
          mapStyle={mapStyle}
          customMarkers={customMarkers}
          isAddingMode={isAddingMode}
          onMapClick={handleMapClick}
          pendingCoords={pendingCoords}
          selectedLandmark={selectedLandmark}
        />

        <div className="absolute top-4 right-4 z-[1000] flex flex-col gap-3">
          <button 
            onClick={() => setIsSidebarOpen(true)}
            className="lg:hidden bg-white/95 backdrop-blur-md p-3.5 rounded-2xl shadow-xl border border-white text-slate-800 active:scale-90 transition-all flex items-center justify-center"
          >
            <Compass size={24} />
          </button>

          <button 
            onClick={toggleMapStyle}
            className="bg-white/95 backdrop-blur-md p-3.5 rounded-2xl shadow-xl border border-white text-slate-800 active:scale-90 transition-all flex items-center justify-center"
          >
            <Layers size={24} className={mapStyle === 'satellite' ? 'text-emerald-600' : 'text-slate-600'} />
          </button>
        </div>

        {isAddingMode && (
          <div className="absolute top-6 left-1/2 -translate-x-1/2 z-[2000] w-[90%] sm:w-auto">
            <div className="bg-emerald-600 text-white px-6 py-3.5 rounded-full font-bold shadow-2xl border-2 border-white/20 flex items-center gap-3 animate-sheet">
              <div className="w-2 h-2 bg-white rounded-full animate-ping" />
              <span className="text-sm whitespace-nowrap">
                {pendingCoords ? "Local selecionado!" : "Toque para fixar o ponto"}
              </span>
              <button 
                onClick={() => {setIsAddingMode(false); setPendingCoords(null);}}
                className="ml-2 p-1 hover:bg-white/20 rounded-full"
              >
                <X size={18} />
              </button>
            </div>
          </div>
        )}

        {selectedLandmark && (
          <div className="lg:hidden fixed inset-x-0 bottom-0 z-[4000] px-4 pb-8 pointer-events-none">
            <div className="bg-white rounded-[40px] shadow-[0_-20px_60px_-15px_rgba(0,0,0,0.2)] pointer-events-auto animate-sheet overflow-hidden max-h-[80vh] flex flex-col">
              <div className="w-full py-4 flex flex-col items-center">
                <div className="w-10 h-1.5 bg-slate-100 rounded-full mb-2" />
              </div>

              <div className="px-8 pb-10 overflow-y-auto custom-scrollbar">
                <div className="flex justify-between items-start mb-6">
                  <div className="flex items-center gap-4">
                    <div className={`p-4 rounded-[22px] text-white shadow-lg ${selectedLandmark.type === 'custom' ? '' : 'bg-emerald-600'}`} style={{ backgroundColor: selectedLandmark.type === 'custom' ? (selectedLandmark as CustomMarker).color : undefined }}>
                      {selectedLandmark.type === 'custom' ? <Sparkles size={24} /> : <MapPin size={24} />}
                    </div>
                    <div>
                      <h2 className="text-2xl font-black text-slate-900 tracking-tight leading-tight">{selectedLandmark.name}</h2>
                      <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mt-1.5">
                        {selectedLandmark.type === 'custom' ? 'Marcador Pessoal' : 'Marco da Cidade'}
                      </p>
                    </div>
                  </div>
                  <button onClick={() => setSelectedLandmark(null)} className="bg-slate-50 p-2.5 rounded-full text-slate-400 active:scale-90"><X size={20} /></button>
                </div>

                <div className="space-y-6">
                  {loading ? (
                    <div className="flex flex-col items-center py-12 bg-slate-50 rounded-[32px] gap-4">
                      <div className="relative">
                        <div className="absolute inset-0 bg-emerald-500/20 blur-xl rounded-full animate-pulse" />
                        <Loader2 className="animate-spin text-emerald-600 relative" size={40} />
                      </div>
                      <span className="text-xs font-bold text-slate-400 uppercase tracking-widest">IA Consultando...</span>
                    </div>
                  ) : (
                    <div className="bg-slate-50 p-6 rounded-[32px] border border-slate-100">
                      <div className="flex items-center gap-2 mb-4 text-emerald-600 font-black text-[9px] uppercase tracking-[0.2em]">
                        <Info size={12} /> Sobre este local
                      </div>
                      <p className="text-slate-700 text-base leading-relaxed font-medium">
                        {selectedLandmark.type === 'custom' ? selectedLandmark.description : groundedInfo.text}
                      </p>

                      {selectedLandmark.type !== 'custom' && groundedInfo.links.length > 0 && (
                        <div className="mt-8 space-y-3">
                          <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest px-1">Links Úteis</p>
                          {groundedInfo.links.map((link, i) => (
                            <a 
                              key={i} 
                              href={link.uri} 
                              target="_blank" 
                              rel="noopener noreferrer" 
                              className="flex items-center justify-between p-5 bg-white rounded-2xl border border-slate-100 shadow-sm active:scale-[0.98] transition-all"
                            >
                              <div className="flex items-center gap-3 overflow-hidden">
                                <div className="w-8 h-8 bg-blue-50 text-blue-500 rounded-lg flex items-center justify-center flex-shrink-0">
                                  <MapIcon size={16} />
                                </div>
                                <span className="text-sm font-bold text-slate-800 truncate">{link.title}</span>
                              </div>
                              <ExternalLink size={16} className="text-slate-300" />
                            </a>
                          ))}
                        </div>
                      )}
                    </div>
                  )}

                  {selectedLandmark.type === 'custom' && (
                    <button 
                      onClick={() => deleteCustomMarker(selectedLandmark.id)}
                      className="flex items-center justify-center gap-3 w-full py-5 text-red-500 font-bold border-2 border-red-500/10 rounded-[24px] hover:bg-red-50 transition-colors active:scale-95"
                    >
                      <Trash2 size={20} /> Remover este lugar
                    </button>
                  )}
                </div>
              </div>
            </div>
          </div>
        )}
      </main>

      <div className="hidden print:block fixed inset-0 bg-white z-[9999] p-12">
        <div className="flex justify-between items-end mb-8 border-b-4 border-slate-900 pb-6">
          <div>
            <h1 className="text-6xl font-display text-slate-900 font-black">São Paulo</h1>
            <p className="text-xl font-bold text-slate-500 uppercase tracking-[0.3em] mt-2">Guia Turístico & Pessoal</p>
          </div>
          <div className="text-right">
            <p className="text-sm font-black text-slate-400">PONTOS DE INTERESSE SALVOS</p>
          </div>
        </div>
        <div className="h-[800px] border-4 border-slate-100 rounded-[40px] overflow-hidden">
          <RealMap 
            onLandmarkClick={()=>{}}
            onCustomLandmarkClick={()=>{}}
            mapStyle={mapStyle}
            customMarkers={customMarkers}
            isAddingMode={false}
            onMapClick={()=>{}}
            pendingCoords={null}
            selectedLandmark={null}
          />
        </div>
      </div>
    </div>
  );
};

export default App;

export interface Neighborhood {
  id: string;
  name: string;
  description?: string;
}

export interface Landmark {
  id: string;
  name: string;
  type: 'monument' | 'park' | 'street' | 'river' | 'custom';
  coordinates: { lat: number; lng: number; x?: number; y?: number };
  description: string;
  color?: string;
  symbol?: string; // Novo campo para o ícone
}

export interface CustomMarker extends Landmark {
  color: string;
  symbol: string;
}

export interface MapData {
  landmarks: Landmark[];
  neighborhoods: Neighborhood[];
}

import React, { useState, useEffect } from 'react';
import RealMap from './components/RealMap';
import { SP_MAP_DATA } from './constants';
import { Landmark, CustomMarker } from './types';
import { getGroundedLocationInfo } from './services/geminiService';
import { 
  Compass, 
  Sparkles, 
  ChevronRight, 
  ChevronLeft, 
  ExternalLink, 
  MapPin, 
  X, 
  Layers, 
  Loader2, 
  Plus, 
  Save, 
  Trash2,
  Map as MapIcon,
  Info,
  Coffee,
  Utensils,
  Camera,
  Music,
  Heart,
  ShoppingBag,
  Star,
  Bike,
  Navigation
} from 'lucide-react';

export type MapStyle = 'standard' | 'satellite';

const COLORS = [
  { name: 'Esmeralda', hex: '#10b981' },
  { name: 'Rubi', hex: '#ef4444' },
  { name: 'Safira', hex: '#3b82f6' },
  { name: 'Ouro', hex: '#f59e0b' },
  { name: 'Ametista', hex: '#8b5cf6' },
  { name: 'Ônix', hex: '#1f2937' },
  { name: 'Céu', hex: '#06b6d4' }
];

const SYMBOLS = [
  { id: 'map-pin', Icon: MapPin },
  { id: 'coffee', Icon: Coffee },
  { id: 'utensils', Icon: Utensils },
  { id: 'camera', Icon: Camera },
  { id: 'music', Icon: Music },
  { id: 'heart', Icon: Heart },
  { id: 'shopping-bag', Icon: ShoppingBag },
  { id: 'star', Icon: Star },
  { id: 'bike', Icon: Bike }
];

// Helper para renderizar o ícone baseado no ID
export const getSymbolIcon = (id: string, size = 20, color = "currentColor") => {
  const symbol = SYMBOLS.find(s => s.id === id) || SYMBOLS[0];
  return <symbol.Icon size={size} color={color} />;
};

const App: React.FC = () => {
  const [selectedLandmark, setSelectedLandmark] = useState<Landmark | CustomMarker | null>(null);
  const [groundedInfo, setGroundedInfo] = useState<{ text: string, links: {uri: string, title: string}[] }>({ text: '', links: [] });
  const [loading, setLoading] = useState<boolean>(false);
  const [isSidebarOpen, setIsSidebarOpen] = useState<boolean>(window.innerWidth >= 1024);
  const [mapStyle, setMapStyle] = useState<MapStyle>('standard');

  const [customMarkers, setCustomMarkers] = useState<CustomMarker[]>(() => {
    const saved = localStorage.getItem('sp_custom_markers');
    return saved ? JSON.parse(saved) : [];
  });

  const [isAddingMode, setIsAddingMode] = useState(false);
  const [pendingCoords, setPendingCoords] = useState<{lat: number, lng: number} | null>(null);
  const [newMarkerForm, setNewMarkerForm] = useState({ 
    title: '', 
    description: '', 
    color: COLORS[0].hex,
    symbol: SYMBOLS[0].id 
  });

  useEffect(() => {
    localStorage.setItem('sp_custom_markers', JSON.stringify(customMarkers));
  }, [customMarkers]);

  useEffect(() => {
    const handleResize = () => {
      if (window.innerWidth >= 1024) setIsSidebarOpen(true);
    };
    window.addEventListener('resize', handleResize);
    return () => window.removeEventListener('resize', handleResize);
  }, []);

  const handleLandmarkClick = async (id: string) => {
    const landmark = SP_MAP_DATA.landmarks.find(l => l.id === id);
    if (landmark) {
      setSelectedLandmark(landmark);
      setLoading(true);
      const info = await getGroundedLocationInfo(landmark.name);
      setGroundedInfo(info);
      setLoading(false);
      if (window.innerWidth < 1024) setIsSidebarOpen(false);
    }
  };

  const handleCustomLandmarkClick = (marker: CustomMarker) => {
    setSelectedLandmark(marker);
    setGroundedInfo({ text: marker.description, links: [] });
    setLoading(false);
    if (window.innerWidth < 1024) setIsSidebarOpen(false);
  };

  const handleMapClick = (latlng: any) => {
    if (isAddingMode) {
      setPendingCoords({ lat: latlng.lat, lng: latlng.lng });
      if (window.innerWidth < 1024) setIsSidebarOpen(true);
    } else {
      if (selectedLandmark) setSelectedLandmark(null);
    }
  };

  const saveCustomMarker = () => {
    if (!pendingCoords || !newMarkerForm.title) return;

    const newMarker: CustomMarker = {
      id: `custom-${Date.now()}`,
      name: newMarkerForm.title,
      type: 'custom',
      coordinates: pendingCoords,
      description: newMarkerForm.description,
      color: newMarkerForm.color,
      symbol: newMarkerForm.symbol
    };

    setCustomMarkers([...customMarkers, newMarker]);
    setPendingCoords(null);
    setIsAddingMode(false);
    setNewMarkerForm({ 
      title: '', 
      description: '', 
      color: COLORS[0].hex, 
      symbol: SYMBOLS[0].id 
    });
    setSelectedLandmark(newMarker);
    setGroundedInfo({ text: newMarker.description, links: [] });
  };

  const deleteCustomMarker = (id: string) => {
    setCustomMarkers(customMarkers.filter(m => m.id !== id));
    if (selectedLandmark?.id === id) setSelectedLandmark(null);
  };

  const toggleMapStyle = () => setMapStyle(prev => prev === 'standard' ? 'satellite' : 'standard');

  return (
    <div className="h-[100dvh] w-screen bg-slate-50 text-slate-900 overflow-hidden relative flex flex-col lg:flex-row font-sans">

      <aside className={`
        fixed inset-y-0 left-0 lg:relative z-[3000] lg:z-[2000]
        bg-white lg:bg-white/80 lg:backdrop-blur-xl border-r border-slate-200
        transition-all duration-500 ease-in-out
        ${isSidebarOpen ? 'w-full sm:w-[420px] translate-x-0' : 'w-0 -translate-x-full lg:translate-x-0 overflow-hidden'}
      `}>
        <div className="flex flex-col h-full">
          <div className="p-6 sm:p-8 flex justify-between items-center border-b border-slate-100">
            <div className="flex items-center gap-3">
              <div className="w-10 h-10 bg-emerald-600 rounded-xl flex items-center justify-center text-white shadow-lg shadow-emerald-600/20">
                <MapIcon size={20} />
              </div>
              <h1 className="font-display text-2xl font-black text-slate-800 tracking-tight">Sampa Map</h1>
            </div>
            <button 
              onClick={() => setIsSidebarOpen(false)} 
              className="p-2.5 hover:bg-slate-100 rounded-2xl text-slate-400 transition-colors"
            >
              <ChevronLeft size={24} />
            </button>
          </div>

          <div className="flex-1 overflow-y-auto p-6 sm:p-8 space-y-10 custom-scrollbar">

            <section className={`
              rounded-[32px] transition-all duration-300
              ${isAddingMode ? 'bg-emerald-50 border-2 border-emerald-200 p-6' : 'bg-slate-50 p-2'}
            `}>
              {!isAddingMode ? (
                <button 
                  onClick={() => setIsAddingMode(true)}
                  className="w-full flex items-center justify-center gap-3 py-4.5 bg-slate-900 text-white rounded-[24px] font-bold hover:bg-emerald-600 transition-all shadow-xl shadow-slate-900/10 active:scale-95"
                >
                  <Plus size={20} /> Novo Marcador
                </button>
              ) : (
                <div className="space-y-5">
                  <div className="flex justify-between items-center">
                    <span className="text-[10px] font-black text-emerald-600 uppercase tracking-widest">Adicionar Local</span>
                    <button onClick={() => {setIsAddingMode(false); setPendingCoords(null);}} className="text-slate-400 hover:text-slate-600 p-1"><X size={20} /></button>
                  </div>

                  {!pendingCoords ? (
                    <div className="text-center py-8 px-4 bg-white/60 rounded-2xl border border-emerald-100">
                      <div className="w-12 h-12 bg-emerald-100 text-emerald-600 rounded-full flex items-center justify-center mx-auto mb-4 animate-bounce">
                        <MapPin size={24} />
                      </div>
                      <p className="text-sm text-emerald-900 font-bold mb-1">Toque no Mapa</p>
                      <p className="text-xs text-emerald-600 font-medium leading-relaxed">Escolha o local exato para fixar seu novo marcador.</p>
