                    >
                      <div className="flex items-center gap-4">
                        <MapPin size={18} className={selectedLandmark?.id === landmark.id ? 'text-emerald-400' : 'text-slate-300'} />
                        <span className="font-bold text-sm truncate">{landmark.name}</span>
