            </div>
          </div>

          <div className="p-8 bg-slate-50/50">
            <button onClick={() => window.print()} className="w-full py-4.5 bg-white text-slate-800 border border-slate-200 rounded-[24px] font-bold hover:bg-slate-900 hover:text-white transition-all shadow-sm active:scale-95">Imprimir Mapa</button>
          </div>
