  'utensils': '<path d="M3 2v7c0 1.1.9 2 2 2h4a2 2 0 0 0 2-2V2"></path><path d="M7 2v20"></path><path d="M21 15V2v0a5 5 0 0 0-5 5v6c0 1.1.9 2 2 2h3Zm0 0v7"></path>',
  'camera': '<rect x="3" y="4" width="18" height="12" rx="2" ry="2"></rect><path d="M17 4l-1.41-2.12A2 2 0 0 0 13.83 1H10.17a2 2 0 0 0-1.76.88L7 4"></path><circle cx="12" cy="10" r="3"></circle>',
  'music': '<path d="M9 18V5l12-2v13"></path><circle cx="6" cy="18" r="3"></circle><circle cx="18" cy="16" r="3"></circle>',
  'school': '<path d="M22 10v6M2 10l10-5 10 5-10 5z"></path><path d="M6 12v5c3 3 9 3 12 0v-5"></path>',
  'heart': '<path d="M20.84 4.61a5.5 5.5 0 0 0-7.78 0L12 5.67l-1.06-1.06a5.5 5.5 0 0 0-7.78 7.78l1.06 1.06L12 21.23l7.78-7.78 1.06-1.06a5.5 5.5 0 0 0 0-7.78z"></path>',
  'shopping-bag': '<path d="M6 2L3 6v14a2 2 0 0 0 2 2h14a2 2 0 0 0 2-2V6l-3-4Z"></path><line x1="3" y1="6" x2="21" y2="6"></line><path d="M16 10a4 4 0 0 1-8 0"></path>',
  'star': '<polygon points="12 2 15.09 8.26 22 9.27 17 14.14 18.18 21.02 12 17.77 5.82 21.02 7 14.14 2 9.27 8.91 8.26 12 2"></polygon>',
  'bike': '<circle cx="5.5" cy="17.5" r="3.5"></circle><circle cx="18.5" cy="17.5" r="3.5"></circle><path d="M15 6a1 1 0 1 0 0-2 1 1 0 0 0 0 2zm-3 11.5V14l-3-3 4-3 2 3h2"></path>'
};

const STATE_BOUNDS = L.latLngBounds(
  [-25.5, -53.2],
  [-19.5, -44.0]
);

const SP_BOUNDARY_COORDS: [number, number][] = [
  [-23.3563, -46.6806], [-23.3644, -46.5492], [-23.3934, -46.4957],
  [-23.4111, -46.4255], [-23.4449, -46.3986], [-23.4862, -46.3655],
  [-23.5173, -46.3695], [-23.5684, -46.3888], [-23.6195, -46.4178],
  [-23.6666, -46.4382], [-23.7058, -46.4576], [-23.7554, -46.4908],
  [-23.8407, -46.5652], [-23.9103, -46.6217], [-23.9667, -46.6437],
  [-23.9761, -46.6905], [-23.9103, -46.7291], [-23.8407, -46.7388],
  [-23.7386, -46.7842], [-23.6811, -46.8311], [-23.6262, -46.8242],
  [-23.5857, -46.8214], [-23.5411, -46.8352], [-23.4977, -46.8256],
  [-23.4474, -46.7911], [-23.4042, -46.7608], [-23.3563, -46.6806]
];

const RealMap: React.FC<RealMapProps> = ({ 
  onLandmarkClick, 
  onCustomLandmarkClick,
  mapStyle, 
  customMarkers, 
  isAddingMode, 
  onMapClick,
  pendingCoords,
  selectedLandmark
}) => {
  const mapRef = useRef<L.Map | null>(null);
  const containerRef = useRef<HTMLDivElement>(null);
  const tileLayerRef = useRef<L.TileLayer | null>(null);
  const userMarkerRef = useRef<L.Marker | null>(null);
  const pendingMarkerRef = useRef<L.Marker | null>(null);
  const customMarkersLayerRef = useRef<L.LayerGroup | null>(null);
  const [isLocating, setIsLocating] = useState(false);

  const onMapClickRef = useRef(onMapClick);
  useEffect(() => {
    onMapClickRef.current = onMapClick;
  }, [onMapClick]);

  useEffect(() => {
    if (!containerRef.current || mapRef.current) return;

    const map = L.map(containerRef.current, {
      zoomControl: false,
      attributionControl: false,
      tap: true,
      bounceAtZoomLimits: true,
      wheelDebounceTime: 150,
      maxBounds: STATE_BOUNDS,
      maxBoundsViscosity: 1.0, 
      minZoom: 8,
      worldCopyJump: false,
    }).setView([-23.5505, -46.6333], 11);

    mapRef.current = map;
    customMarkersLayerRef.current = L.layerGroup().addTo(map);

    tileLayerRef.current = L.tileLayer(TILE_LAYERS[mapStyle], {
      maxZoom: 19,
      bounds: STATE_BOUNDS,
      noWrap: true,
      crossOrigin: true
    }).addTo(map);

    L.polyline(SP_BOUNDARY_COORDS, {
      color: '#ef4444',
      weight: 3,
      opacity: 0.6,
      dashArray: '10, 15',
      lineJoin: 'round',
      interactive: false
    }).addTo(map);

    SP_MAP_DATA.landmarks.forEach(landmark => {
      const icon = L.divIcon({
        className: 'custom-marker',
        html: `<div class="marker-container">
                <div class="bg-emerald-600 w-10 h-10 rounded-[14px] border-2 border-white shadow-lg flex items-center justify-center text-white">
                  <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="3" stroke-linecap="round" stroke-linejoin="round">${SYMBOL_PATHS['map-pin']}</svg>
                </div>
              </div>`,
        iconSize: [40, 40],
        iconAnchor: [20, 40],
      });

      L.marker([landmark.coordinates.lat, landmark.coordinates.lng], { icon })
        .addTo(map)
        .on('click', (e) => {
          L.DomEvent.stopPropagation(e);
          onLandmarkClick(landmark.id);
        });
    });

    map.on('click', (e) => {
      onMapClickRef.current(e.latlng);
    });

    const resizeObserver = new ResizeObserver(() => {
      if (mapRef.current) mapRef.current.invalidateSize();
    });
    resizeObserver.observe(containerRef.current);

    return () => {
      resizeObserver.disconnect();
      if (mapRef.current) mapRef.current.remove();
      mapRef.current = null;
    };
  }, []);

  useEffect(() => {
    if (mapRef.current && selectedLandmark) {
      const { lat, lng } = selectedLandmark.coordinates;
      mapRef.current.flyTo([lat, lng], 15, {
        duration: 1.5,
        easeLinearity: 0.25
      });
    }
  }, [selectedLandmark]);

  useEffect(() => {
    if (!mapRef.current || !customMarkersLayerRef.current) return;
    customMarkersLayerRef.current.clearLayers();

    customMarkers.forEach(marker => {
      const iconPath = SYMBOL_PATHS[marker.symbol] || SYMBOL_PATHS['map-pin'];
      const icon = L.divIcon({
        className: 'user-custom-marker',
        html: `<div class="marker-container">
                <div style="background-color: ${marker.color}" class="w-10 h-10 rounded-[14px] border-2 border-white shadow-lg flex items-center justify-center text-white">
                  <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="3" stroke-linecap="round" stroke-linejoin="round">${iconPath}</svg>
                </div>
              </div>`,
        iconSize: [40, 40],
        iconAnchor: [20, 40],
      });

      L.marker([marker.coordinates.lat, marker.coordinates.lng], { icon })
        .addTo(customMarkersLayerRef.current!)
        .on('click', (e) => {
          L.DomEvent.stopPropagation(e);
          onCustomLandmarkClick(marker);
        });
    });
  }, [customMarkers]);

  useEffect(() => {
    if (!mapRef.current) return;
    if (pendingCoords) {
      if (pendingMarkerRef.current) {
        pendingMarkerRef.current.setLatLng([pendingCoords.lat, pendingCoords.lng]);
      } else {
        const ghostIcon = L.divIcon({
          className: 'pending-marker',
          html: `<div class="animate-bounce">
                  <div class="bg-slate-900 w-12 h-12 rounded-[18px] border-4 border-white shadow-2xl flex items-center justify-center text-emerald-400">
                    <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="4"><path d="M12 5v14M5 12h14"></path></svg>
                  </div>
                </div>`,
          iconSize: [48, 48],
          iconAnchor: [24, 48],
        });
        pendingMarkerRef.current = L.marker([pendingCoords.lat, pendingCoords.lng], { icon: ghostIcon }).addTo(mapRef.current);
      }
    } else if (pendingMarkerRef.current) {
      pendingMarkerRef.current.remove();
      pendingMarkerRef.current = null;
    }
  }, [pendingCoords]);

  useEffect(() => {
    if (!mapRef.current || !tileLayerRef.current) return;
    tileLayerRef.current.setUrl(TILE_LAYERS[mapStyle]);
  }, [mapStyle]);

  const handleLocateMe = () => {
    if (!navigator.geolocation) return;
    setIsLocating(true);
    navigator.geolocation.getCurrentPosition(
      (position) => {
        const { latitude, longitude } = position.coords;
        const latLng = L.latLng(latitude, longitude);
        setIsLocating(false);
        if (!STATE_BOUNDS.contains(latLng)) {
          alert("Fora de SP");
          return;
        }
        if (mapRef.current) {
          if (!userMarkerRef.current) {
            const userIcon = L.divIcon({
              className: 'user-pos',
              html: `<div class="relative"><div class="absolute inset-0 w-8 h-8 bg-blue-500/20 rounded-full animate-ping -translate-x-1/2 -translate-y-1/2"></div><div class="w-4 h-4 bg-blue-600 rounded-full border-2 border-white shadow-md -translate-x-1/2 -translate-y-1/2"></div></div>`,
              iconSize: [0, 0],
            });
            userMarkerRef.current = L.marker(latLng, { icon: userIcon }).addTo(mapRef.current);
          } else {
            userMarkerRef.current.setLatLng(latLng);
          }
          mapRef.current.flyTo(latLng, 14, { duration: 2 });
        }
      },
      () => setIsLocating(false)
    );
  };

  return (
    <div className={`relative w-full h-full flex flex-col bg-slate-100 overflow-hidden ${isAddingMode ? 'cursor-crosshair' : ''}`}>
      <div ref={containerRef} className="w-full h-full" />

      <button
        onClick={handleLocateMe}
        disabled={isLocating}
        className={`
          absolute z-[1000] bottom-10 right-4 sm:bottom-auto sm:top-[124px] sm:right-4
          bg-white/95 backdrop-blur-md p-4 rounded-2xl shadow-2xl border border-white
          text-slate-700 hover:text-blue-600 active:scale-90 transition-all
          ${isLocating ? 'opacity-50' : 'opacity-100'}
        `}
      >
        <Navigation size={24} className={isLocating ? 'animate-pulse' : ''} fill={userMarkerRef.current ? '#2563eb' : 'none'} />
      </button>

      <div className={`hidden sm:block absolute z-[1000] pointer-events-none transition-all duration-500 bottom-12 left-8 ${mapStyle === 'satellite' ? 'opacity-80 invert grayscale brightness-200' : 'opacity-10'}`}>
         <div className="relative w-14 h-14 flex items-center justify-center border-2 border-slate-900 rounded-full">
            <div className="absolute w-px h-[60%] bg-slate-900/30"></div>
            <div className="absolute h-px w-[60%] bg-slate-900/30"></div>
            <div className="absolute w-0 h-0 border-l-[4px] border-l-transparent border-r-[4px] border-r-transparent border-b-[16px] border-b-emerald-600 top-0 -translate-y-1/2"></div>
            <span className="absolute -top-5 text-[9px] font-black text-slate-800">N</span>
         </div>
      </div>
    </div>
  );
};

export default RealMap;

