    window.addEventListener('resize', handleResize);
    return () => window.removeEventListener('resize', handleResize);
  }, []);

  const handleLandmarkClick = async (id: string) => {
    const landmark = SP_MAP_DATA.landmarks.find(l => l.id === id);
    if (landmark) {
      setSelectedLandmark(landmark);
      setLoading(true);
      const info = await getGroundedLocationInfo(landmark.name);
      setGroundedInfo(info);
      setLoading(false);
      if (window.innerWidth < 1024) setIsSidebarOpen(false);
    }
  };

  const handleCustomLandmarkClick = (marker: CustomMarker) => {
    setSelectedLandmark(marker);
    setGroundedInfo({ text: marker.description, links: [] });
