        {selectedLandmark && (
          <div className="lg:hidden fixed inset-x-0 bottom-0 z-[4000] px-4 pb-8 pointer-events-none">
            <div className="bg-white rounded-[40px] shadow-[0_-20px_60px_-15px_rgba(0,0,0,0.2)] pointer-events-auto animate-sheet overflow-hidden max-h-[80vh] flex flex-col">
