                    </div>
                    <div>
                      <h2 className="text-2xl font-black text-slate-900 tracking-tight leading-tight">{selectedLandmark.name}</h2>
                      <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mt-1.5">
                        {selectedLandmark.type === 'custom' ? 'Marcador Pessoal' : 'Marco da Cidade'}
