              iconSize: [0, 0],
            });
            userMarkerRef.current = L.marker(latLng, { icon: userIcon }).addTo(mapRef.current);
          } else {
            userMarkerRef.current.setLatLng(latLng);
          }
          mapRef.current.flyTo(latLng, 14, { duration: 2 });
        }
      },
      () => setIsLocating(false)
    );
  };

  return (
    <div className={`relative w-full h-full flex flex-col bg-slate-100 overflow-hidden ${isAddingMode ? 'cursor-crosshair' : ''}`}>
      <div ref={containerRef} className="w-full h-full" />

      <button
        onClick={handleLocateMe}
        disabled={isLocating}
        className={`
          absolute z-[1000] bottom-10 right-4 sm:bottom-auto sm:top-[124px] sm:right-4
          bg-white/95 backdrop-blur-md p-4 rounded-2xl shadow-2xl border border-white
          text-slate-700 hover:text-blue-600 active:scale-90 transition-all
          ${isLocating ? 'opacity-50' : 'opacity-100'}
        `}
      >
        <Navigation size={24} className={isLocating ? 'animate-pulse' : ''} fill={userMarkerRef.current ? '#2563eb' : 'none'} />
      </button>

      <div className={`hidden sm:block absolute z-[1000] pointer-events-none transition-all duration-500 bottom-12 left-8 ${mapStyle === 'satellite' ? 'opacity-80 invert grayscale brightness-200' : 'opacity-10'}`}>
         <div className="relative w-14 h-14 flex items-center justify-center border-2 border-slate-900 rounded-full">
            <div className="absolute w-px h-[60%] bg-slate-900/30"></div>
            <div className="absolute h-px w-[60%] bg-slate-900/30"></div>
            <div className="absolute w-0 h-0 border-l-[4px] border-l-transparent border-r-[4px] border-r-transparent border-b-[16px] border-b-emerald-600 top-0 -translate-y-1/2"></div>
            <span className="absolute -top-5 text-[9px] font-black text-slate-800">N</span>
         </div>
      </div>
    </div>
  );
};

