                      <button onClick={() => deleteCustomMarker(selectedLandmark.id)} className="flex items-center justify-center gap-3 w-full py-5 text-red-500 font-bold border-2 border-red-500/10 rounded-[28px] hover:bg-red-50 transition-colors active:scale-95"><Trash2 size={20} /> Remover marcador pessoal</button>
                    )}
                  </div>
                </div>
              </div>
            </div>
          </div>
        )}
      </main>
    </div>
  );
};

