export interface TravelInfo {
  distanceKm: number;
  durationMinutes: {
    walking: number;
    car: number;
  };
}

export function calculateDistance(lat1: number, lon1: number, lat2: number, lon2: number): number {
  const R = 6371; // Rayon de la Terre en km
  const dLat = (lat2 - lat1) * Math.PI / 180;
  const dLon = (lon2 - lon1) * Math.PI / 180;
  const a = 
    Math.sin(dLat/2) * Math.sin(dLat/2) +
    Math.cos(lat1 * Math.PI / 180) * Math.cos(lat2 * Math.PI / 180) * 
    Math.sin(dLon/2) * Math.sin(dLon/2);
  const c = 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1-a));
  return R * c;
}

export function getTravelInfo(lat1: number, lon1: number, lat2: number, lon2: number): TravelInfo {
  const distance = calculateDistance(lat1, lon1, lat2, lon2);

  // Vitesse moyenne SP : Voiture 22km/h, Marche 4.5km/h
  return {
    distanceKm: parseFloat(distance.toFixed(1)),
    durationMinutes: {
      walking: Math.round((distance / 4.5) * 60),
      car: Math.round((distance / 22) * 60)
    }
  };
}

import React, { useEffect, useRef, useState } from 'react';
import { SP_MAP_DATA } from '../constants';
import L from 'leaflet';
import { MapStyle } from '../App';
import { Navigation } from 'lucide-react';
import { Landmark, CustomMarker } from '../types';

interface RealMapProps {
  onLandmarkClick: (id: string) => void;
  onCustomLandmarkClick: (marker: CustomMarker) => void;
  mapStyle: MapStyle;
  customMarkers: CustomMarker[];
  isAddingMode: boolean;
  onMapClick: (latlng: L.LatLng) => void;
  pendingCoords: { lat: number; lng: number } | null;
  selectedLandmark: Landmark | CustomMarker | null;
  onUserLocationUpdate: (coords: { lat: number, lng: number } | null) => void;
}

const TILE_LAYERS = {
  standard: 'https://{s}.basemaps.cartocdn.com/rastertiles/voyager/{z}/{x}/{y}{r}.png',
  satellite: 'https://server.arcgisonline.com/ArcGIS/rest/services/World_Imagery/MapServer/tile/{z}/{y}/{x}'
};

const SYMBOL_PATHS: Record<string, string> = {
  'map-pin': '<path d="M21 10c0 7-9 13-9 13s-9-6-9-13a9 9 0 0 1 18 0z"></path><circle cx="12" cy="10" r="3"></circle>',
