          <div className="absolute inset-0 z-[5000] bg-blue-900/10 backdrop-blur-[2px] pointer-events-none flex items-center justify-center">
            <div className="bg-white px-8 py-4 rounded-full shadow-2xl border-4 border-blue-500 animate-bounce flex items-center gap-3">
              <ArrowRightLeft size={20} className="text-blue-600" />
              <span className="font-black text-blue-900 uppercase">Sélectionnez le deuxième point</span>
            </div>
          </div>
