        {selectedLandmark && (
          <div className="fixed inset-x-0 bottom-0 lg:left-[420px] z-[4000] p-4 lg:p-10 pointer-events-none">
            <div className="bg-white rounded-[40px] shadow-2xl pointer-events-auto overflow-hidden animate-sheet max-w-4xl mx-auto border border-slate-200">
