                    <div>
                      <h2 className="text-3xl font-black text-slate-900 tracking-tight">{selectedLandmark.name}</h2>
                      <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mt-1">
                        {selectedLandmark.type === 'custom' ? 'Marqueur Personnel' : 'Monument Historique'}
                      </p>
                    </div>
                  </div>
                  <button onClick={() => {setSelectedLandmark(null); setComparisonLandmark(null); setIsComparing(false);}} className="p-3 bg-slate-50 rounded-full text-slate-400 hover:text-red-500 transition-colors"><X size={24} /></button>
                </div>

                <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
                  <div className="space-y-6">
                    <div className="bg-slate-50 p-6 rounded-[32px] border border-slate-100 space-y-4">
                      <div className="flex items-center gap-2 text-[10px] font-black uppercase text-slate-400"><Navigation size={14} /> Logistique & Distance</div>

                      {/* Distance de l'utilisateur */}
                      <div className="flex items-center justify-between p-4 bg-white rounded-2xl shadow-sm border border-slate-100">
                        <div className="flex items-center gap-3">
                          <PersonStanding className={`text-blue-500 ${!userLocation && 'opacity-30'}`} size={20} />
                          <div>
                            <p className="text-[10px] font-bold text-slate-400">De votre position</p>
                            <p className="font-black text-lg">{userLocation && travelFromUser ? `${travelFromUser.distanceKm} km` : '-- km'}</p>
                          </div>
                        </div>
                        {userLocation && travelFromUser && (
                          <div className="flex gap-3 text-[11px] font-bold">
                            <span className="flex flex-col items-center text-blue-600"><Car size={14} /> {travelFromUser.durationMinutes.car}m</span>
                            <span className="flex flex-col items-center text-emerald-600"><PersonStanding size={14} /> {travelFromUser.durationMinutes.walking}m</span>
                          </div>
                        )}
                      </div>

                      {/* Distance entre deux marqueurs */}
                      {comparisonLandmark ? (
                        <div className="p-4 bg-blue-50 rounded-2xl border border-blue-200 space-y-3">
                          <div className="flex justify-between items-center">
                            <span className="text-[10px] font-black text-blue-900 uppercase">Distance entre points</span>
                            <button onClick={() => setComparisonLandmark(null)}><X size={14} className="text-blue-400" /></button>
                          </div>
                          <div className="flex items-center justify-between">
                            <span className="text-xs font-bold text-blue-700 truncate max-w-[100px]">{selectedLandmark.name}</span>
                            <div className="flex flex-col items-center">
                              <span className="font-black text-xl text-blue-900">{travelBetweenMarkers?.distanceKm} km</span>
                              <div className="flex gap-4 text-[10px] font-black text-blue-600">
                                <span><Car size={10} className="inline" /> {travelBetweenMarkers?.durationMinutes.car} min</span>
                                <span><PersonStanding size={10} className="inline" /> {travelBetweenMarkers?.durationMinutes.walking} min</span>
                              </div>
                            </div>
                            <span className="text-xs font-bold text-blue-700 truncate max-w-[100px]">{comparisonLandmark.name}</span>
                          </div>
                        </div>
                      ) : (
                        <button onClick={() => setIsComparing(true)} className="w-full py-4 border-2 border-dashed border-blue-200 rounded-2xl text-blue-600 font-bold text-sm hover:bg-blue-50 transition-all flex items-center justify-center gap-2"><ArrowRightLeft size={18} /> Comparer avec un autre lieu</button>
                      )}
                    </div>
                  </div>

                  <div className="space-y-6">
                    {loading ? (
                      <div className="flex flex-col items-center py-10 bg-slate-50 rounded-[32px] gap-3">
                        <Loader2 className="animate-spin text-emerald-600" size={32} />
                        <span className="text-[10px] font-black uppercase text-slate-400">Recherche IA...</span>
                      </div>
                    ) : (
                      <div className="bg-slate-50 p-6 rounded-[32px] border border-slate-100">
                        <div className="flex items-center gap-2 mb-3 text-[10px] font-black uppercase text-emerald-600"><Info size={14} /> Description</div>
                        <p className="text-slate-700 text-base leading-relaxed font-medium">{selectedLandmark.type === 'custom' ? selectedLandmark.description : groundedInfo.text}</p>
                        {groundedInfo.links.length > 0 && (
                          <div className="mt-4 space-y-2">
                            {groundedInfo.links.map((link, i) => (
                              <a key={i} href={link.uri} target="_blank" className="flex items-center justify-between p-3 bg-white rounded-xl border hover:shadow-md transition-all">
                                <span className="text-xs font-bold truncate">{link.title}</span>
                                <ExternalLink size={14} className="text-blue-500" />
                              </a>
                            ))}
                          </div>
                        )}
                      </div>
                    )}
                    {selectedLandmark.type === 'custom' && (
                      <button onClick={() => { setCustomMarkers(customMarkers.filter(m => m.id !== selectedLandmark.id)); setSelectedLandmark(null); }} className="w-full py-4 text-red-500 font-bold border-2 border-red-100 rounded-2xl hover:bg-red-50 transition-all flex items-center justify-center gap-2"><Trash2 size={18} /> Supprimer le marqueur</button>
                    )}
                  </div>
                </div>
              </div>
            </div>
          </div>
        )}
      </main>
    </div>
  );
};

export default App;

import React, { useEffect, useRef, useState } from 'react';
import { SP_MAP_DATA } from '../constants';
import L from 'leaflet';
import { MapStyle } from '../App';
import { Navigation } from 'lucide-react';
import { Landmark, CustomMarker } from '../types';

interface RealMapProps {
  onLandmarkClick: (id: string) => void;
  onCustomLandmarkClick: (marker: CustomMarker) => void;
  mapStyle: MapStyle;
  customMarkers: CustomMarker[];
  isAddingMode: boolean;
  onMapClick: (latlng: L.LatLng) => void;
  pendingCoords: { lat: number; lng: number } | null;
  selectedLandmark: Landmark | CustomMarker | null;
  comparisonLandmark: Landmark | CustomMarker | null;
  onUserLocationUpdate: (coords: { lat: number, lng: number } | null) => void;
  userLocation: { lat: number, lng: number } | null;
}

const TILE_LAYERS = {
  standard: 'https://{s}.basemaps.cartocdn.com/rastertiles/voyager/{z}/{x}/{y}{r}.png',
  satellite: 'https://server.arcgisonline.com/ArcGIS/rest/services/World_Imagery/MapServer/tile/{z}/{y}/{x}'
};

const SYMBOL_PATHS: Record<string, string> = {
  'map-pin': '<path d="M21 10c0 7-9 13-9 13s-9-6-9-13a9 9 0 0 1 18 0z"></path><circle cx="12" cy="10" r="3"></circle>',
  'home': '<path d="m3 9 9-7 9 7v11a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2z"></path><polyline points="9 22 9 12 15 12 15 22"></polyline>',
  'building': '<rect x="4" y="2" width="16" height="20" rx="2" ry="2"></rect><path d="M9 22v-4h6v4"></path><path d="M8 6h8"></path><path d="M8 10h8"></path><path d="M8 14h8"></path>',
  'work': '<rect width="20" height="14" x="2" y="7" rx="2" ry="2"></rect><path d="M16 21V5a2 2 0 0 0-2-2h-4a2 2 0 0 0-2 2v16"></path>',
  'coffee': '<path d="M18 8h1a4 4 0 0 1 0 8h-1"></path><path d="M2 8h16v9a4 4 0 0 1-4 4H6a4 4 0 0 1-4-4V8z"></path><line x1="6" y1="1" x2="6" y2="4"></line><line x1="10" y1="1" x2="10" y2="4"></line><line x1="14" y1="1" x2="14" y2="4"></line>',
  'utensils': '<path d="M3 2v7c0 1.1.9 2 2 2h4a2 2 0 0 0 2-2V2"></path><path d="M7 2v20"></path><path d="M21 15V2v0a5 5 0 0 0-5 5v6c0 1.1.9 2 2 2h3Zm0 0v7"></path>',
  'camera': '<rect x="3" y="4" width="18" height="12" rx="2" ry="2"></rect><path d="M17 4l-1.41-2.12A2 2 0 0 0 13.83 1H10.17a2 2 0 0 0-1.76.88L7 4"></path><circle cx="12" cy="10" r="3"></circle>',
  'music': '<path d="M9 18V5l12-2v13"></path><circle cx="6" cy="18" r="3"></circle><circle cx="18" cy="16" r="3"></circle>',
  'school': '<path d="M22 10v6M2 10l10-5 10 5-10 5z"></path><path d="M6 12v5c3 3 9 3 12 0v-5"></path>',
  'heart': '<path d="M20.84 4.61a5.5 5.5 0 0 0-7.78 0L12 5.67l-1.06-1.06a5.5 5.5 0 0 0-7.78 7.78l1.06 1.06L12 21.23l7.78-7.78 1.06-1.06a5.5 5.5 0 0 0 0-7.78z"></path>',
  'shopping-bag': '<path d="M6 2L3 6v14a2 2 0 0 0 2 2h14a2 2 0 0 0 2-2V6l-3-4Z"></path><line x1="3" y1="6" x2="21" y2="6"></line><path d="M16 10a4 4 0 0 1-8 0"></path>',
  'star': '<polygon points="12 2 15.09 8.26 22 9.27 17 14.14 18.18 21.02 12 17.77 5.82 21.02 7 14.14 2 9.27 8.91 8.26 12 2"></polygon>',
  'bike': '<circle cx="5.5" cy="17.5" r="3.5"></circle><circle cx="18.5" cy="17.5" r="3.5"></circle><path d="M15 6a1 1 0 1 0 0-2 1 1 0 0 0 0 2zm-3 11.5V14l-3-3 4-3 2 3h2"></path>',
  'train': '<path d="M2 14h20M7 8h10M9 22H7M15 22h2M4 18h16V5a2 2 0 0 0-2-2H6a2 2 0 0 0-2 2v13Z"></path>'
};

const STATE_BOUNDS = L.latLngBounds([-25.5, -53.2], [-19.5, -44.0]);

const RealMap: React.FC<RealMapProps> = ({ 
  onLandmarkClick, 
  onCustomLandmarkClick,
  mapStyle, 
  customMarkers, 
  isAddingMode, 
  onMapClick,
  pendingCoords,
  selectedLandmark,
  comparisonLandmark,
  onUserLocationUpdate,
  userLocation
}) => {
  const mapRef = useRef<L.Map | null>(null);
  const containerRef = useRef<HTMLDivElement>(null);
  const userMarkerRef = useRef<L.Marker | null>(null);
  const pendingMarkerRef = useRef<L.Marker | null>(null);
  const customMarkersLayerRef = useRef<L.LayerGroup | null>(null);
  const routeLayerRef = useRef<L.LayerGroup | null>(null);
  const tileLayerRef = useRef<L.TileLayer | null>(null);
  const [isLocating, setIsLocating] = useState(false);

  useEffect(() => {
    if (!containerRef.current || mapRef.current) return;
    const map = L.map(containerRef.current, {
      zoomControl: false,
      attributionControl: false,
      maxBounds: STATE_BOUNDS,
      maxBoundsViscosity: 1.0, 
      minZoom: 8,
    }).setView([-23.5505, -46.6333], 11);

    mapRef.current = map;
    customMarkersLayerRef.current = L.layerGroup().addTo(map);
    routeLayerRef.current = L.layerGroup().addTo(map);
    tileLayerRef.current = L.tileLayer(TILE_LAYERS[mapStyle], { maxZoom: 19 }).addTo(map);

    SP_MAP_DATA.landmarks.forEach(landmark => {
      const iconPath = SYMBOL_PATHS[landmark.symbol || 'map-pin'] || SYMBOL_PATHS['map-pin'];
      const icon = L.divIcon({
        className: 'custom-marker',
        html: `<div class="marker-container"><div style="background-color: ${landmark.color || '#059669'}" class="w-10 h-10 rounded-xl border-2 border-white shadow-lg flex items-center justify-center text-white"><svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="3">${iconPath}</svg></div></div>`,
        iconSize: [40, 40],
        iconAnchor: [20, 40],
      });
      L.marker([landmark.coordinates.lat, landmark.coordinates.lng], { icon })
        .addTo(map)
        .on('click', (e) => { L.DomEvent.stopPropagation(e); onLandmarkClick(landmark.id); });
    });

    map.on('click', (e) => onMapClick(e.latlng));
    return () => { if (mapRef.current) mapRef.current.remove(); mapRef.current = null; };
  }, []);

  useEffect(() => {
    if (tileLayerRef.current) tileLayerRef.current.setUrl(TILE_LAYERS[mapStyle]);
  }, [mapStyle]);

  useEffect(() => {
    if (!mapRef.current || !customMarkersLayerRef.current) return;
    customMarkersLayerRef.current.clearLayers();
    customMarkers.forEach(marker => {
      const iconPath = SYMBOL_PATHS[marker.symbol] || SYMBOL_PATHS['map-pin'];
      const icon = L.divIcon({
        className: 'custom-marker',
        html: `<div class="marker-container"><div style="background-color: ${marker.color}" class="w-10 h-10 rounded-xl border-2 border-white shadow-lg flex items-center justify-center text-white"><svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="3">${iconPath}</svg></div></div>`,
        iconSize: [40, 40],
        iconAnchor: [20, 40],
      });
      L.marker([marker.coordinates.lat, marker.coordinates.lng], { icon })
        .addTo(customMarkersLayerRef.current!)
        .on('click', (e) => { L.DomEvent.stopPropagation(e); onCustomLandmarkClick(marker); });
    });
  }, [customMarkers]);

  // Dessiner les lignes d'itinéraire
  useEffect(() => {
    if (!mapRef.current || !routeLayerRef.current) return;
    routeLayerRef.current.clearLayers();

    // Ligne utilisateur vers marqueur sélectionné
    if (userLocation && selectedLandmark) {
      L.polyline(
        [
          [userLocation.lat, userLocation.lng],
          [selectedLandmark.coordinates.lat, selectedLandmark.coordinates.lng]
        ],
        { color: '#3b82f6', weight: 3, dashArray: '10, 10', opacity: 0.6 }
      ).addTo(routeLayerRef.current);
    }

    // Ligne entre marqueur sélectionné et marqueur de comparaison
    if (selectedLandmark && comparisonLandmark) {
      L.polyline(
        [
          [selectedLandmark.coordinates.lat, selectedLandmark.coordinates.lng],
          [comparisonLandmark.coordinates.lat, comparisonLandmark.coordinates.lng]
        ],
        { color: '#ef4444', weight: 4, dashArray: '12, 12', opacity: 0.8 }
      ).addTo(routeLayerRef.current);
    }
  }, [userLocation, selectedLandmark, comparisonLandmark]);

  useEffect(() => {
    if (mapRef.current && selectedLandmark) {
      mapRef.current.flyTo([selectedLandmark.coordinates.lat, selectedLandmark.coordinates.lng], 15);
    }
  }, [selectedLandmark]);

  useEffect(() => {
    if (!mapRef.current) return;
    if (pendingCoords) {
      if (!pendingMarkerRef.current) {
        const icon = L.divIcon({ className: 'p-m', html: `<div class="animate-bounce"><div class="bg-slate-900 w-12 h-12 rounded-2xl border-4 border-white flex items-center justify-center text-emerald-400"><svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="4"><path d="M12 5v14M5 12h14"></path></svg></div></div>`, iconSize: [48, 48], iconAnchor: [24, 48] });
        pendingMarkerRef.current = L.marker([pendingCoords.lat, pendingCoords.lng], { icon }).addTo(mapRef.current);
      } else {
        pendingMarkerRef.current.setLatLng([pendingCoords.lat, pendingCoords.lng]);
      }
    } else if (pendingMarkerRef.current) {
      pendingMarkerRef.current.remove();
      pendingMarkerRef.current = null;
    }
  }, [pendingCoords]);

  const handleLocateMe = () => {
    if (!navigator.geolocation) return;
    setIsLocating(true);
    navigator.geolocation.getCurrentPosition(
      (pos) => {
        const latLng = L.latLng(pos.coords.latitude, pos.coords.longitude);
        setIsLocating(false);
        onUserLocationUpdate({ lat: latLng.lat, lng: latLng.lng });
        if (mapRef.current) {
          if (!userMarkerRef.current) {
            const icon = L.divIcon({ className: 'u-m', html: `<div class="relative"><div class="absolute inset-0 w-8 h-8 bg-blue-500/20 rounded-full animate-ping -translate-x-1/2 -translate-y-1/2"></div><div class="w-4 h-4 bg-blue-600 rounded-full border-2 border-white -translate-x-1/2 -translate-y-1/2"></div></div>` });
            userMarkerRef.current = L.marker(latLng, { icon }).addTo(mapRef.current);
          } else userMarkerRef.current.setLatLng(latLng);
          mapRef.current.flyTo(latLng, 14);
        }
      },
      () => setIsLocating(false)
    );
  };

  return (
    <div className={`relative w-full h-full ${isAddingMode ? 'cursor-crosshair' : ''}`}>
      <div ref={containerRef} className="w-full h-full" />
      <button onClick={handleLocateMe} className="absolute z-[1000] bottom-10 right-4 bg-white p-4 rounded-2xl shadow-2xl border border-slate-200 hover:bg-slate-50 transition-colors">
        <Navigation size={24} className={isLocating ? 'animate-pulse' : ''} fill={userMarkerRef.current ? '#2563eb' : 'none'} />
      </button>
    </div>
  );
};

export default RealMap;

import React, { useState, useEffect, useMemo } from 'react';
import RealMap from './components/RealMap';
import { SP_MAP_DATA } from './constants';
import { Landmark, CustomMarker } from './types';
import { getGroundedLocationInfo } from './services/geminiService';
import { getTravelInfo, TravelInfo } from './services/geoUtils';
import { 
  Compass, Sparkles, ChevronRight, ChevronLeft, ExternalLink, MapPin, X, Layers, Loader2, Plus, Trash2,
  Map as MapIcon, Info, Coffee, Utensils, Camera, Music, Heart, ShoppingBag, Star, Bike, Navigation,
  Home, Building2, Briefcase, GraduationCap, Train, Clock, Car, PersonStanding, ArrowRightLeft
} from 'lucide-react';

export type MapStyle = 'standard' | 'satellite';

const COLORS = [
  { name: 'Émeraude', hex: '#10b981' }, { name: 'Rubis', hex: '#ef4444' }, { name: 'Saphir', hex: '#3b82f6' },
  { name: 'Or', hex: '#f59e0b' }, { name: 'Améthyste', hex: '#8b5cf6' }, { name: 'Onyx', hex: '#1f2937' }, { name: 'Ciel', hex: '#06b6d4' }
];

const SYMBOLS = [
  { id: 'map-pin', Icon: MapPin }, { id: 'home', Icon: Home }, { id: 'building', Icon: Building2 },
  { id: 'work', Icon: Briefcase }, { id: 'coffee', Icon: Coffee }, { id: 'utensils', Icon: Utensils },
  { id: 'camera', Icon: Camera }, { id: 'music', Icon: Music }, { id: 'school', Icon: GraduationCap },
  { id: 'heart', Icon: Heart }, { id: 'shopping-bag', Icon: ShoppingBag }, { id: 'star', Icon: Star },
  { id: 'bike', Icon: Bike }, { id: 'train', Icon: Train }
];

export const getSymbolIcon = (id: string, size = 20, color = "currentColor") => {
  const symbol = SYMBOLS.find(s => s.id === id) || SYMBOLS[0];
  return <symbol.Icon size={size} color={color} />;
};

const App: React.FC = () => {
  const [selectedLandmark, setSelectedLandmark] = useState<Landmark | CustomMarker | null>(null);
  const [comparisonLandmark, setComparisonLandmark] = useState<Landmark | CustomMarker | null>(null);
  const [isComparing, setIsComparing] = useState(false);
  const [userLocation, setUserLocation] = useState<{ lat: number, lng: number } | null>(null);

  const [groundedInfo, setGroundedInfo] = useState<{ text: string, links: {uri: string, title: string}[] }>({ text: '', links: [] });
  const [loading, setLoading] = useState<boolean>(false);
  const [isSidebarOpen, setIsSidebarOpen] = useState<boolean>(window.innerWidth >= 1024);
  const [mapStyle, setMapStyle] = useState<MapStyle>('standard');
  const [customMarkers, setCustomMarkers] = useState<CustomMarker[]>(() => {
    const saved = localStorage.getItem('sp_custom_markers');
    return saved ? JSON.parse(saved) : [];
  });
  const [isAddingMode, setIsAddingMode] = useState(false);
  const [pendingCoords, setPendingCoords] = useState<{lat: number, lng: number} | null>(null);
  const [newMarkerForm, setNewMarkerForm] = useState({ title: '', description: '', color: COLORS[0].hex, symbol: SYMBOLS[0].id });

  useEffect(() => { localStorage.setItem('sp_custom_markers', JSON.stringify(customMarkers)); }, [customMarkers]);

  const allLandmarks = useMemo(() => [...SP_MAP_DATA.landmarks, ...customMarkers], [customMarkers]);

  const travelFromUser = useMemo(() => {
    if (!userLocation || !selectedLandmark) return null;
    return getTravelInfo(userLocation.lat, userLocation.lng, selectedLandmark.coordinates.lat, selectedLandmark.coordinates.lng);
  }, [userLocation, selectedLandmark]);

  const travelBetweenMarkers = useMemo(() => {
    if (!selectedLandmark || !comparisonLandmark) return null;
    return getTravelInfo(selectedLandmark.coordinates.lat, selectedLandmark.coordinates.lng, comparisonLandmark.coordinates.lat, comparisonLandmark.coordinates.lng);
  }, [selectedLandmark, comparisonLandmark]);

  const handleLandmarkClick = async (id: string) => {
    const landmark = allLandmarks.find(l => l.id === id);
    if (!landmark) return;
    if (isComparing) {
      if (landmark.id !== selectedLandmark?.id) { setComparisonLandmark(landmark); setIsComparing(false); }
      return;
    }
    setSelectedLandmark(landmark);
    setComparisonLandmark(null);
    setLoading(true);
    const info = landmark.type === 'custom' ? { text: landmark.description, links: [] } : await getGroundedLocationInfo(landmark.name);
    setGroundedInfo(info);
    setLoading(false);
  };

  const handleCustomLandmarkClick = (marker: CustomMarker) => {
    if (isComparing) {
      if (marker.id !== selectedLandmark?.id) { setComparisonLandmark(marker); setIsComparing(false); }
      return;
    }
    setSelectedLandmark(marker);
    setComparisonLandmark(null);
    setGroundedInfo({ text: marker.description, links: [] });
  };

  const saveCustomMarker = () => {
    if (!pendingCoords || !newMarkerForm.title) return;
    const newMarker: CustomMarker = { id: `c-${Date.now()}`, name: newMarkerForm.title, type: 'custom', coordinates: pendingCoords, description: newMarkerForm.description, color: newMarkerForm.color, symbol: newMarkerForm.symbol };
    setCustomMarkers([...customMarkers, newMarker]);
    setPendingCoords(null);
    setIsAddingMode(false);
    setSelectedLandmark(newMarker);
    setGroundedInfo({ text: newMarker.description, links: [] });
    setNewMarkerForm({ title: '', description: '', color: COLORS[0].hex, symbol: SYMBOLS[0].id });
  };

  return (
    <div className="h-[100dvh] w-screen bg-slate-50 flex flex-col lg:row overflow-hidden font-sans relative">
