  );
};

export default App;

export interface RouteInfo {
  distanceKm: number;
  durationMinutes: number;
  geometry?: any; // GéoJSON du tracé
}

export interface TravelModes {
  car: RouteInfo;
  walking: RouteInfo;
  bike: RouteInfo;
}

/**
 * Récupère l'itinéraire réel via l'API OSRM (Open Source Routing Machine)
 */
async function fetchOSRMRoute(lat1: number, lon1: number, lat2: number, lon2: number, profile: 'car' | 'foot' | 'bike'): Promise<RouteInfo> {
  const url = `https://router.project-osrm.org/route/v1/${profile}/${lon1},${lat1};${lon2},${lat2}?overview=full&geometries=geojson`;
  try {
    const response = await fetch(url);
    const data = await response.json();
    if (data.code === 'Ok' && data.routes.length > 0) {
      const route = data.routes[0];
      return {
        distanceKm: parseFloat((route.distance / 1000).toFixed(1)),
        durationMinutes: Math.round(route.duration / 60),
        geometry: route.geometry
      };
    }
  } catch (e) {
    console.error(`Erreur de routage OSRM (${profile}):`, e);
  }
  return { distanceKm: 0, durationMinutes: 0 };
}

/**
 * Calcule les informations de voyage pour plusieurs modes de transport
 */
export async function getAllTravelInfo(lat1: number, lon1: number, lat2: number, lon2: number): Promise<TravelModes> {
  const [car, walking, bike] = await Promise.all([
    fetchOSRMRoute(lat1, lon1, lat2, lon2, 'car'),
    fetchOSRMRoute(lat1, lon1, lat2, lon2, 'foot'),
    fetchOSRMRoute(lat1, lon1, lat2, lon2, 'bike')
  ]);

  return { car, walking, bike };
}

/**
 * Fallback simple au cas où l'API est indisponible
 */
export function calculateStraightDistance(lat1: number, lon1: number, lat2: number, lon2: number): number {
  const R = 6371;
  const dLat = (lat2 - lat1) * Math.PI / 180;
  const dLon = (lon2 - lon1) * Math.PI / 180;
  const a = 
    Math.sin(dLat/2) * Math.sin(dLat/2) +
    Math.cos(lat1 * Math.PI / 180) * Math.cos(lat2 * Math.PI / 180) * 
    Math.sin(dLon/2) * Math.sin(dLon/2);
  const c = 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1-a));
  return parseFloat((R * c).toFixed(1));
}

import React, { useEffect, useRef, useState } from 'react';
import { SP_MAP_DATA } from '../constants';
import L from 'leaflet';
import { MapStyle } from '../App';
import { Navigation } from 'lucide-react';
import { Landmark, CustomMarker } from '../types';

interface RealMapProps {
  onLandmarkClick: (id: string) => void;
  onCustomLandmarkClick: (marker: CustomMarker) => void;
  mapStyle: MapStyle;
  customMarkers: CustomMarker[];
  isAddingMode: boolean;
  onMapClick: (latlng: L.LatLng) => void;
  pendingCoords: { lat: number; lng: number } | null;
  selectedLandmark: Landmark | CustomMarker | null;
  comparisonLandmark: Landmark | CustomMarker | null;
  onUserLocationUpdate: (coords: { lat: number, lng: number } | null) => void;
  userLocation: { lat: number, lng: number } | null;
  routeGeometry?: any; // GéoJSON du tracé actuel
}

const TILE_LAYERS = {
