  'building': '<rect x="4" y="2" width="16" height="20" rx="2" ry="2"></rect><path d="M9 22v-4h6v4"></path><path d="M8 6h8"></path><path d="M8 10h8"></path><path d="M8 14h8"></path>',
  'work': '<rect width="20" height="14" x="2" y="7" rx="2" ry="2"></rect><path d="M16 21V5a2 2 0 0 0-2-2h-4a2 2 0 0 0-2 2v16"></path>',
  'coffee': '<path d="M18 8h1a4 4 0 0 1 0 8h-1"></path><path d="M2 8h16v9a4 4 0 0 1-4 4H6a4 4 0 0 1-4-4V8z"></path><line x1="6" y1="1" x2="6" y2="4"></line><line x1="10" y1="1" x2="10" y2="4"></line><line x1="14" y1="1" x2="14" y2="4"></line>',
  'utensils': '<path d="M3 2v7c0 1.1.9 2 2 2h4a2 2 0 0 0 2-2V2"></path><path d="M7 2v20"></path><path d="M21 15V2v0a5 5 0 0 0-5 5v6c0 1.1.9 2 2 2h3Zm0 0v7"></path>',
  'camera': '<rect x="3" y="4" width="18" height="12" rx="2" ry="2"></rect><path d="M17 4l-1.41-2.12A2 2 0 0 0 13.83 1H10.17a2 2 0 0 0-1.76.88L7 4"></path><circle cx="12" cy="10" r="3"></circle>',
  'music': '<path d="M9 18V5l12-2v13"></path><circle cx="6" cy="18" r="3"></circle><circle cx="18" cy="16" r="3"></circle>',
  'school': '<path d="M22 10v6M2 10l10-5 10 5-10 5z"></path><path d="M6 12v5c3 3 9 3 12 0v-5"></path>',
  'heart': '<path d="M20.84 4.61a5.5 5.5 0 0 0-7.78 0L12 5.67l-1.06-1.06a5.5 5.5 0 0 0-7.78 7.78l1.06 1.06L12 21.23l7.78-7.78 1.06-1.06a5.5 5.5 0 0 0 0-7.78z"></path>',
  'shopping-bag': '<path d="M6 2L3 6v14a2 2 0 0 0 2 2h14a2 2 0 0 0 2-2V6l-3-4Z"></path><line x1="3" y1="6" x2="21" y2="6"></line><path d="M16 10a4 4 0 0 1-8 0"></path>',
  'star': '<polygon points="12 2 15.09 8.26 22 9.27 17 14.14 18.18 21.02 12 17.77 5.82 21.02 7 14.14 2 9.27 8.91 8.26 12 2"></polygon>',
  'bike': '<circle cx="5.5" cy="17.5" r="3.5"></circle><circle cx="18.5" cy="17.5" r="3.5"></circle><path d="M15 6a1 1 0 1 0 0-2 1 1 0 0 0 0 2zm-3 11.5V14l-3-3 4-3 2 3h2"></path>',
  'train': '<path d="M2 14h20M7 8h10M9 22H7M15 22h2M4 18h16V5a2 2 0 0 0-2-2H6a2 2 0 0 0-2 2v13Z"></path>'
};

const STATE_BOUNDS = L.latLngBounds([-25.5, -53.2], [-19.5, -44.0]);

const RealMap: React.FC<RealMapProps> = ({ 
  onLandmarkClick, 
  onCustomLandmarkClick,
  mapStyle, 
  customMarkers, 
  isAddingMode, 
  onMapClick,
  pendingCoords,
  selectedLandmark,
  comparisonLandmark,
  onUserLocationUpdate,
  userLocation,
  routeGeometry
}) => {
  const mapRef = useRef<L.Map | null>(null);
  const containerRef = useRef<HTMLDivElement>(null);
  const userMarkerRef = useRef<L.Marker | null>(null);
  const pendingMarkerRef = useRef<L.Marker | null>(null);
  const customMarkersLayerRef = useRef<L.LayerGroup | null>(null);
  const routeLayerRef = useRef<L.LayerGroup | null>(null);
  const tileLayerRef = useRef<L.TileLayer | null>(null);
  const [isLocating, setIsLocating] = useState(false);

  useEffect(() => {
    if (!containerRef.current || mapRef.current) return;
    const map = L.map(containerRef.current, {
      zoomControl: false,
      attributionControl: false,
      maxBounds: STATE_BOUNDS,
      maxBoundsViscosity: 1.0, 
      minZoom: 8,
    }).setView([-23.5505, -46.6333], 11);

    mapRef.current = map;
    customMarkersLayerRef.current = L.layerGroup().addTo(map);
    routeLayerRef.current = L.layerGroup().addTo(map);
    tileLayerRef.current = L.tileLayer(TILE_LAYERS[mapStyle], { maxZoom: 19 }).addTo(map);

    SP_MAP_DATA.landmarks.forEach(landmark => {
      const iconPath = SYMBOL_PATHS[landmark.symbol || 'map-pin'] || SYMBOL_PATHS['map-pin'];
      const icon = L.divIcon({
        className: 'custom-marker',
        html: `<div class="marker-container"><div style="background-color: ${landmark.color || '#059669'}" class="w-10 h-10 rounded-xl border-2 border-white shadow-lg flex items-center justify-center text-white"><svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="3">${iconPath}</svg></div></div>`,
        iconSize: [40, 40],
        iconAnchor: [20, 40],
      });
      L.marker([landmark.coordinates.lat, landmark.coordinates.lng], { icon })
        .addTo(map)
        .on('click', (e) => { L.DomEvent.stopPropagation(e); onLandmarkClick(landmark.id); });
    });

    map.on('click', (e) => onMapClick(e.latlng));
    return () => { if (mapRef.current) mapRef.current.remove(); mapRef.current = null; };
  }, []);

  useEffect(() => {
    if (tileLayerRef.current) tileLayerRef.current.setUrl(TILE_LAYERS[mapStyle]);
  }, [mapStyle]);

  useEffect(() => {
    if (!mapRef.current || !customMarkersLayerRef.current) return;
    customMarkersLayerRef.current.clearLayers();
    customMarkers.forEach(marker => {
      const iconPath = SYMBOL_PATHS[marker.symbol] || SYMBOL_PATHS['map-pin'];
      const icon = L.divIcon({
        className: 'custom-marker',
        html: `<div class="marker-container"><div style="background-color: ${marker.color}" class="w-10 h-10 rounded-xl border-2 border-white shadow-lg flex items-center justify-center text-white"><svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="3">${iconPath}</svg></div></div>`,
        iconSize: [40, 40],
        iconAnchor: [20, 40],
      });
      L.marker([marker.coordinates.lat, marker.coordinates.lng], { icon })
        .addTo(customMarkersLayerRef.current!)
        .on('click', (e) => { L.DomEvent.stopPropagation(e); onCustomLandmarkClick(marker); });
    });
  }, [customMarkers]);

  // Dessiner l'itinéraire basé sur la géométrie réelle
  useEffect(() => {
    if (!mapRef.current || !routeLayerRef.current) return;
    routeLayerRef.current.clearLayers();

    if (routeGeometry) {
      // Afficher le tracé réel reçu de l'API
      const geoJsonLayer = L.geoJSON(routeGeometry, {
        style: {
          color: comparisonLandmark ? '#ef4444' : '#3b82f6',
          weight: 5,
          opacity: 0.7,
          dashArray: '1, 10',
          lineCap: 'round'
        }
      }).addTo(routeLayerRef.current);

      // Ajuster la vue pour voir tout l'itinéraire
      mapRef.current.fitBounds(geoJsonLayer.getBounds(), { padding: [50, 50] });
    } else if (userLocation && selectedLandmark && !comparisonLandmark) {
        // Fallback ligne directe si pas de géométrie encore chargée
        L.polyline(
            [[userLocation.lat, userLocation.lng], [selectedLandmark.coordinates.lat, selectedLandmark.coordinates.lng]],
            { color: '#3b82f6', weight: 2, dashArray: '5, 5', opacity: 0.4 }
        ).addTo(routeLayerRef.current);
    }
  }, [routeGeometry, userLocation, selectedLandmark, comparisonLandmark]);

  useEffect(() => {
    if (mapRef.current && selectedLandmark && !routeGeometry) {
      mapRef.current.flyTo([selectedLandmark.coordinates.lat, selectedLandmark.coordinates.lng], 15);
    }
  }, [selectedLandmark, routeGeometry]);

  useEffect(() => {
    if (!mapRef.current) return;
    if (pendingCoords) {
      if (!pendingMarkerRef.current) {
        const icon = L.divIcon({ className: 'p-m', html: `<div class="animate-bounce"><div class="bg-slate-900 w-12 h-12 rounded-2xl border-4 border-white flex items-center justify-center text-emerald-400"><svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="4"><path d="M12 5v14M5 12h14"></path></svg></div></div>`, iconSize: [48, 48], iconAnchor: [24, 48] });
        pendingMarkerRef.current = L.marker([pendingCoords.lat, pendingCoords.lng], { icon }).addTo(mapRef.current);
      } else {
        pendingMarkerRef.current.setLatLng([pendingCoords.lat, pendingCoords.lng]);
      }
    } else if (pendingMarkerRef.current) {
      pendingMarkerRef.current.remove();
      pendingMarkerRef.current = null;
    }
  }, [pendingCoords]);

  const handleLocateMe = () => {
    if (!navigator.geolocation) return;
    setIsLocating(true);
    navigator.geolocation.getCurrentPosition(
      (pos) => {
        const latLng = L.latLng(pos.coords.latitude, pos.coords.longitude);
        setIsLocating(false);
        onUserLocationUpdate({ lat: latLng.lat, lng: latLng.lng });
        if (mapRef.current) {
          if (!userMarkerRef.current) {
            const icon = L.divIcon({ className: 'u-m', html: `<div class="relative"><div class="absolute inset-0 w-8 h-8 bg-blue-500/20 rounded-full animate-ping -translate-x-1/2 -translate-y-1/2"></div><div class="w-4 h-4 bg-blue-600 rounded-full border-2 border-white -translate-x-1/2 -translate-y-1/2"></div></div>` });
            userMarkerRef.current = L.marker(latLng, { icon }).addTo(mapRef.current);
          } else userMarkerRef.current.setLatLng(latLng);
          mapRef.current.flyTo(latLng, 14);
        }
      },
      () => setIsLocating(false)
    );
  };

  return (
    <div className={`relative w-full h-full ${isAddingMode ? 'cursor-crosshair' : ''}`}>
      <div ref={containerRef} className="w-full h-full" />
      <button onClick={handleLocateMe} className="absolute z-[1000] bottom-10 right-4 bg-white p-4 rounded-2xl shadow-2xl border border-slate-200 hover:bg-slate-50 transition-colors">
        <Navigation size={24} className={isLocating ? 'animate-pulse' : ''} fill={userMarkerRef.current ? '#2563eb' : 'none'} />
      </button>
    </div>
  );
};

