                    <button onClick={() => setTravelMode('bike')} className={`py-3 rounded-2xl flex flex-col items-center gap-1 transition-all border ${travelMode === 'bike' ? 'bg-blue-600 border-blue-600 text-white shadow-lg' : 'bg-slate-50 border-slate-100 text-slate-400'}`}>
