                        <p className="text-2xl font-black text-slate-900 tracking-tight">{travelData[travelMode].distanceKm}<span className="text-sm ml-1 text-slate-400">km</span></p>
                      </div>
                      <div className="bg-blue-50 p-4 rounded-2xl border border-blue-100 text-center">
                        <p className="text-[9px] font-black text-blue-400 uppercase mb-1">Temps</p>
                        <p className="text-2xl font-black text-blue-700 tracking-tight flex items-center justify-center gap-1"><Clock size={16}/> {travelData[travelMode].durationMinutes}<span className="text-sm font-bold">min</span></p>
                      </div>
                    </div>
                  )}
                </div>
              )}
            </div>
          </div>
        )}

        {/* Controles de Mapa */}
        <div className="absolute top-4 right-4 z-[1000] flex flex-col gap-3">
          <button 
            onClick={() => setIsSidebarOpen(true)}
            className="lg:hidden bg-white/95 backdrop-blur-md p-3.5 rounded-2xl shadow-xl border border-white active:scale-95 transition-transform"
          >
            <Compass size={24} />
          </button>
          <button 
            onClick={() => setMapStyle(prev => prev === 'standard' ? 'satellite' : 'standard')}
