    if (!mapRef.current) return;
    if (measurementPoint) {
      if (!measurementMarkerRef.current) {
        const icon = L.divIcon({
          className: 'measurement-target',
          html: `<div class="w-6 h-6 bg-blue-600 rounded-full border-4 border-white shadow-2xl flex items-center justify-center animate-in zoom-in-50"><div class="w-1.5 h-1.5 bg-white rounded-full"></div></div>`,
          iconSize: [24, 24],
          iconAnchor: [12, 12]
        });
        measurementMarkerRef.current = L.marker([measurementPoint.lat, measurementPoint.lng], { icon }).addTo(mapRef.current);
      } else {
        measurementMarkerRef.current.setLatLng([measurementPoint.lat, measurementPoint.lng]);
      }
    } else if (measurementMarkerRef.current) {
      measurementMarkerRef.current.remove();
      measurementMarkerRef.current = null;
    }
  }, [measurementPoint]);

  useEffect(() => {
    if (!mapRef.current) return;
    if (pendingCoords) {
      if (!pendingMarkerRef.current) {
        const icon = L.divIcon({
          className: 'pending-marker-wrapper',
          html: `<div class="animate-bounce bg-slate-900 w-12 h-12 rounded-2xl border-4 border-white flex items-center justify-center text-emerald-400 shadow-2xl"><svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="4"><path d="M12 5v14M5 12h14"></path></svg></div>`,
          iconSize: [48, 48],
          iconAnchor: [24, 48]
        });
        pendingMarkerRef.current = L.marker([pendingCoords.lat, pendingCoords.lng], { icon }).addTo(mapRef.current);
      } else {
        pendingMarkerRef.current.setLatLng([pendingCoords.lat, pendingCoords.lng]);
      }
    } else if (pendingMarkerRef.current) {
      pendingMarkerRef.current.remove();
      pendingMarkerRef.current = null;
    }
  }, [pendingCoords]);

  useEffect(() => {
    if (!mapRef.current || !tileLayerRef.current) return;
    tileLayerRef.current.setUrl(TILE_LAYERS[mapStyle]);
  }, [mapStyle]);

  async function handleLocateMe() {
    if (!navigator.geolocation) return;
    setIsLocating(true);
    navigator.geolocation.getCurrentPosition(
      (pos) => {
        const latLng = L.latLng(pos.coords.latitude, pos.coords.longitude);
        setIsLocating(false);
        onUserLocationUpdate?.({ lat: latLng.lat, lng: latLng.lng });
        if (mapRef.current) {
          if (!userMarkerRef.current) {
            const icon = L.divIcon({
              className: 'user-pos-wrapper',
              html: `<div class="relative"><div class="absolute inset-0 w-10 h-10 bg-blue-500/20 rounded-full animate-ping -translate-x-1/2 -translate-y-1/2"></div><div class="w-5 h-5 bg-blue-600 rounded-full border-4 border-white -translate-x-1/2 -translate-y-1/2 shadow-xl"></div></div>`,
            });
            userMarkerRef.current = L.marker(latLng, { icon }).addTo(mapRef.current);
          } else userMarkerRef.current.setLatLng(latLng);
          mapRef.current.flyTo(latLng, 14);
        }
      },
      () => setIsLocating(false),
      { enableHighAccuracy: true }
    );
  }

  return (
    <div className={`relative w-full h-full ${isAddingMode || isMeasuring ? 'cursor-crosshair' : ''}`}>
      <div ref={containerRef} className="w-full h-full" />
      <button onClick={handleLocateMe} className="absolute z-[1000] bottom-10 right-4 bg-white/90 backdrop-blur p-4 rounded-3xl shadow-2xl border border-white hover:bg-slate-50 active:scale-95 transition-all">
        <Navigation size={28} className={isLocating ? 'animate-pulse text-blue-600' : 'text-slate-700'} fill={userMarkerRef.current ? '#2563eb' : 'none'} />
      </button>
    </div>
  );
});

export default RealMap;

import React, { useState, useEffect, useCallback, useRef } from 'react';
import RealMap from './components/RealMap';
import { SP_MAP_DATA } from './constants';
import { Landmark, CustomMarker } from './types';
import { getGroundedLocationInfo } from './services/geminiService';
import { getAllTravelInfo, TravelModes } from './services/geoUtils';
import { 
  Compass, 
  ChevronRight, 
  ChevronLeft, 
  ExternalLink, 
  MapPin, 
  X, 
  Layers, 
  Loader2, 
  Plus, 
  Trash2,
  Map as MapIcon,
  Info,
  Bike,
  Navigation,
  Home,
  Building2,
  Briefcase,
  GraduationCap,
  Train,
  Ruler,
  Car,
  Footprints,
  Clock,
  ArrowRight
} from 'lucide-react';

export type MapStyle = 'standard' | 'satellite';

const COLORS = [
  { name: 'Émeraude', hex: '#10b981' },
  { name: 'Rubis', hex: '#ef4444' },
  { name: 'Saphir', hex: '#3b82f6' },
  { name: 'Or', hex: '#f59e0b' },
  { name: 'Améthyste', hex: '#8b5cf6' },
  { name: 'Onyx', hex: '#1f2937' },
  { name: 'Ciel', hex: '#06b6d4' }
];

const SYMBOLS = [
  { id: 'map-pin', Icon: MapPin },
  { id: 'home', Icon: Home },
  { id: 'building', Icon: Building2 },
  { id: 'work', Icon: Briefcase },
  { id: 'school', Icon: GraduationCap },
  { id: 'train', Icon: Train }
];

export const getSymbolIcon = (id: string, size = 20, color = "currentColor") => {
  const symbol = SYMBOLS.find(s => s.id === id) || SYMBOLS[0];
  return <symbol.Icon size={size} color={color} />;
};

const App: React.FC = () => {
  const [selectedLandmark, setSelectedLandmark] = useState<Landmark | CustomMarker | null>(null);
  const [groundedInfo, setGroundedInfo] = useState<{ text: string, links: {uri: string, title: string}[] }>({ text: '', links: [] });
  const [loading, setLoading] = useState<boolean>(false);
  const [isSidebarOpen, setIsSidebarOpen] = useState<boolean>(window.innerWidth >= 1024);
  const [mapStyle, setMapStyle] = useState<MapStyle>('standard');
  const [userLocation, setUserLocation] = useState<{lat: number, lng: number} | null>(null);

  // Measurement state
  const [isMeasuring, setIsMeasuring] = useState(false);
  const [measurementPoint, setMeasurementPoint] = useState<{lat: number, lng: number} | null>(null);
  const [travelData, setTravelData] = useState<TravelModes | null>(null);
  const [travelMode, setTravelMode] = useState<'car' | 'walking' | 'bike'>('car');
  const [isCalculatingRoute, setIsCalculatingRoute] = useState(false);

  const [customMarkers, setCustomMarkers] = useState<CustomMarker[]>(() => {
    const saved = localStorage.getItem('sp_custom_markers');
    return saved ? JSON.parse(saved) : [];
  });

  const [isAddingMode, setIsAddingMode] = useState(false);
  const [pendingCoords, setPendingCoords] = useState<{lat: number, lng: number} | null>(null);
  const [newMarkerForm, setNewMarkerForm] = useState({ 
    title: '', 
    description: '', 
    color: COLORS[0].hex,
    symbol: SYMBOLS[0].id 
  });

  const mapComponentRef = useRef<{ triggerLocate: () => void } | null>(null);

  useEffect(() => {
    localStorage.setItem('sp_custom_markers', JSON.stringify(customMarkers));
  }, [customMarkers]);

  const handleLandmarkClick = async (id: string) => {
    const landmark = [...SP_MAP_DATA.landmarks, ...customMarkers].find(l => l.id === id);
    if (landmark) {
      setSelectedLandmark(landmark);
      setLoading(true);
      const info = landmark.type === 'custom' ? { text: landmark.description, links: [] } : await getGroundedLocationInfo(landmark.name);
      setGroundedInfo(info);
      setLoading(false);
      setIsMeasuring(false);
      setMeasurementPoint(null);
      if (window.innerWidth < 1024) setIsSidebarOpen(false);
    }
  };

  const handleMapClick = useCallback(async (latlng: any) => {
    if (isAddingMode) {
      setPendingCoords({ lat: latlng.lat, lng: latlng.lng });
    } else if (isMeasuring) {
      if (!userLocation) {
        // Se não tem localização, tenta buscar automaticamente antes de medir
        mapComponentRef.current?.triggerLocate();
        return;
      }
      setMeasurementPoint({ lat: latlng.lat, lng: latlng.lng });
      setIsCalculatingRoute(true);
      try {
        const data = await getAllTravelInfo(userLocation.lat, userLocation.lng, latlng.lat, latlng.lng);
        setTravelData(data);
      } catch (err) {
        console.error("Erro ao calcular rota:", err);
      } finally {
        setIsCalculatingRoute(false);
      }
    } else {
      if (selectedLandmark) setSelectedLandmark(null);
    }
  }, [isAddingMode, isMeasuring, userLocation, selectedLandmark]);

  const toggleMeasurementMode = () => {
    const newMode = !isMeasuring;
    setIsMeasuring(newMode);
    setIsAddingMode(false);
    setSelectedLandmark(null);
    if (newMode && !userLocation) {
      mapComponentRef.current?.triggerLocate();
    }
    if (!newMode) {
      setMeasurementPoint(null);
      setTravelData(null);
    }
  };

  const saveCustomMarker = () => {
    if (!pendingCoords || !newMarkerForm.title) return;
    const newMarker: CustomMarker = {
      id: `custom-${Date.now()}`,
      name: newMarkerForm.title,
      type: 'custom',
      coordinates: pendingCoords,
      description: newMarkerForm.description,
      color: newMarkerForm.color,
      symbol: newMarkerForm.symbol
    };
    setCustomMarkers([...customMarkers, newMarker]);
    setPendingCoords(null);
    setIsAddingMode(false);
    setNewMarkerForm({ title: '', description: '', color: COLORS[0].hex, symbol: SYMBOLS[0].id });
    setSelectedLandmark(newMarker);
    setGroundedInfo({ text: newMarker.description, links: [] });
