  return (
    <div className="h-[100dvh] w-screen bg-slate-50 text-slate-900 overflow-hidden relative flex flex-col lg:flex-row font-sans">

      <aside className={`
        fixed inset-y-0 left-0 lg:relative z-[3000] lg:z-[2000]
        bg-white lg:bg-white/80 lg:backdrop-blur-xl border-r border-slate-200
        transition-all duration-500 ease-in-out
        ${isSidebarOpen ? 'w-full sm:w-[420px] translate-x-0' : 'w-0 -translate-x-full lg:translate-x-0 overflow-hidden'}
      `}>
        <div className="flex flex-col h-full">
          <div className="p-6 sm:p-8 flex justify-between items-center border-b border-slate-100">
            <div className="flex items-center gap-3">
              <div className="w-10 h-10 bg-emerald-600 rounded-xl flex items-center justify-center text-white shadow-lg shadow-emerald-200">
                <MapIcon size={20} />
              </div>
              <h1 className="font-display text-2xl font-black text-slate-800 tracking-tight">Sampa Map</h1>
            </div>
            <button onClick={() => setIsSidebarOpen(false)} className="lg:hidden p-2.5 hover:bg-slate-100 rounded-2xl text-slate-400">
              <ChevronLeft size={24} />
            </button>
          </div>

          <div className="flex-1 overflow-y-auto p-6 sm:p-8 space-y-8 custom-scrollbar">

            <div className="grid grid-cols-2 gap-3">
              <button 
                onClick={() => { setIsAddingMode(!isAddingMode); setIsMeasuring(false); }}
                className={`flex flex-col items-center justify-center gap-2 py-5 rounded-3xl font-bold transition-all ${isAddingMode ? 'bg-emerald-600 text-white shadow-emerald-200 shadow-xl' : 'bg-slate-100 text-slate-600 hover:bg-slate-200'}`}
              >
                <Plus size={24} className={isAddingMode ? 'animate-pulse' : ''} />
                <span className="text-xs uppercase tracking-widest">Marqueur</span>
              </button>
              <button 
                onClick={toggleMeasurementMode}
                className={`flex flex-col items-center justify-center gap-2 py-5 rounded-3xl font-bold transition-all ${isMeasuring ? 'bg-blue-600 text-white shadow-blue-200 shadow-xl' : 'bg-slate-100 text-slate-600 hover:bg-slate-200'}`}
              >
                <Ruler size={24} className={isMeasuring ? 'animate-bounce' : ''} />
                <span className="text-xs uppercase tracking-widest">Distance</span>
              </button>
            </div>

            {isAddingMode && (
              <section className="bg-emerald-50 p-6 rounded-[32px] border-2 border-emerald-200 animate-in fade-in slide-in-from-top-4 duration-300">
                <div className="flex justify-between items-center mb-6">
                  <span className="text-[10px] font-black text-emerald-600 uppercase tracking-widest">Nouveau Marqueur</span>
                  <button onClick={() => {setIsAddingMode(false); setPendingCoords(null);}} className="text-slate-400 hover:text-slate-600"><X size={20} /></button>
                </div>
                {!pendingCoords ? (
                  <div className="text-center py-6 space-y-2">
                    <div className="w-12 h-12 bg-white rounded-full flex items-center justify-center mx-auto shadow-sm text-emerald-600">
                      <Navigation size={24} className="animate-bounce" />
                    </div>
                    <p className="text-sm text-emerald-900 font-bold">Touchez la carte pour choisir l'emplacement</p>
                  </div>
                ) : (
                  <div className="space-y-4">
                    <input 
                      type="text" 
                      placeholder="Nom du lieu..." 
                      className="w-full p-4 rounded-2xl ring-1 ring-slate-200 text-sm focus:ring-2 focus:ring-emerald-500 outline-none bg-white"
                      value={newMarkerForm.title}
                      onChange={e => setNewMarkerForm({...newMarkerForm, title: e.target.value})}
                    />
                    <div className="grid grid-cols-6 gap-2">
                      {SYMBOLS.map(({ id, Icon }) => (
                        <button key={id} onClick={() => setNewMarkerForm({...newMarkerForm, symbol: id})} className={`aspect-square rounded-xl flex items-center justify-center transition-all ${newMarkerForm.symbol === id ? 'bg-slate-900 text-white' : 'bg-white border border-slate-100 text-slate-400'}`}>
                          <Icon size={16} />
                        </button>
                      ))}
                    </div>
                    <button onClick={saveCustomMarker} disabled={!newMarkerForm.title} className="w-full py-4 bg-emerald-600 text-white rounded-[20px] font-bold shadow-lg active:scale-95 transition-transform">Enregistrer</button>
                  </div>
                )}
              </section>
            )}

            <section className="space-y-6">
              <div className="flex items-center justify-between">
                <h2 className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em]">Lieux & Monuments</h2>
                <span className="px-2 py-0.5 bg-slate-100 rounded text-[9px] font-bold text-slate-500">{[...customMarkers, ...SP_MAP_DATA.landmarks].length}</span>
              </div>
              <div className="space-y-3">
                {[...customMarkers, ...SP_MAP_DATA.landmarks].map((l) => (
                  <button
                    key={l.id}
                    onClick={() => handleLandmarkClick(l.id)}
                    className={`w-full flex items-center justify-between p-4 rounded-2xl border-2 transition-all ${selectedLandmark?.id === l.id ? 'bg-slate-900 border-slate-900 text-white shadow-lg' : 'bg-white border-slate-100 hover:border-slate-200 text-slate-600 shadow-sm'}`}
                  >
                    <div className="flex items-center gap-3 truncate">
                      {l.type === 'custom' ? <div style={{ color: (l as CustomMarker).color }}>{getSymbolIcon((l as CustomMarker).symbol, 18)}</div> : <MapPin size={18} className="text-emerald-500" />}
                      <span className="font-bold text-sm truncate">{l.name}</span>
                    </div>
                    <ChevronRight size={14} className="opacity-30 flex-shrink-0" />
