        {/* HUD de Medição Flutuante */}
        {isMeasuring && (
          <div className="absolute top-4 left-4 lg:left-6 z-[2000] w-[calc(100%-2rem)] max-w-sm pointer-events-none">
            <div className="bg-white/90 backdrop-blur-xl rounded-[32px] shadow-2xl border border-white p-6 pointer-events-auto animate-in fade-in slide-in-from-top-4">
              <div className="flex justify-between items-center mb-5">
                <div className="flex items-center gap-3">
                  <div className="w-8 h-8 bg-blue-600 rounded-lg flex items-center justify-center text-white">
                    <Ruler size={16} />
