                  <span className="font-black text-xs uppercase tracking-wider text-slate-800">Mode Mesure</span>
                </div>
                <button onClick={toggleMeasurementMode} className="p-2 hover:bg-slate-100 rounded-full text-slate-400"><X size={18} /></button>
