                <div className="space-y-5">
                  <div className="grid grid-cols-3 gap-2">
                    <button onClick={() => setTravelMode('car')} className={`py-3 rounded-2xl flex flex-col items-center gap-1 transition-all border ${travelMode === 'car' ? 'bg-blue-600 border-blue-600 text-white shadow-lg' : 'bg-slate-50 border-slate-100 text-slate-400'}`}>
                      <Car size={18} /><span className="text-[10px] font-black uppercase">Auto</span>
                    </button>
                    <button onClick={() => setTravelMode('walking')} className={`py-3 rounded-2xl flex flex-col items-center gap-1 transition-all border ${travelMode === 'walking' ? 'bg-blue-600 border-blue-600 text-white shadow-lg' : 'bg-slate-50 border-slate-100 text-slate-400'}`}>
                      <Footprints size={18} /><span className="text-[10px] font-black uppercase">Pied</span>
                    </button>
                    <button onClick={() => setTravelMode('bike')} className={`py-3 rounded-2xl flex flex-col items-center gap-1 transition-all border ${travelMode === 'bike' ? 'bg-blue-600 border-blue-600 text-white shadow-lg' : 'bg-slate-50 border-slate-100 text-slate-400'}`}>
                      <Bike size={18} /><span className="text-[10px] font-black uppercase">Vélo</span>
                    </button>
                  </div>

                  {isCalculatingRoute ? (
                    <div className="flex items-center justify-center py-6 gap-3 text-blue-600">
                      <Loader2 size={24} className="animate-spin" />
                      <span className="text-sm font-black uppercase tracking-widest">Calcul en cours...</span>
                    </div>
                  ) : travelData && (
                    <div className="grid grid-cols-2 gap-3">
                      <div className="bg-slate-50 p-4 rounded-2xl border border-slate-100 text-center">
                        <p className="text-[9px] font-black text-slate-400 uppercase mb-1">Distance</p>
                        <p className="text-2xl font-black text-slate-900 tracking-tight">{travelData[travelMode].distanceKm}<span className="text-sm ml-1 text-slate-400">km</span></p>
                      </div>
                      <div className="bg-blue-50 p-4 rounded-2xl border border-blue-100 text-center">
                        <p className="text-[9px] font-black text-blue-400 uppercase mb-1">Temps</p>
                        <p className="text-2xl font-black text-blue-700 tracking-tight flex items-center justify-center gap-1"><Clock size={16}/> {travelData[travelMode].durationMinutes}<span className="text-sm font-bold">min</span></p>
                      </div>
                    </div>
                  )}
                </div>
              )}
            </div>
          </div>
        )}

        {/* Controles de Mapa */}
        <div className="absolute top-4 right-4 z-[1000] flex flex-col gap-3">
          <button 
            onClick={() => setIsSidebarOpen(true)}
            className="lg:hidden bg-white/95 backdrop-blur-md p-3.5 rounded-2xl shadow-xl border border-white active:scale-95 transition-transform"
          >
            <Compass size={24} />
          </button>
          <button 
            onClick={() => setMapStyle(prev => prev === 'standard' ? 'satellite' : 'standard')}
            className="bg-white/95 backdrop-blur-md p-3.5 rounded-2xl shadow-xl border border-white active:scale-95 transition-transform"
          >
            <Layers size={24} className={mapStyle === 'satellite' ? 'text-emerald-600' : 'text-slate-600'} />
          </button>
        </div>

        {/* Painel de Detalhes do Landmark */}
        {selectedLandmark && (
          <div className="fixed inset-x-0 bottom-0 lg:left-[420px] z-[4000] p-4 lg:p-10 pointer-events-none">
            <div className="bg-white rounded-[40px] shadow-2xl pointer-events-auto overflow-hidden animate-sheet max-w-2xl mx-auto border border-slate-200">
               <div className="p-8 space-y-6">
                  <div className="flex justify-between items-start">
                    <div className="flex items-center gap-5">
                      <div className="p-4 rounded-3xl text-white shadow-lg shadow-current/20" style={{ backgroundColor: selectedLandmark.type === 'custom' ? (selectedLandmark as CustomMarker).color : '#059669' }}>
                        {selectedLandmark.type === 'custom' ? getSymbolIcon((selectedLandmark as CustomMarker).symbol, 28) : <MapPin size={28} />}
                      </div>
                      <div>
                        <h2 className="text-2xl font-black text-slate-900 tracking-tight">{selectedLandmark.name}</h2>
                        <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mt-1">
                          {selectedLandmark.type === 'custom' ? 'Marqueur personnel' : 'Monument historique'}
                        </p>
                      </div>
                    </div>
                    <button onClick={() => setSelectedLandmark(null)} className="p-2.5 hover:bg-slate-50 rounded-full text-slate-300 hover:text-red-500 transition-colors"><X size={24} /></button>
                  </div>

                  {loading ? (
                    <div className="py-12 flex flex-col items-center gap-4">
                      <Loader2 className="animate-spin text-emerald-600" size={40} />
                      <span className="text-xs font-black text-slate-400 uppercase tracking-widest">Recherche d'infos...</span>
                    </div>
                  ) : (
                    <div className="bg-slate-50 p-6 rounded-3xl border border-slate-100 space-y-4">
                      <p className="text-slate-700 text-base leading-relaxed font-medium">
                        {selectedLandmark.type === 'custom' ? selectedLandmark.description : groundedInfo.text}
                      </p>
                      {groundedInfo.links.length > 0 && (
                        <div className="flex flex-wrap gap-2 pt-2">
                          {groundedInfo.links.map((l, i) => (
                            <a key={i} href={l.uri} target="_blank" className="flex items-center gap-2 px-4 py-2.5 bg-white rounded-xl text-xs font-bold border border-slate-200 hover:border-emerald-500 hover:text-emerald-700 transition-all shadow-sm">
                              <MapIcon size={14} className="text-blue-500" /> {l.title} <ArrowRight size={12}/>
                            </a>
                          ))}
                        </div>
                      )}
                    </div>
                  )}
                  {selectedLandmark.type === 'custom' && (
                    <button onClick={() => { setCustomMarkers(customMarkers.filter(m => m.id !== selectedLandmark.id)); setSelectedLandmark(null); }} className="w-full py-4 text-red-500 font-bold border-2 border-red-50 rounded-2xl hover:bg-red-50 transition-colors flex items-center justify-center gap-2">
                      <Trash2 size={18} /> Supprimer le marqueur
                    </button>
                  )}
               </div>
            </div>
          </div>
        )}
      </main>
    </div>
  );
};

export default App;

export interface RouteInfo {
  distanceKm: number;
  durationMinutes: number;
  geometry?: any;
}

export interface TravelModes {
  car: RouteInfo;
  walking: RouteInfo;
  bike: RouteInfo;
}

async function fetchOSRMRoute(lat1: number, lon1: number, lat2: number, lon2: number, profile: 'car' | 'foot' | 'bike'): Promise<RouteInfo> {
  const url = `https://router.project-osrm.org/route/v1/${profile}/${lon1},${lat1};${lon2},${lat2}?overview=full&geometries=geojson`;
  try {
    const response = await fetch(url);
    const data = await response.json();
    if (data.code === 'Ok' && data.routes.length > 0) {
      const route = data.routes[0];
      return {
        distanceKm: parseFloat((route.distance / 1000).toFixed(1)),
        durationMinutes: Math.round(route.duration / 60),
        geometry: route.geometry
      };
    }
  } catch (e) {
    console.error(`OSRM Error (${profile}):`, e);
  }
  return { distanceKm: 0, durationMinutes: 0 };
}

export async function getAllTravelInfo(lat1: number, lon1: number, lat2: number, lon2: number): Promise<TravelModes> {
  const [car, walking, bike] = await Promise.all([
    fetchOSRMRoute(lat1, lon1, lat2, lon2, 'car'),
    fetchOSRMRoute(lat1, lon1, lat2, lon2, 'foot'),
    fetchOSRMRoute(lat1, lon1, lat2, lon2, 'bike')
  ]);

  return { car, walking, bike };
}

