import React from 'react';
import { SP_MAP_DATA } from '../constants';
import LandmarkIcon from './LandmarkIcon';

interface IllustratedMapProps {
  onLandmarkClick: (id: string) => void;
  showCoordinates?: boolean;
}

const IllustratedMap: React.FC<IllustratedMapProps> = ({ onLandmarkClick, showCoordinates = true }) => {
  const width = 1000;
  const height = 1414;
  const centerX = width / 2;
  const centerY = height / 2;

  // Gerar marcações nos eixos
  const ticksX = [];
  for (let i = 0; i <= width; i += 100) ticksX.push(i);

  const ticksY = [];
  for (let i = 0; i <= height; i += 100) ticksY.push(i);

  return (
    <div className="relative w-full aspect-[297/420] bg-[#fdfcf0] rounded-xl overflow-hidden shadow-2xl border-8 border-white print:border-0">
      <svg 
        viewBox={`0 0 ${width} ${height}`} 
        className="w-full h-full"
        xmlns="http://www.w3.org/2000/svg"
      >
        <defs>
          {/* Grade menor (milimetrada) */}
          <pattern id="smallGrid" width="20" height="20" patternUnits="userSpaceOnUse">
            <path d="M 20 0 L 0 0 0 20" fill="none" stroke="rgba(0,0,0,0.05)" strokeWidth="0.5"/>
          </pattern>
          {/* Grade maior */}
          <pattern id="grid" width="100" height="100" patternUnits="userSpaceOnUse">
            <rect width="100" height="100" fill="url(#smallGrid)"/>
            <path d="M 100 0 L 0 0 0 100" fill="none" stroke="rgba(0,0,0,0.15)" strokeWidth="1"/>
          </pattern>
        </defs>

        {/* Fundo de Papel Milimetrado */}
        <rect width="100%" height="100%" fill="url(#grid)" />

        {/* Eixos Cartesianos */}
        <g className="axes">
          {/* Eixo X */}
          <line x1="0" y1={centerY} x2={width} y2={centerY} stroke="#94a3b8" strokeWidth="2" />
          <text x={width - 20} y={centerY - 10} className="fill-slate-400 font-bold text-xs italic">Eixo X</text>

          {/* Eixo Y */}
          <line x1={centerX} y1="0" x2={centerX} y2={height} stroke="#94a3b8" strokeWidth="2" />
          <text x={centerX + 10} y="30" className="fill-slate-400 font-bold text-xs italic">Eixo Y</text>

          {/* Origem (0,0) */}
          <circle cx={centerX} cy={centerY} r="4" fill="#64748b" />
          <text x={centerX + 8} y={centerY + 18} className="fill-slate-500 text-[10px] font-bold">(0,0)</text>
        </g>

        {/* Marcações de Escala nos Eixos */}
        {ticksX.map(x => (
          <g key={`tx-${x}`}>
            <line x1={x} y1={centerY - 5} x2={x} y2={centerY + 5} stroke="#cbd5e1" strokeWidth="1" />
            <text x={x} y={centerY + 20} textAnchor="middle" className="fill-slate-400 text-[8px]">{x - centerX}</text>
          </g>
        ))}
        {ticksY.map(y => (
          <g key={`ty-${y}`}>
            <line x1={centerX - 5} y1={y} x2={centerX + 5} y2={y} stroke="#cbd5e1" strokeWidth="1" />
            <text x={centerX - 15} y={y} textAnchor="end" alignmentBaseline="middle" className="fill-slate-400 text-[8px]">{centerY - y}</text>
          </g>
        ))}

        {/* Rios (Estilizados como trajetórias matemáticas) */}
        <g className="opacity-20">
          <path 
            d="M0,350 Q300,380 500,350 T1000,380" 
            fill="none" 
            stroke="#0ea5e9" 
            strokeWidth="4" 
            strokeDasharray="10,5"
          />
          <path 
            d="M200,950 Q280,750 350,365" 
            fill="none" 
            stroke="#0ea5e9" 
            strokeWidth="3" 
            strokeDasharray="5,5"
          />
        </g>

        {/* Landmarks com coordenadas */}
        {SP_MAP_DATA.landmarks.map((landmark) => (
          <LandmarkIcon
            key={landmark.id}
            type={landmark.type}
            x={landmark.coordinates.x || 0}
            y={landmark.coordinates.y || 0}
            name={showCoordinates ? `${landmark.name} (${(landmark.coordinates.x || 0) - centerX}, ${centerY - (landmark.coordinates.y || 0)})` : landmark.name}
            onClick={() => onLandmarkClick(landmark.id)}
          />
        ))}

        {/* Título e Legenda Matemática */}
        <g transform="translate(50, 80)">
          <text className="font-display fill-slate-800 text-5xl" style={{ fontSize: '48px' }}>São Paulo</text>
          <text y="35" className="fill-slate-500 font-bold uppercase tracking-widest" style={{ fontSize: '12px' }}>Análise Cartesiana de Pontos de Interesse</text>
        </g>
      </svg>
    </div>
  );
};

export default IllustratedMap;

import React from 'react';

interface LandmarkIconProps {
  type: 'monument' | 'park' | 'street' | 'river' | 'custom';
  x: number;
  y: number;
  name: string;
  onClick: () => void;
}

const LandmarkIcon: React.FC<LandmarkIconProps> = ({ type, x, y, name, onClick }) => {
  const getIcon = () => {
    switch (type) {
      case 'monument':
        return <rect x="-6" y="-6" width="12" height="12" fill="#e11d48" stroke="#fff" strokeWidth="2" />;
      case 'park':
        return <circle r="7" fill="#16a34a" stroke="#fff" strokeWidth="2" />;
      case 'street':
        return <rect x="-12" y="-3" width="24" height="6" rx="1" fill="#475569" stroke="#fff" strokeWidth="1" />;
      default:
        return <circle r="5" fill="#8b5cf6" stroke="#fff" strokeWidth="2" />;
    }
  };

  return (
    <g transform={`translate(${x}, ${y})`} onClick={onClick} className="cursor-pointer group">
      {/* Ponto de Precisão */}
      <circle r="2" fill="#000" className="group-hover:fill-red-500" />

      {/* Aura de Interação */}
      <circle r="18" fill="rgba(255,255,255,0.1)" className="opacity-0 group-hover:opacity-100 transition-opacity" />

      {/* O Ícone propriamente dito, deslocado para não cobrir o ponto exato */}
      <g transform="translate(0, -15)">
        {getIcon()}
      </g>

      {/* Etiqueta de Texto */}
      <g transform="translate(0, 15)">
        <rect 
          x="-50" 
          y="-1" 
          width="100" 
          height="14" 
          rx="4" 
          fill="rgba(255,255,255,0.9)" 
          className="opacity-0 group-hover:opacity-100 transition-opacity"
        />
        <text
          textAnchor="middle"
          className="text-[10px] font-bold fill-slate-800 drop-shadow-sm select-none pointer-events-none"
        >
          {name}
        </text>
      </g>
    </g>
  );
};

export default LandmarkIcon;

import React, { useState, useEffect, useCallback, useRef } from 'react';
import RealMap from './components/RealMap';
import IllustratedMap from './components/IllustratedMap';
