        <div className="flex flex-col h-full">
          <div className="p-6 sm:p-8 flex justify-between items-center border-b border-slate-100">
            <div className="flex items-center gap-3">
              <div className="w-10 h-10 bg-slate-900 rounded-xl flex items-center justify-center text-white shadow-lg">
                <Grid3X3 size={20} />
              </div>
              <h1 className="font-display text-2xl font-black text-slate-800 tracking-tight">Sampa Cartesian</h1>
            </div>
            <button onClick={() => setIsSidebarOpen(false)} className="lg:hidden p-2.5 hover:bg-slate-100 rounded-2xl text-slate-400">
              <ChevronLeft size={24} />
            </button>
          </div>

          <div className="flex-1 overflow-y-auto p-6 sm:p-8 space-y-8 custom-scrollbar">

            <section className="bg-slate-50 p-2 rounded-3xl flex gap-1">
              <button 
                onClick={() => setViewMode('cartesian')}
                className={`flex-1 py-3 rounded-2xl font-bold text-xs transition-all ${viewMode === 'cartesian' ? 'bg-white shadow-sm text-slate-900' : 'text-slate-400'}`}
              >
                Plano Cartesiano
              </button>
              <button 
                onClick={() => setViewMode('geographic')}
                className={`flex-1 py-3 rounded-2xl font-bold text-xs transition-all ${viewMode === 'geographic' ? 'bg-white shadow-sm text-slate-900' : 'text-slate-400'}`}
              >
                Mapa Geográfico
              </button>
            </section>

            <section className={isAddingMode ? 'bg-indigo-50 p-6 rounded-[32px] border-2 border-indigo-200' : 'bg-slate-100 p-1 rounded-3xl'}>
              {!isAddingMode ? (
                <button 
                  onClick={() => setIsAddingMode(true)}
                  className="w-full flex items-center justify-center gap-2 py-4 bg-slate-900 text-white rounded-2xl font-bold shadow-lg shadow-slate-900/10 active:scale-95 transition-transform"
                >
                  <Plus size={20} /> Adicionar Ponto (x,y)
                </button>
              ) : (
                <div className="space-y-4">
                  <div className="flex justify-between items-center">
                    <span className="text-[10px] font-black text-indigo-600 uppercase tracking-widest">Novo Ponto Matemático</span>
                    <button onClick={() => {setIsAddingMode(false); setPendingCoords(null);}} className="text-slate-400 hover:text-slate-600"><X size={20} /></button>
                  </div>
                  {!pendingCoords ? (
                    <div className="text-center py-6 px-4 bg-white/60 rounded-2xl border border-indigo-100">
                      <p className="text-sm text-indigo-900 font-bold mb-1">Escolha a Coordenada</p>
                      <p className="text-xs text-indigo-600 font-medium leading-relaxed">Toque no mapa para definir a posição no plano.</p>
                    </div>
                  ) : (
                    <div className="space-y-4 animate-in fade-in slide-in-from-top-2">
                      <input 
                        type="text" 
                        placeholder="Nome da Coordenada..." 
                        className="w-full p-4 rounded-2xl ring-1 ring-slate-200 text-sm focus:ring-2 focus:ring-indigo-500 outline-none"
                        value={newMarkerForm.title}
                        onChange={e => setNewMarkerForm({...newMarkerForm, title: e.target.value})}
                      />
                      <div className="grid grid-cols-6 gap-2">
                        {SYMBOLS.map(({ id, Icon }) => (
                          <button key={id} onClick={() => setNewMarkerForm({...newMarkerForm, symbol: id})} className={`aspect-square rounded-xl flex items-center justify-center transition-all ${newMarkerForm.symbol === id ? 'bg-slate-900 text-white' : 'bg-white border text-slate-400'}`}>
                            <Icon size={16} />
