                      </div>
                      <button onClick={saveCustomMarker} disabled={!newMarkerForm.title} className="w-full py-4 bg-indigo-600 text-white rounded-[20px] font-bold shadow-lg active:scale-95 transition-all">Salvar Ponto</button>
                    </div>
                  )}
                </div>
              )}
            </section>

            <section className="space-y-6">
              <h2 className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] mb-4">Pontos de Coordenada</h2>
              <div className="space-y-2">
                {[...customMarkers, ...SP_MAP_DATA.landmarks].map((l) => (
                  <button
                    key={l.id}
                    onClick={() => handleLandmarkClick(l.id)}
                    className={`w-full flex items-center justify-between p-4 rounded-2xl border-2 transition-all ${selectedLandmark?.id === l.id ? 'bg-slate-900 border-slate-900 text-white shadow-xl' : 'bg-white border-slate-100 hover:border-slate-200 text-slate-600'}`}
                  >
                    <div className="flex items-center gap-3 truncate">
                      {l.type === 'custom' ? <div style={{ color: (l as CustomMarker).color }}>{getSymbolIcon((l as CustomMarker).symbol, 18)}</div> : <MapPin size={18} className="text-indigo-500" />}
                      <span className="font-bold text-sm truncate">{l.name}</span>
                    </div>
                    <ChevronRight size={16} className="opacity-30" />
                  </button>
                ))}
              </div>
            </section>
          </div>
        </div>
      </aside>

      <main className="flex-1 relative bg-[#f1f5f9] no-print overflow-hidden">
        {viewMode === 'geographic' ? (
          <RealMap 
            ref={mapRef}
            onLandmarkClick={handleLandmarkClick}
            onCustomLandmarkClick={(m) => handleLandmarkClick(m.id)}
            mapStyle={mapStyle}
            customMarkers={customMarkers}
            isAddingMode={isAddingMode}
            onMapClick={handleMapClick}
            pendingCoords={pendingCoords}
            selectedLandmark={selectedLandmark}
            onUserLocationUpdate={(coords) => setUserLocation(coords)}
            routeGeometry={travelData ? travelData[travelMode].geometry : undefined}
            routeColor={travelMode === 'bus' ? '#f59e0b' : travelMode === 'train' ? '#3b82f6' : '#10b981'}
          />
        ) : (
          <div className="w-full h-full p-6 lg:p-12 overflow-auto flex items-center justify-center custom-scrollbar">
             <div className="w-full max-w-4xl">
                <IllustratedMap onLandmarkClick={handleLandmarkClick} />
