  const calculateRouteToSelected = async () => {
    if (!selectedLandmark) return;
    if (!userLocation) {
      mapRef.current?.triggerLocate();
      alert("Localizando sua posição...");
      return;
    }

    setIsCalculating(true);
    try {
      const data = await getAllTravelInfo(
        userLocation.lat, 
        userLocation.lng, 
        selectedLandmark.coordinates.lat, 
        selectedLandmark.coordinates.lng,
        selectedLandmark.id
      );
      setTravelData(data);
    } catch (err) {
      console.error(err);
    } finally {
      setIsCalculating(false);
    }
  };

  const handleMapClick = (latlng: any) => {
    if (isAddingMode) {
      setPendingCoords({ lat: latlng.lat, lng: latlng.lng });
      if (window.innerWidth < 1024) setIsSidebarOpen(true);
    } else {
      setSelectedLandmark(null);
      setTravelData(null);
    }
  };

  return (
    <div className="h-[100dvh] w-screen bg-slate-50 text-slate-900 overflow-hidden relative flex flex-col lg:flex-row font-sans">

      <aside className={`
        fixed inset-y-0 left-0 lg:relative z-[3000] lg:z-[2000]
        bg-white lg:bg-white/80 lg:backdrop-blur-xl border-r border-slate-200
        transition-all duration-500 ease-in-out
        ${isSidebarOpen ? 'w-full sm:w-[420px] translate-x-0' : 'w-0 -translate-x-full lg:translate-x-0 overflow-hidden'}
      `}>
        <div className="flex flex-col h-full">
          <div className="p-6 sm:p-8 flex justify-between items-center border-b border-slate-100">
            <div className="flex items-center gap-3">
              <div className="w-10 h-10 bg-indigo-600 rounded-xl flex items-center justify-center text-white shadow-lg">
                <MapIcon size={20} />
              </div>
              <h1 className="font-display text-2xl font-black text-slate-800 tracking-tight">Sampa Map</h1>
            </div>
            <button onClick={() => setIsSidebarOpen(false)} className="lg:hidden p-2.5 hover:bg-slate-100 rounded-2xl text-slate-400">
              <ChevronLeft size={24} />
            </button>
          </div>

          <div className="flex-1 overflow-y-auto p-6 sm:p-8 space-y-8 custom-scrollbar">

            <section className="bg-slate-100 p-1.5 rounded-2xl flex gap-1">
              <button 
                onClick={() => setViewMode('illustrated')}
                className={`flex-1 py-3 rounded-xl font-bold text-xs transition-all flex items-center justify-center gap-2 ${viewMode === 'illustrated' ? 'bg-white shadow-sm text-indigo-600' : 'text-slate-400'}`}
              >
                <Grid size={16} /> Esquema (X,Y)
              </button>
              <button 
                onClick={() => setViewMode('real')}
                className={`flex-1 py-3 rounded-xl font-bold text-xs transition-all flex items-center justify-center gap-2 ${viewMode === 'real' ? 'bg-white shadow-sm text-indigo-600' : 'text-slate-400'}`}
              >
                <MapIcon size={16} /> Mapa Real
              </button>
            </section>

            <section className="space-y-6">
              <h2 className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] mb-4">Explorar Lugares</h2>
              <div className="space-y-2">
                {[...customMarkers, ...SP_MAP_DATA.landmarks].map((l) => (
                  <button
                    key={l.id}
                    onClick={() => handleLandmarkClick(l.id)}
                    className={`w-full flex items-center justify-between p-4 rounded-2xl border-2 transition-all ${selectedLandmark?.id === l.id ? 'bg-slate-900 border-slate-900 text-white shadow-xl' : 'bg-white border-slate-100 hover:border-slate-200 text-slate-600'}`}
                  >
                    <div className="flex items-center gap-3 truncate">
                      {l.type === 'custom' ? <div style={{ color: (l as CustomMarker).color }}>{getSymbolIcon((l as CustomMarker).symbol, 18)}</div> : <MapPin size={18} className="text-indigo-500" />}
                      <span className="font-bold text-sm truncate">{l.name}</span>
                    </div>
                    <ChevronRight size={16} className="opacity-30" />
                  </button>
                ))}
              </div>
            </section>
          </div>
        </div>
      </aside>

      <main className="flex-1 relative bg-slate-100 no-print overflow-hidden">
        {viewMode === 'real' ? (
          <RealMap 
            ref={mapRef}
            onLandmarkClick={handleLandmarkClick}
            onCustomLandmarkClick={(m) => handleLandmarkClick(m.id)}
            mapStyle={mapStyle}
            customMarkers={customMarkers}
            isAddingMode={isAddingMode}
            onMapClick={handleMapClick}
            pendingCoords={pendingCoords}
            selectedLandmark={selectedLandmark}
            onUserLocationUpdate={(coords) => setUserLocation(coords)}
            routeGeometry={travelData ? travelData[travelMode].geometry : undefined}
            routeColor={travelMode === 'bus' ? '#f59e0b' : travelMode === 'train' ? '#3b82f6' : '#10b981'}
          />
        ) : (
          <div className="w-full h-full flex items-center justify-center p-4 lg:p-12 overflow-auto custom-scrollbar">
            <div className="w-full max-w-4xl max-h-full">
               <IllustratedMap onLandmarkClick={handleLandmarkClick} />
            </div>
          </div>
        )}

        <div className="absolute top-4 right-4 z-[1000] flex flex-col gap-3">
          <button 
            onClick={() => setIsSidebarOpen(true)}
            className="lg:hidden bg-white/95 backdrop-blur-md p-3.5 rounded-2xl shadow-xl border border-white"
          >
            <Compass size={24} />
          </button>
          {viewMode === 'real' && (
            <button 
              onClick={() => setMapStyle(prev => prev === 'standard' ? 'satellite' : 'standard')}
              className="bg-white/95 backdrop-blur-md p-3.5 rounded-2xl shadow-xl border border-white"
            >
              <Layers size={24} className={mapStyle === 'satellite' ? 'text-indigo-600' : 'text-slate-600'} />
            </button>
          )}
        </div>

        {selectedLandmark && (
          <div className="fixed inset-x-0 bottom-0 lg:left-[420px] z-[4000] p-4 lg:p-10 pointer-events-none">
            <div className="bg-white rounded-[40px] shadow-2xl pointer-events-auto overflow-hidden animate-sheet max-w-2xl mx-auto border border-slate-200">
               <div className="p-8 space-y-6">
                  <div className="flex justify-between items-start">
                    <div className="flex items-center gap-4">
                      <div className="p-4 rounded-2xl text-white shadow-lg bg-indigo-600">
                        {selectedLandmark.type === 'custom' ? getSymbolIcon((selectedLandmark as CustomMarker).symbol, 24) : <MapPin size={24} />}
                      </div>
                      <div>
                        <h2 className="text-xl font-black text-slate-900 tracking-tight">{selectedLandmark.name}</h2>
                        <div className="flex gap-2 mt-1">
                          <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest px-2 py-0.5 bg-slate-50 rounded-md">
                            {selectedLandmark.type === 'custom' ? 'Personnel' : 'Monument'}
                          </span>
                          {selectedLandmark.coordinates.x && (
                            <span className="text-[10px] font-bold text-indigo-600 px-2 py-0.5 bg-indigo-50 rounded-md">
                              X:{selectedLandmark.coordinates.x} Y:{selectedLandmark.coordinates.y}
                            </span>
                          )}
                        </div>
                      </div>
                    </div>
                    <button onClick={() => {setSelectedLandmark(null); setTravelData(null);}} className="p-2 hover:bg-slate-100 rounded-full"><X size={20} /></button>
                  </div>

                  {loading ? (
                    <div className="py-10 flex flex-col items-center gap-4">
                      <Loader2 className="animate-spin text-indigo-600" size={32} />
                      <span className="text-xs font-bold text-slate-400 uppercase tracking-widest">Chargement...</span>
                    </div>
                  ) : (
                    <div className="space-y-6">
                      <div className="bg-slate-50 p-6 rounded-3xl border border-slate-100">
                        <p className="text-slate-700 text-sm leading-relaxed font-medium">
                          {selectedLandmark.type === 'custom' ? selectedLandmark.description : groundedInfo.text}
                        </p>
                      </div>

                      <div className="grid grid-cols-2 gap-3">
                         <button 
                            onClick={calculateRouteToSelected}
                            disabled={isCalculating}
                            className="flex items-center justify-center gap-2 py-4 bg-slate-900 text-white rounded-[24px] font-bold shadow-lg disabled:opacity-50 active:scale-95 transition-all"
                         >
                            {isCalculating ? <Loader2 size={18} className="animate-spin" /> : <Navigation size={18} fill="white" />}
                            Tracer l'itinéraire
                         </button>
                         {selectedLandmark.type !== 'custom' && groundedInfo.links.length > 0 && (
                            <a href={groundedInfo.links[0].uri} target="_blank" className="flex items-center justify-center gap-2 py-4 bg-indigo-100 text-indigo-700 rounded-[24px] font-bold border border-indigo-200 active:scale-95 transition-all">
                                <ExternalLink size={18} /> Google Maps
                            </a>
                         )}
                      </div>
                    </div>
                  )}
               </div>
            </div>
          </div>
        )}
      </main>
    </div>
  );
};

export default App;

