          <pattern id="smallGrid" width="20" height="20" patternUnits="userSpaceOnUse">
            <path d="M 20 0 L 0 0 0 20" fill="none" stroke="rgba(0,0,0,0.03)" strokeWidth="0.5"/>
          </pattern>
        </defs>

        <rect width="100%" height="100%" fill="url(#smallGrid)" />
        <rect width="100%" height="100%" fill="url(#grid)" />

        <g className="axes-system">
          <line x1="0" y1={height - 40} x2={width} y2={height - 40} stroke="#64748b" strokeWidth="2" />
          {xTicks.map(x => (
            <g key={`x-${x}`} transform={`translate(${x}, ${height - 40})`}>
              <line y1="0" y2="10" stroke="#64748b" strokeWidth="2" />
              <text y="25" textAnchor="middle" className="text-[12px] fill-slate-500 font-mono font-bold">{x}</text>
            </g>
          ))}

          <line x1="40" y1="0" x2="40" y2={height} stroke="#64748b" strokeWidth="2" />
          {yTicks.map(y => (
            <g key={`y-${y}`} transform={`translate(40, ${y})`}>
              <line x1="0" x2="-10" stroke="#64748b" strokeWidth="2" />
              <text x="-15" y="4" textAnchor="end" className="text-[12px] fill-slate-500 font-mono font-bold">{y}</text>
            </g>
          ))}
        </g>

        <g className="opacity-40">
          <path d="M0,350 Q300,380 500,350 T1000,380" fill="none" stroke="#0ea5e9" strokeWidth="15" strokeLinecap="round" />
          <text x="60" y="340" className="text-[12px] fill-sky-600 italic font-bold">Rio Tietê</text>
          <path d="M200,950 Q280,750 350,365" fill="none" stroke="#0ea5e9" strokeWidth="12" strokeLinecap="round" />
          <text x="230" y="820" className="text-[12px] fill-sky-600 italic font-bold" transform="rotate(-65, 230, 820)">Rio Pinheiros</text>
        </g>

        {SP_MAP_DATA.landmarks.map((landmark) => (
          <LandmarkIcon
            key={landmark.id}
            type={landmark.type}
            x={landmark.coordinates.x || 500}
            y={landmark.coordinates.y || 700}
            name={landmark.name}
            color={landmark.color}
            symbol={landmark.symbol}
            onClick={() => onLandmarkClick(landmark.id)}
          />
        ))}

        <g transform="translate(920, 80)" className="opacity-50">
          <circle r="30" fill="none" stroke="#64748b" strokeWidth="1" />
          <path d="M0,-25 L8,0 L0,25 L-8,0 Z" fill="#64748b" />
          <text y="-35" textAnchor="middle" className="text-[12px] fill-slate-600 font-bold uppercase">Norte</text>
        </g>

        <g transform="translate(70, 80)">
          <text className="font-display fill-slate-800" style={{ fontSize: '52px', fontWeight: 900 }}>São Paulo</text>
          <text y="40" className="fill-slate-500 font-bold uppercase tracking-[0.2em]" style={{ fontSize: '12px' }}>Mapa Ilustrado & Coordenadas (X, Y)</text>
        </g>
      </svg>
    </div>
  );
};

