import React, { useState, useEffect, useCallback, useRef } from 'react';
import RealMap from './components/RealMap';
import IllustratedMap from './components/IllustratedMap';
import { SP_MAP_DATA } from './constants';
import { Landmark, CustomMarker } from './types';
import { getGroundedLocationInfo } from './services/geminiService';
import { getAllTravelInfo, TravelModes } from './services/geoUtils';
import { 
  Compass, 
  ChevronRight, 
  ChevronLeft, 
  ExternalLink, 
  MapPin, 
  X, 
  Layers, 
  Loader2, 
  Plus, 
  Trash2,
  Map as MapIcon,
  Info,
  Navigation,
  Home,
  Building2,
  Briefcase,
  GraduationCap,
  TrainFront,
  Bus,
  Car,
  Clock,
  Info as InfoIcon,
  Navigation2,
  Brush
} from 'lucide-react';

export type MapStyle = 'standard' | 'satellite' | 'illustrated';

const COLORS = [
  { name: 'Améthyste', hex: '#8b5cf6' },
  { name: 'Émeraude', hex: '#10b981' },
  { name: 'Rubis', hex: '#ef4444' },
  { name: 'Saphir', hex: '#3b82f6' },
  { name: 'Or', hex: '#f59e0b' }
];

const SYMBOLS = [
  { id: 'home', Icon: Home },
  { id: 'map-pin', Icon: MapPin },
  { id: 'building', Icon: Building2 },
  { id: 'work', Icon: Briefcase },
  { id: 'school', Icon: GraduationCap },
  { id: 'train', Icon: TrainFront }
];

export const getSymbolIcon = (id: string, size = 20, color = "currentColor") => {
  const symbol = SYMBOLS.find(s => s.id === id) || SYMBOLS[0];
  return <symbol.Icon size={size} color={color} />;
};

const App: React.FC = () => {
  const [selectedLandmark, setSelectedLandmark] = useState<Landmark | CustomMarker | null>(null);
  const [groundedInfo, setGroundedInfo] = useState<{ text: string, links: {uri: string, title: string}[] }>({ text: '', links: [] });
  const [loading, setLoading] = useState<boolean>(false);
  const [isSidebarOpen, setIsSidebarOpen] = useState<boolean>(window.innerWidth >= 1024);
  const [mapStyle, setMapStyle] = useState<MapStyle>('standard');
  const [userLocation, setUserLocation] = useState<{lat: number, lng: number} | null>(null);

  const [travelData, setTravelData] = useState<TravelModes | null>(null);
  const [travelMode, setTravelMode] = useState<'car' | 'train' | 'bus'>('car');
  const [isCalculating, setIsCalculating] = useState(false);

  const [customMarkers, setCustomMarkers] = useState<CustomMarker[]>(() => {
    const saved = localStorage.getItem('sp_custom_markers');
    return saved ? JSON.parse(saved) : [];
  });

  const [isAddingMode, setIsAddingMode] = useState(false);
  const [pendingCoords, setPendingCoords] = useState<{lat: number, lng: number} | null>(null);
  const [newMarkerForm, setNewMarkerForm] = useState({ 
    title: '', 
    description: '', 
    color: COLORS[0].hex,
    symbol: SYMBOLS[0].id 
  });

  const mapRef = useRef<{ triggerLocate: () => void }>(null);

  useEffect(() => {
    localStorage.setItem('sp_custom_markers', JSON.stringify(customMarkers));
  }, [customMarkers]);

  const handleLandmarkClick = async (id: string) => {
    const landmark = [...SP_MAP_DATA.landmarks, ...customMarkers].find(l => l.id === id);
    if (landmark) {
      setSelectedLandmark(landmark);
      setTravelData(null);
      setLoading(true);
      const info = landmark.type === 'custom' ? { text: landmark.description, links: [] } : await getGroundedLocationInfo(landmark.name);
      setGroundedInfo(info);
      setLoading(false);
      if (window.innerWidth < 1024) setIsSidebarOpen(false);
    }
  };

  const calculateRouteToSelected = async () => {
    if (!selectedLandmark) return;
    if (!userLocation) {
      mapRef.current?.triggerLocate();
      return;
    }
    setIsCalculating(true);
    try {
      const data = await getAllTravelInfo(userLocation.lat, userLocation.lng, selectedLandmark.coordinates.lat, selectedLandmark.coordinates.lng, selectedLandmark.id);
      setTravelData(data);
    } catch (err) { console.error(err); } finally { setIsCalculating(false); }
  };

  const saveCustomMarker = () => {
    if (!pendingCoords || !newMarkerForm.title) return;
    const newMarker: CustomMarker = {
      id: `custom-${Date.now()}`,
      name: newMarkerForm.title,
      type: 'custom',
      coordinates: pendingCoords,
      description: newMarkerForm.description,
      color: newMarkerForm.color,
      symbol: newMarkerForm.symbol
    };
    setCustomMarkers([...customMarkers, newMarker]);
    setPendingCoords(null);
    setIsAddingMode(false);
    setNewMarkerForm({ title: '', description: '', color: COLORS[0].hex, symbol: SYMBOLS[0].id });
    setSelectedLandmark(newMarker);
    setGroundedInfo({ text: newMarker.description, links: [] });
  };

  return (
    <div className="h-[100dvh] w-screen bg-slate-50 text-slate-900 overflow-hidden relative flex flex-col lg:flex-row font-sans">

      <aside className={`fixed inset-y-0 left-0 lg:relative z-[3000] lg:z-[2000] bg-white lg:bg-white/80 lg:backdrop-blur-xl border-r border-slate-200 transition-all duration-500 ease-in-out ${isSidebarOpen ? 'w-full sm:w-[420px] translate-x-0' : 'w-0 -translate-x-full lg:translate-x-0 overflow-hidden'}`}>
        <div className="flex flex-col h-full">
          <div className="p-8 flex justify-between items-center border-b border-slate-100">
            <div className="flex items-center gap-3">
              <div className="w-10 h-10 bg-indigo-600 rounded-xl flex items-center justify-center text-white shadow-lg"><MapIcon size={20} /></div>
              <h1 className="font-display text-2xl font-black text-slate-800 tracking-tight">Sampa Map</h1>
            </div>
            <button onClick={() => setIsSidebarOpen(false)} className="lg:hidden p-2 text-slate-400"><ChevronLeft size={24} /></button>
          </div>

          <div className="flex-1 overflow-y-auto p-8 space-y-8 custom-scrollbar">
            <section className={isAddingMode ? 'bg-indigo-50 p-6 rounded-[32px] border-2 border-indigo-200' : 'bg-slate-50 p-2 rounded-3xl'}>
              {!isAddingMode ? (
                <button onClick={() => { setIsAddingMode(true); setMapStyle('standard'); }} className="w-full flex items-center justify-center gap-2 py-4 bg-slate-900 text-white rounded-2xl font-bold shadow-lg shadow-slate-900/10 active:scale-95 transition-transform"><Plus size={20} /> Novo Marcador</button>
              ) : (
                <div className="space-y-4">
                  <div className="flex justify-between items-center"><span className="text-[10px] font-black text-indigo-600 uppercase tracking-widest">Novo Ponto</span><button onClick={() => {setIsAddingMode(false); setPendingCoords(null);}}><X size={20} /></button></div>
                  {!pendingCoords ? <div className="text-center py-6 px-4 bg-white/60 rounded-2xl border border-indigo-100 text-sm font-bold text-indigo-900">Clique no mapa para marcar</div> : (
                    <div className="space-y-4">
                      <input type="text" placeholder="Nome do local..." className="w-full p-4 rounded-2xl ring-1 ring-slate-200 text-sm focus:ring-2 focus:ring-indigo-500 outline-none" value={newMarkerForm.title} onChange={e => setNewMarkerForm({...newMarkerForm, title: e.target.value})} />
                      <div className="grid grid-cols-6 gap-2">{SYMBOLS.map(({ id, Icon }) => (<button key={id} onClick={() => setNewMarkerForm({...newMarkerForm, symbol: id})} className={`aspect-square rounded-xl flex items-center justify-center transition-all ${newMarkerForm.symbol === id ? 'bg-slate-900 text-white' : 'bg-white border text-slate-400'}`}><Icon size={16} /></button>))}</div>
                      <button onClick={saveCustomMarker} disabled={!newMarkerForm.title} className="w-full py-4 bg-indigo-600 text-white rounded-[20px] font-bold shadow-lg active:scale-95 transition-all">Salvar Local</button>
                    </div>
                  )}
                </div>
              )}
            </section>

            <section className="space-y-6">
              <h2 className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-4">Meus Lugares & Marcos</h2>
              <div className="space-y-2">
                {[...customMarkers, ...SP_MAP_DATA.landmarks].map((l) => (
                  <button key={l.id} onClick={() => handleLandmarkClick(l.id)} className={`w-full flex items-center justify-between p-4 rounded-2xl border-2 transition-all ${selectedLandmark?.id === l.id ? 'bg-slate-900 border-slate-900 text-white shadow-xl' : 'bg-white border-slate-100 hover:border-slate-200 text-slate-600'}`}>
                    <div className="flex items-center gap-3 truncate">{l.type === 'custom' ? <div style={{ color: (l as CustomMarker).color }}>{getSymbolIcon((l as CustomMarker).symbol, 18)}</div> : <MapPin size={18} className="text-emerald-500" />}<span className="font-bold text-sm truncate">{l.name}</span></div>
                    <ChevronRight size={16} className="opacity-30" />
                  </button>
                ))}
              </div>
            </section>
          </div>
        </div>
      </aside>

      <main className="flex-1 relative bg-slate-100 no-print overflow-hidden">
        {mapStyle === 'illustrated' ? (
          <div className="w-full h-full flex items-center justify-center p-4 lg:p-10 bg-slate-200 overflow-auto custom-scrollbar">
            <IllustratedMap onLandmarkClick={handleLandmarkClick} />
          </div>
        ) : (
          <RealMap 
            ref={mapRef} onLandmarkClick={handleLandmarkClick} onCustomLandmarkClick={(m) => handleLandmarkClick(m.id)} 
            mapStyle={mapStyle === 'satellite' ? 'satellite' : 'standard'} customMarkers={customMarkers} isAddingMode={isAddingMode} 
            onMapClick={(ll) => { if (isAddingMode) setPendingCoords({lat: ll.lat, lng: ll.lng}); else setSelectedLandmark(null); }} 
            pendingCoords={pendingCoords} selectedLandmark={selectedLandmark} onUserLocationUpdate={setUserLocation} 
            routeGeometry={travelData?.[travelMode].geometry} routeColor={travelMode === 'bus' ? '#f59e0b' : travelMode === 'train' ? '#3b82f6' : '#10b981'}
          />
        )}

        <div className="absolute top-4 right-4 z-[1000] flex flex-col gap-3">
          <button onClick={() => setIsSidebarOpen(true)} className="lg:hidden bg-white/95 p-3.5 rounded-2xl shadow-xl border border-white"><Compass size={24} /></button>
          <button onClick={() => setMapStyle(mapStyle === 'illustrated' ? 'standard' : 'illustrated')} className={`bg-white/95 p-3.5 rounded-2xl shadow-xl border border-white transition-all ${mapStyle === 'illustrated' ? 'bg-indigo-600 text-white' : 'text-slate-600'}`}><Brush size={24} /></button>
          {mapStyle !== 'illustrated' && (
            <button onClick={() => setMapStyle(prev => prev === 'standard' ? 'satellite' : 'standard')} className="bg-white/95 p-3.5 rounded-2xl shadow-xl border border-white transition-all"><Layers size={24} className={mapStyle === 'satellite' ? 'text-indigo-600' : 'text-slate-600'} /></button>
          )}
        </div>

        {travelData && (
          <div className="absolute top-4 left-4 lg:left-6 z-[2000] w-[calc(100%-2rem)] max-w-sm">
            <div className="bg-white/90 backdrop-blur-xl rounded-[32px] shadow-2xl border border-white p-5 pointer-events-auto">
              <div className="flex justify-between items-center mb-4"><span className="font-black text-[10px] uppercase tracking-widest text-blue-600">Calculando Rota</span><button onClick={() => setTravelData(null)}><X size={18} /></button></div>
              <div className="grid grid-cols-3 gap-2 mb-4">
                <button onClick={() => setTravelMode('car')} className={`flex flex-col items-center py-3 rounded-2xl border-2 ${travelMode === 'car' ? 'bg-slate-900 border-slate-900 text-white' : 'bg-white text-slate-400'}`}><Car size={18}/><span className="text-[10px] font-bold mt-1">Carro</span></button>
                <button onClick={() => setTravelMode('train')} className={`flex flex-col items-center py-3 rounded-2xl border-2 ${travelMode === 'train' ? 'bg-blue-600 border-blue-600 text-white' : 'bg-white text-slate-400'}`}><TrainFront size={18}/><span className="text-[10px] font-bold mt-1">Trem</span></button>
                <button onClick={() => setTravelMode('bus')} className={`flex flex-col items-center py-3 rounded-2xl border-2 ${travelMode === 'bus' ? 'bg-amber-500 border-amber-500 text-white' : 'bg-white text-slate-400'}`}><Bus size={18}/><span className="text-[10px] font-bold mt-1">Ônibus</span></button>
              </div>
              <div className="flex gap-3 mb-4">
                <div className="flex-1 bg-slate-50 p-4 rounded-2xl text-center"><p className="text-[9px] font-black text-slate-400 uppercase">Distância</p><p className="text-xl font-black text-slate-800">{travelData[travelMode].distanceKm} km</p></div>
                <div className="flex-1 bg-blue-50 p-4 rounded-2xl text-center"><p className="text-[9px] font-black text-blue-400 uppercase">Tempo Est.</p><p className="text-xl font-black text-blue-700">{travelData[travelMode].durationMinutes} min</p></div>
              </div>
              <button onClick={() => window.open(`https://www.google.com/maps/dir/?api=1&origin=${userLocation?.lat},${userLocation?.lng}&destination=${selectedLandmark?.coordinates.lat},${selectedLandmark?.coordinates.lng}&travelmode=${travelMode==='car'?'driving':'transit'}`, '_blank')} className="w-full flex items-center justify-center gap-2 py-4 bg-blue-600 text-white rounded-[20px] font-bold shadow-lg shadow-blue-200">Iniciar Navegação</button>
            </div>
          </div>
        )}

        {selectedLandmark && (
          <div className="fixed inset-x-0 bottom-0 lg:left-[420px] z-[4000] p-4 lg:p-10 pointer-events-none">
            <div className="bg-white rounded-[40px] shadow-2xl pointer-events-auto overflow-hidden animate-sheet max-w-2xl mx-auto border border-slate-200">
               <div className="p-8 space-y-6">
                  <div className="flex justify-between items-start">
                    <div className="flex items-center gap-4">
                      <div className="p-4 rounded-2xl text-white shadow-lg" style={{ backgroundColor: selectedLandmark.type === 'custom' ? (selectedLandmark as CustomMarker).color : '#059669' }}>
                        {selectedLandmark.type === 'custom' ? getSymbolIcon((selectedLandmark as CustomMarker).symbol, 24) : <MapPin size={24} />}
                      </div>
                      <div>
                        <h2 className="text-xl font-black text-slate-900 tracking-tight">{selectedLandmark.name}</h2>
                        <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mt-1">Localização em Sampa</p>
                      </div>
                    </div>
                    <button onClick={() => {setSelectedLandmark(null); setTravelData(null);}} className="p-2 hover:bg-slate-100 rounded-full"><X size={20} /></button>
                  </div>
                  <div className="space-y-6">
                    <div className="bg-slate-50 p-6 rounded-3xl border border-slate-100">
                      <p className="text-slate-700 text-sm leading-relaxed font-medium">
                        {selectedLandmark.type === 'custom' ? selectedLandmark.description : (loading ? "Carregando informações..." : groundedInfo.text)}
                      </p>
                    </div>
                    <div className="grid grid-cols-2 gap-3">
                       <button onClick={calculateRouteToSelected} disabled={isCalculating} className="flex items-center justify-center gap-2 py-4 bg-blue-600 text-white rounded-[24px] font-bold shadow-lg disabled:opacity-50"><Navigation size={18} fill="white" /> Traçar Rota</button>
                       {selectedLandmark.type === 'custom' ? (
                          <button onClick={() => { setCustomMarkers(customMarkers.filter(m => m.id !== selectedLandmark.id)); setSelectedLandmark(null); }} className="w-full py-4 text-red-500 font-bold border-2 border-red-50 rounded-[24px] flex items-center justify-center gap-2"><Trash2 size={18} /> Excluir</button>
                       ) : (groundedInfo.links.length > 0 && (
                          <a href={groundedInfo.links[0].uri} target="_blank" className="flex items-center justify-center gap-2 py-4 bg-emerald-100 text-emerald-700 rounded-[24px] font-bold border border-emerald-200"><ExternalLink size={18} /> Google Maps</a>
                       ))}
                    </div>
                  </div>
               </div>
            </div>
          </div>
        )}
      </main>
    </div>
  );
};

